window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]=window.__LIBQ["pham-nhan-tu-tien"]["q04"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]["techniques"]={"updatedAt":"2026-07-13","count":142,"techniques":[{"id":"than-thuc-do-xet-vung-phu-can","name":"Thần thức dò xét vùng phụ cận","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Cách Hàn Lập phóng thần thức để dò xem quanh cô đảo có người tu tiên tồn tại hay không.","detail":"Sau khi đến cô đảo xa lạ, Hàn Lập nhắm mắt phóng thần thức ra xung quanh để thăm dò vùng phụ cận. Sau thời gian một chén trà, hắn thu thần thức lại với vẻ mặt kỳ quái.","congNang":["Dò xét khu vực quanh cô đảo để tìm dấu vết người tu tiên @c0364"],"tabs":{"tienTrinh":[{"chuong":"@c0364","loai":"thi triển","importance":"normal","giaiDoan":"Dò xét cô đảo","text":"Hàn Lập phóng thần thức ra vùng phụ cận cô đảo để kiểm tra xem có người tu tiên tồn tại hay không.","anchor":"mà là nhắm mắt lại, chậm rãi phóng thần thức của mình ra, nhìn xem vùng phụ cận có người tu tiên nào tồn tại hay không."}]},"capNhatToi":"@c0364","nguon":["@c0364"]},{"id":"than-thuc-do-xet-toan-thuyen","name":"Thần thức dò xét toàn thuyền","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"tu sĩ","soHuu":["Hàn Lập"],"blurb":"Cách Hàn Lập dùng thần thức quét toàn bộ hải thuyền để kiểm tra có tu sĩ ẩn nấp hay không.","detail":"Tại hải thuyền phàm nhân, Hàn Lập dùng thần thức đảo qua toàn bộ người trên thuyền và xác nhận tất cả đều là phàm nhân, không có người tu tiên. Việc kiểm tra này giúp hắn yên tâm giao tiếp và tạm ở lại thuyền.","thuocTinh":"thần thức","uyLuc":"Có thể bao quát toàn bộ hải thuyền và kiểm tra thân phận tu tiên hay phàm nhân của người trên thuyền.","dacDiem":"Dùng để dò xét an toàn trước khi tiếp xúc trong môi trường xa lạ.","congNang":["Kiểm tra toàn bộ người trên hải thuyền để xác định có tu sĩ hay không @c0365"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0365","tangDatToi":"dùng được để quét toàn thuyền","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0365","loai":"thi triển","importance":"normal","giaiDoan":"Dò xét hải thuyền","text":"Hàn Lập dùng thần thức kiểm tra toàn bộ hải thuyền, xác nhận không có người tu tiên ẩn trong nhóm phàm nhân.","anchor":"dùng thần thức đảo qua toàn bộ những người trên thuyền này"}]},"capNhatToi":"@c0365","nguon":["@c0365"]},{"id":"than-ngoai-hoa-than","name":"Thân Ngoại Hóa Thân","aliases":["Thân ngoại hóa thân thuật"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":["Hàn Lập"],"blurb":"Pháp môn được Hàn Lập dự tính tu luyện sau khi đặt chân tại Khôi Tinh Đảo.","detail":"Hàn Lập xếp Thân Ngoại Hóa Thân vào nhóm pháp môn cần tu luyện tại Khôi Tinh Đảo, cùng Đại Diễn Quyết, nhằm phục vụ khả năng bảo mệnh về sau.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0367","tangDatToi":"dự tính tu luyện","trangThai":"dự tính"}],"trangThai":"dự tính tu luyện","capNhatToi":"@c0367","nguon":["@c0367"]},{"id":"cam-che-tren-tung-quanh-co-gia","name":"Cấm chế trên tùng quanh Cố gia","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"Không rõ","hePhai":"Cố gia","soHuu":["Cố gia"],"blurb":"Cấm chế bố trí trên các cây tùng quanh tòa nhà trong Cố gia trang. Hàn Lập nhận ra khí tượng trận pháp và đánh giá nó đủ vây khốn tu tiên giả cấp thấp.","detail":"Các cây tùng quanh trạch viện Cố gia lộ ra khí tượng trận pháp, cho thấy nơi này không phải trang viên phàm tục hoàn toàn. Trận pháp không cao minh trong mắt Hàn Lập nhưng vẫn có hiệu quả vây khốn tu tiên giả cấp thấp.","congNang":["Vây khốn tu tiên giả cấp thấp @c0368"],"dinhDanh":"goc","capNhatToi":"@c0368","tabs":{"tienTrinh":[{"chuong":"@c0368","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị Hàn Lập phát hiện tại Cố gia trang","text":"Hàn Lập nhận ra khí tượng trận pháp trên các cây tùng quanh tòa nhà Cố gia và đánh giá cấm chế đủ vây tu tiên giả cấp thấp.","anchor":"tại các cây tùng khắp bốn phía của tòa nhà lộ ra vài tia khí tượng của trận pháp"}]},"nguon":["@c0368"]},{"id":"luyen-thi-thuat-moi-nghi-van","name":"Luyện thi thuật mới nghi vấn","cn":"","aliases":[],"loai":"luyen-the","loaiLabel":"Luyện thi thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Loại Luyện thi thuật mà Dương tiên sư nghi ngờ khi quan sát Khúc Hồn. Điểm khiến ông chú ý là thân thể tử thi hoàn toàn lại phát tán linh khí ra ngoài.","detail":"Sau khi Hàn Lập rời thạch ốc, Dương tiên sư cho rằng Khúc Hồn là một luyện thi cổ quái: rõ ràng là tử thi nhưng vẫn có linh khí phát tán. Từ đó ông đặt nghi vấn đây có thể là một loại Luyện thi thuật mới.","thuocTinh":"luyện thi","dacDiem":"Tử thi vẫn có linh khí phát tán ra bên ngoài.","congNang":["Khiến luyện thi là tử thi hoàn toàn vẫn phát tán linh khí @c0368"],"dinhDanh":"goc","capNhatToi":"@c0368","tabs":{"tienTrinh":[{"chuong":"@c0368","loai":"nhắc tới","importance":"normal","giaiDoan":"Dương tiên sư nghi ngờ khi nhìn Khúc Hồn","text":"Dương tiên sư nhìn Khúc Hồn là tử thi nhưng vẫn có linh khí phát tán, nên nghi có một loại Luyện thi thuật mới.","anchor":"Chẳng lẽ là một loại Luyện thi thuật mới?"}]},"nguon":["@c0368"]},{"id":"tran-phap-san-dau-lo-thien","name":"Trận pháp sàn đấu lộ thiên","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Khôi Tinh Đảo","soHuu":[],"blurb":"Trận pháp bảo vệ sàn đấu lộ thiên phía sau đại sảnh, dùng cho tỷ thí giữa các tu sĩ khiêu chiến. Khi hai bên bước vào, không gian hiện thành một vùng trắng có sương mù bao quanh.","detail":"Trận pháp này đủ mạnh để chịu pháp thuật trong lúc tỷ thí và tránh phá hỏng bên ngoài. Nó tạo khu vực chiến đấu cách ly, khiến Hàn Lập và đối thủ xuất hiện trong mảnh thiên địa trắng rộng hơn mười trượng.","congNang":["Cách ly khu vực tỷ thí và chịu pháp thuật trong lúc tu sĩ giao đấu @c0369"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c0369","loai":"xuất hiện","importance":"normal","giaiDoan":"Vòng khiêu chiến tại cung điện trung tâm","text":"Trận pháp sàn đấu lộ thiên được giới thiệu là lớp bảo vệ cho nơi tỷ thí, đủ để không sợ pháp thuật phá hư bên ngoài.","anchor":"nơi đấy có trận pháp mạnh, không sợ pháp thuật phá hư"}]},"nguon":["@c0369"]},{"id":"tran-phap-phong-ho-tieu-hoan-dao","name":"Trận pháp phòng hộ Tiểu Hoàn Đảo","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Khôi Tinh Đảo","Hàn Lập"],"blurb":"Trận pháp bảo vệ Tiểu Hoàn Đảo, cần linh thạch để duy trì. Người chọn đảo phải gánh nghĩa vụ cung cấp linh thạch cho trận pháp này.","detail":"Trận pháp phòng hộ bao quanh Tiểu Hoàn Đảo và có cửa vào ở khu vực bến tàu. Vì cư dân trên đảo không đủ bù hao tổn thường ngày, người tu luyện chọn đảo phải tự chuẩn bị linh thạch duy trì.","thuocTinh":"phòng hộ","uyLuc":"Bảo hộ Tiểu Hoàn Đảo và duy trì lớp phòng vệ quanh đảo.","dacDiem":"Cần linh thạch duy trì lâu dài.","congNang":["Bảo hộ Tiểu Hoàn Đảo bằng trận pháp phòng hộ @c0372"],"nguoiTu":[],"tabs":{"tienTrinh":[{"chuong":"@c0372","loai":"xuất hiện","importance":"normal","giaiDoan":"được Hàn Lập tiếp nhận nghĩa vụ duy trì","text":"Trận pháp phòng hộ Tiểu Hoàn Đảo được nhắc là lớp bảo hộ cần linh thạch duy trì, và Hàn Lập phải gánh nghĩa vụ này khi chọn đảo.","anchor":"Hơn nữa trên có quy định, tu sĩ lựa chọn đảo này đồng thời phải có nghĩa vụ bảo hộ"}]},"capNhatToi":"@c0372","nguon":["@c0372"]},{"id":"thien-phong-cuong-liet-tran","name":"Thiên Phong Cuồng Liệt Trận","cn":"天风狂烈阵","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp phạm vi lớn được Hàn Lập dùng để bảo vệ hai ngọn núi tại Tiểu Hoàn Sơn. Trận này phối hợp với Huyễn Hành Thiên La Trận và Điên Đảo Ngũ Hành Trận tạo thành hệ phòng hộ động phủ.","detail":"Hàn Lập dùng trận kỳ và trận bàn mới được tặng để bày Thiên Phong Cuồng Liệt Trận quanh khu vực hai ngọn núi. Trận pháp này thuộc lớp phòng hộ mới của động phủ, khiến tu sĩ Trúc Cơ kỳ khó xâm nhập.","congNang":["Phòng hộ phạm vi lớn cho hai ngọn núi nơi Hàn Lập lập động phủ @c0373","Phòng ngự, chặn đường vào trung tâm đảo"],"nguon":["@c0373","@c0395"],"tabs":{"tienTrinh":[{"chuong":"@c0373","loai":"xuất hiện","importance":"normal","giaiDoan":"bố trí động phủ Tiểu Hoàn Sơn","text":"Hàn Lập dùng bộ trận kỳ và trận bàn mới được tặng để bày Thiên Phong Cuồng Liệt Trận làm một lớp phòng hộ cho hai ngọn núi.","anchor":"trận kỳ và trận bàn gọi là “Thiên phong cuồng liệt trận”"},{"chuong":"@c0395","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí tại Hồng Hô đảo","text":"Được Khúc Hồn bố trí trên đường vào trung tâm đảo cùng hai trận pháp khác.","anchor":"\"Thiên phong cuồng liệt trận\" và \"Huyễn hình thiên la trận\""}]}},{"id":"huyen-hanh-thien-la-tran","name":"Huyễn Hành Thiên La Trận","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp phạm vi lớn được bày cùng Thiên Phong Cuồng Liệt Trận tại Tiểu Hoàn Sơn. Nó là một phần trong hệ thống phòng hộ động phủ thật giả của Hàn Lập.","detail":"Huyễn Hành Thiên La Trận được Hàn Lập bố trí bằng bộ pháp khí trận kỳ và trận bàn mới nhận. Trận pháp này tăng cường phòng hộ cho hai ngọn núi, phối hợp với các trận khác tạo lớp bảo vệ khó vượt qua với Trúc Cơ kỳ.","congNang":["Tăng cường phòng hộ phạm vi lớn cho khu động phủ hai núi @c0373"],"nguon":["@c0373"],"tabs":{"tienTrinh":[{"chuong":"@c0373","loai":"xuất hiện","importance":"normal","giaiDoan":"bố trí động phủ Tiểu Hoàn Sơn","text":"Hàn Lập bày Huyễn Hành Thiên La Trận cùng Thiên Phong Cuồng Liệt Trận để bảo vệ hai ngọn núi.","anchor":"và “Huyễn hành thiên la trận”"}]}},{"id":"duc-trung-tam-dac","name":"Dục Trùng tâm đắc","cn":"","aliases":[],"loai":"khac","loaiLabel":"Tâm đắc nuôi trùng","phamCap":"không rõ","hePhai":"Ngự Linh Tông","soHuu":["Hàn Lập"],"blurb":"Tâm đắc nuôi trùng liên quan tu sĩ Ngự Linh Tông. Hàn Lập dùng nó để cải tạo mật thất và nuôi Bạch tri thù cùng kỳ trùng.","detail":"Dựa theo Dục Trùng tâm đắc của tu sĩ Ngự Linh Tông, Hàn Lập mở hơn mười mật thất lớn nhỏ, cải tạo môi trường, đặt cấm chế và chuẩn bị thức ăn cho Bạch tri thù cùng các kỳ trùng còn sống.","congNang":["Hướng dẫn cải tạo môi trường mật thất để nuôi linh trùng và kỳ trùng @c0373"],"nguon":["@c0373"],"tabs":{"tienTrinh":[{"chuong":"@c0373","loai":"xuất hiện","importance":"normal","giaiDoan":"xây trùng thất","text":"Hàn Lập dựa theo Dục Trùng tâm đắc để cải tạo hơn mười mật thất nuôi Bạch tri thù và kỳ trùng.","anchor":"dựa theo Dục Trùng tâm đắc của Ngự linh tông tu sĩ"}]}},{"id":"sat-dan","name":"Sát Đan","cn":"","aliases":[],"loai":"khac","loaiLabel":"Kết đan đặc dị","phamCap":"Kết Đan kỳ liên quan phân thân","hePhai":"","soHuu":[],"blurb":"Sát Đan là kết quả mà Hàn Lập kỳ vọng phân thân có thể kết thành nhờ Huyết Ngưng Ngũ Hành Đan. Nếu thành công, phân thân có thể trở thành khôi lỗi hộ vệ cấp Kết Đan.","detail":"Khi nghiên cứu Thân ngoại hóa thân, Hàn Lập cho rằng nhờ Huyết Ngưng Ngũ Hành Đan, phân thân có cơ hội kết thành Sát Đan. Đây là mấu chốt trong kế hoạch tạo một hộ vệ cấp Kết Đan từ Khúc Hồn.","congNang":["Giúp phân thân đạt chiến lực hoặc tu vi tương ứng Kết Đan kỳ trong kế hoạch của Hàn Lập @c0373"],"nguon":["@c0373"],"tabs":{"tienTrinh":[{"chuong":"@c0373","loai":"nhắc tới","importance":"normal","giaiDoan":"kế hoạch tế luyện phân thân","text":"Hàn Lập kỳ vọng dùng Huyết Ngưng Ngũ Hành Đan để phân thân kết thành Sát Đan.","anchor":"có thể cho phân thân kết thành “Sát Đan”"}]}},{"id":"khoi-loi-thuat","name":"Khôi lỗi thuật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Thuật khôi lỗi","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập"],"blurb":"Khôi lỗi thuật được nhắc như pháp môn kết hợp với Đại Diễn Quyết. Khi phối hợp với tầng hai Đại Diễn Quyết, uy lực chân chính mới được bộc lộ rõ.","detail":"Trong quá trình Hàn Lập chuyên tu Đại Diễn Quyết tầng hai, khôi lỗi thuật được nêu là phần phối hợp quan trọng để phát huy uy lực đáng sợ của công pháp thần thức này.","congNang":["Kết hợp Đại Diễn Quyết để phát huy khả năng điều khiển khôi lỗi và phân thần @c0374"],"tabs":{"tienTrinh":[{"chuong":"@c0374","loai":"nhắc tới","importance":"normal","giaiDoan":"Kết hợp Đại Diễn Quyết","text":"Khôi lỗi thuật được nêu là phải kết hợp với Đại Diễn Quyết tầng hai mới lộ uy lực chân chính.","anchor":"công pháp cùng khôi lỗi thuật kết hợp lại một chỗ"}]},"nguon":["@c0374"]},{"id":"huyet-luyen-than-quang","name":"Huyết luyện thần quang","cn":"血煉身光","aliases":["Huyết Luyện Thần Quang"],"loai":"cong-phap","loaiLabel":"Ma công","phamCap":"không rõ","hePhai":"ma công Việt hoàng","soHuu":["Việt hoàng","Khúc Hồn"],"blurb":"Huyết luyện thần quang là ma công Việt hoàng từng tu luyện. Hàn Lập nhận định uy lực của nó mạnh và dự định để Khúc Hồn tu luyện sau khi Trúc Cơ.","detail":"Hàn Lập lấy ma công này từ ngọc giản hôi bạch chi khí, nhớ rõ uy lực từng thấy nơi Việt hoàng, nên chuẩn bị nó làm lộ tuyến tu luyện cho phân thân Khúc Hồn sau khi Trúc Cơ.","nguonGoc":"Ma công Việt hoàng từng tu luyện @c0374","congNang":["Dùng làm ma công tu luyện cho Khúc Hồn sau khi Trúc Cơ @c0374","Phóng huyết quang bao phủ toàn thân hộ thể"],"nguoiTu":[{"ten":"Việt hoàng","tuChuong":"@c0374","tangDatToi":"không rõ","trangThai":"đã từng tu luyện"},{"ten":"Khúc Hồn","tuChuong":"@c0374","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0374","loai":"nhắc tới","importance":"normal","giaiDoan":"Chuẩn bị cho Khúc Hồn","text":"Hàn Lập xác định Huyết luyện thần quang là ma công Việt hoàng từng tu luyện và chuẩn bị cho Khúc Hồn tu sau khi Trúc Cơ.","anchor":"ma công Việt hoàng tu luyện “Huyết luyện thần quang”"},{"chuong":"@c0426","loai":"thi triển","importance":"normal","giaiDoan":"Khúc Hồn thi triển trước quái ảnh","text":"Khúc Hồn phóng huyết quang hộ thể sánh vai Hàn Lập chuẩn bị chiến đấu. Quái ảnh nhận ra gọi tên Huyết Luyện thân quang, hỏi là môn hạ Cực Âm hay Cực Huyễn, tiết lộ công pháp liên quan cả hai nhánh truyền thừa.","anchor":"Huyết Luyện thân quang! Tốt! Tốt! Các ngươi là môn hạ của Cực Âm hay Cực Huyễn?"}]},"nguon":["@c0374","@c0426"]},{"id":"luc-don-thuy-ba-dai-tran","name":"Lục độn thủy ba đại trận","cn":"","aliases":["Lục độn thủy ba trận","Lục độn thủy ba đại trận"],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Lục Liên Điện sử dụng","soHuu":["Lục Liên Điện"],"blurb":"Trận pháp được Lục Liên Điện dự định dùng trong hành động vây bắt yêu thú cấp sáu. Sáu tu sĩ Giả Đan được mời chủ trì trận để phối hợp hai khách khanh trưởng lão Kết Đan kỳ.","detail":"Lục Liên Điện tiết lộ kế hoạch bày Lục độn thủy ba đại trận khi săn yêu thú cấp sáu, trong đó sáu tu sĩ Giả Đan chỉ cần chủ trì trận, còn hai trưởng lão Kết Đan kỳ là lực lượng ra tay chính. Hàn Lập nhận ra tên trận này vì từng thấy trong tư liệu trận pháp Tân Như Âm tặng.","dinhDanh":"goc","congNang":["Hỗ trợ vây bắt yêu thú cấp sáu bằng cách để sáu tu sĩ Giả Đan chủ trì trận phối hợp cao thủ Kết Đan kỳ @c0377"],"trangThai":"được Lục Liên Điện chuẩn bị dùng","capNhatToi":"@c0377","tabs":{"tienTrinh":[{"chuong":"@c0377","loai":"xuất hiện","importance":"normal","giaiDoan":"Kế hoạch săn yêu thú cấp sáu","text":"Lục Liên Điện dự định bày Lục độn thủy ba đại trận để sáu tu sĩ Giả Đan chủ trì, phối hợp hai trưởng lão Kết Đan kỳ lấy Yêu Đan của yêu thú cấp sáu.","anchor":"Lại bày ra “Lục độn thủy ba đại trận”. Chỉ cần sáu tu sĩ Giả Đan cảnh giới tiến đến chủ trì trận thôi"}]},"nguon":["@c0377"]},{"id":"bich-thuy-thanh-giap-dai-tran","name":"Bích Thủy Thanh Giáp Đại Trận","aliases":["Bích Thủy Thanh Giáp Trận"],"cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập","Khúc Hồn"],"blurb":"Bích Thủy Thanh Giáp Đại Trận là bộ trận khí đầy đủ Hàn Lập lấy ra làm hậu thủ trước trận săn Anh Lý Thú.","detail":"Hàn Lập nhận định trận này kém Điên Đảo Ngũ Hành Trận và Lục Điện Thủy Ba Trận nhưng mạnh hơn trận pháp thường, lại dễ bố trí vì có đủ trận kỳ và trận bàn. Khúc Hồn được lệnh cắm quanh tảng đá nơi hai người nghỉ để tăng phòng bị.","dinhDanh":"goc","congNang":["Phòng bị quanh chỗ nghỉ của Hàn Lập và Khúc Hồn trước khi vào trận săn yêu @c0380"],"dacDiem":"Bộ trận khí đầy đủ, gồm hơn mười trận kỳ và năm sáu trận bàn, dễ bố trí hơn các trận pháp phức tạp.","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0380","tangDatToi":"sử dụng trận khí","trangThai":"dang-dung"},{"ten":"Khúc Hồn","tuChuong":"@c0380","tangDatToi":"bố trí trận kỳ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0380","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí hậu thủ","text":"Hàn Lập lấy bộ Bích Thủy Thanh Giáp Đại Trận ra và sai Khúc Hồn bố trí quanh tảng đá để tự phòng bị trước trận săn yêu.","anchor":"Đây chính là trận khí đầy đủ của “Bích Thủy Thanh Giáp Trận”"}]},"capNhatToi":"@c0380","nguon":["@c0380"]},{"id":"thuy-cuong-than-loi","name":"Thủy Cương Thần Lôi","aliases":[],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thủy hệ","soHuu":["Anh Lý Thú"],"blurb":"Thủy Cương Thần Lôi là thần thông của Anh Lý Thú, khiến Miêu trưởng lão e ngại trong lúc bị truy đuổi.","detail":"Dấu hiệu thi triển là tiếng trẻ con khóc biến kèm tiếng sấm càng lúc càng lớn trong khối sương trắng. Miêu trưởng lão vừa nhận ra đã thúc Cổ trưởng lão tăng tốc, cho thấy uy lực của thần thông này đủ khiến tu sĩ Kết Đan cảnh giác.","dinhDanh":"goc","thuocTinh":"Thủy hệ","congNang":["Tạo áp lực công kích trong khối sương trắng, khiến tu sĩ Kết Đan phải vội tăng tốc tránh né @c0380"],"uyLuc":"Khiến Miêu trưởng lão lo sợ trong cuộc dẫn dụ Anh Lý Thú.","nguoiTu":[{"ten":"Anh Lý Thú","tuChuong":"@c0380","tangDatToi":"sắp thi triển","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0380","loai":"thi triển","importance":"normal","giaiDoan":"Truy đuổi trên biển","text":"Trong lúc truy đuổi Miêu trưởng lão và Cổ trưởng lão, Anh Lý Thú phát dấu hiệu sắp dùng Thủy Cương Thần Lôi.","anchor":"Không ổn, tên này vừa muốn sử dụng Thủy Cương Thần Lôi"}]},"capNhatToi":"@c0380","nguon":["@c0380"]},{"id":"tran-ky-mau-lam-tran-phap-vay-anh-ly-thu","name":"Trận kỳ màu lam / trận pháp vây Anh Lý Thú","cn":"","loai":"than-thong","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Lục Liên Điện","soHuu":["Phùng Tam Nương","Khúc Hồn","Trung niên nho sinh","Thanh Toán Tử"],"blurb":"Trận pháp dùng các trận kỳ màu lam để ẩn thân và dựng màn hào quang vây Anh Lý Thú trên mặt biển. Trận bị đòn quyết tử của yêu thú công phá.","detail":"Nhóm Phùng Tam Nương dùng trận kỳ màu lam khởi động trận, khiến quang hoa màu lam nổi lên bốn phía và hình thành màn hào quang bao lấy bạch vụ của Anh Lý Thú. Trận có tác dụng vây khốn, che giấu người bày trận và gia cố màn hào quang, nhưng bị Thủy cương thần lôi cùng bạch vụ toàn phong phá vỡ.","congNang":["Ẩn nhóm bày trận và dựng màn hào quang vây khốn Anh Lý Thú @c0381"],"uyLuc":"Có thể tạm thời vây giữ Anh Lý Thú để hai trưởng lão Kết Đan kỳ tế dị bảo.","dacDiem":"Dựa vào các trận kỳ màu lam và pháp lực của nhiều tu sĩ duy trì.","trangThai":"bị phá","capNhatToi":"@c0381","nguon":["@c0381"],"tabs":{"tienTrinh":[{"chuong":"@c0381","loai":"xuất hiện","importance":"normal","giaiDoan":"Vây yêu thú","text":"Trận pháp được kích hoạt để vây Anh Lý Thú bằng quang hoa màu lam, nhưng sau đó bị đòn quyết tử của yêu thú phá vỡ.","anchor":"bốn phía quang hoa màu lam mênh mông đại khởi"}]}},{"id":"bach-vu-toan-phong-cua-anh-ly-thu","name":"Bạch vụ toàn phong của Anh Lý Thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông yêu thú","phamCap":"không rõ","hePhai":"Anh Lý Thú","soHuu":["Anh Lý Thú"],"blurb":"Thần thông cuộn bạch vụ thành cơn lốc khổng lồ của Anh Lý Thú. Chiêu này phối hợp Thủy cương thần lôi để công phá trận môn.","detail":"Anh Lý Thú xoay bạch vụ thành một cơn lốc lớn, cuốn sóng biển và dồn công kích vào trận môn do trung niên nho sinh trấn giữ. Khi kết hợp với Thủy cương thần lôi, đòn này phá vỡ đại trận vây yêu.","congNang":["Cuộn bạch vụ thành cơn lốc lớn để phá trận môn @c0381"],"uyLuc":"Phá vỡ đại trận vây Anh Lý Thú khi phối hợp với Thủy cương thần lôi.","dacDiem":"Cơn lốc sinh từ bạch vụ quanh thân Anh Lý Thú, cuốn động sóng lớn trên biển.","trangThai":"đã thi triển","capNhatToi":"@c0381","nguon":["@c0381"],"tabs":{"tienTrinh":[{"chuong":"@c0381","loai":"thi triển","importance":"normal","giaiDoan":"Phá trận","text":"Anh Lý Thú hóa bạch vụ thành cơn lốc khổng lồ, phối hợp Thủy cương thần lôi đánh vào trận môn và phá vỡ đại trận.","anchor":"một lát sau liền hóa thành một cổ toàn phong thật lớn"}]}},{"id":"huyen-am-ma-khi","name":"Huyền Âm ma khí","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Ma khí / thần thông","phamCap":"không rõ","hePhai":"Cực Âm Đảo","soHuu":["Ô Sửu"],"blurb":"Huyền Âm ma khí là hắc khí được hai trưởng lão Miêu, Cổ nhận ra khi Ô Sửu xuất hiện bên Anh Lý Thú. Ma khí này cuốn quanh khu vực yêu thú bị đóng băng thành gió lốc đen.","detail":"Trong lần Ô Sửu xuất hiện, Huyền Âm ma khí hiện ra dưới dạng hắc khí khiến Miêu trưởng lão và Cổ trưởng lão nhận ra lai lịch. Hàn Lập cảm thấy tà khí này có nét tương tự Huyết luyện thần quang trên Khúc Hồn và liên hệ đến Huyền Âm Kinh trong ngọc giản trắng xám.","thuocTinh":"ma khí","uyLuc":"Có thể cuốn hắc khí quanh khu vực Anh Lý Thú bị đóng băng.","dacDiem":"Khiến Hàn Lập nghi có liên hệ với Huyết luyện thần quang và Huyền Âm Kinh.","congNang":["Cuốn hắc khí quanh khu vực Anh Lý Thú bị đóng băng @c0382"],"nguoiTu":[{"ten":"Ô Sửu","tuChuong":"@c0382","tangDatToi":"","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0382","loai":"xuất hiện","importance":"normal","giaiDoan":"Hắc khí lộ diện","text":"Huyền Âm ma khí xuất hiện dưới dạng hắc khí quanh Anh Lý Thú và bị hai trưởng lão Miêu, Cổ nhận ra.","anchor":"tựa hồ nhận ra được lai lịch hắc khí trên mặt đất"}]},"capNhatToi":"@c0382","nguon":["@c0382"]},{"id":"huyen-am-cong","name":"Huyền âm công","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Cực Âm Đảo","soHuu":["Ô Sửu"],"blurb":"Huyền âm công là công pháp Ô Sửu tu luyện tại Loạn Tinh Hải. Nhờ công pháp này, hắn được đánh giá không phải tu sĩ Kết Đan sơ kỳ bình thường có thể so sánh.","detail":"Huyền âm công được nêu trực tiếp khi phe Lục Liên Điện cân nhắc thực lực Ô Sửu. Công pháp này làm nền cho uy hiếp của Ô Sửu trong vụ tranh đoạt chiến lợi phẩm Anh Lý Thú.","thuocTinh":"huyền âm","uyLuc":"Khiến Ô Sửu vượt khỏi mức Kết Đan sơ kỳ bình thường.","dacDiem":"Gắn với danh tiếng ma đạo của Cực Âm Đảo tại Loạn Tinh Hải.","congNang":["Tăng thực lực chiến đấu của Ô Sửu đến mức Kết Đan sơ kỳ bình thường khó sánh @c0382"],"nguoiTu":[{"ten":"Ô Sửu","tuChuong":"@c0382","tangDatToi":"","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0382","loai":"xuất hiện","importance":"normal","giaiDoan":"Công pháp của Ô Sửu","text":"Huyền âm công được nêu là công pháp Ô Sửu tu luyện, khiến hắn không giống tu sĩ Kết Đan sơ kỳ bình thường.","anchor":"tu luyện công pháp “Huyền âm công” không phải bất cứ tu sĩ Kết đan bình thường có thể so sánh"}]},"capNhatToi":"@c0382","nguon":["@c0382"]},{"id":"nguyet-nha-quang-nhan","name":"Nguyệt Nha quang nhận","cn":"","loai":"than-thong","loaiLabel":"Công kích pháp bảo","phamCap":"Liên quan tu sĩ Kết Đan","hePhai":"Lục Liên Điện","soHuu":["Cổ trưởng lão"],"blurb":"Nguyệt Nha quang nhận là công kích hình trăng khuyết do Cổ trưởng lão thi triển trong lúc truy sát Hàn Lập. Đòn này phá liên tiếp nhiều pháp khí phòng ngự và công kích của Hàn Lập.","detail":"Cổ trưởng lão xuất thủ tạo hai đạo quang nhận hình trăng khuyết, phá Thanh Ngưng Kính, Quy Xác pháp khí, Ô Long Cập và năm đạo phi nhận trắng đen. Huyết quang xích giao của Khúc Hồn cùng quang xử khôi lỗi thú mới tạm thời giữ được thế giằng co.","thuocTinh":"Hoàng quang, quang nhận hình trăng khuyết","uyLuc":"Phá nhiều đỉnh giai pháp khí liên tiếp trong giao chiến với Hàn Lập.","dacDiem":"Tấn công sắc bén, áp đảo lớp phòng ngự pháp khí thông thường của tu sĩ Trúc Cơ.","congNang":["Phá hủy và xuyên phá nhiều lớp pháp khí phòng ngự, công kích của Hàn Lập @c0383"],"nguoiTu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0383","tangDatToi":"Thi triển trong giao chiến","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0383","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát Hàn Lập","text":"Cổ trưởng lão thi triển Nguyệt Nha quang nhận, phá nhiều pháp khí của Hàn Lập và ép Khúc Hồn phải dùng huyết quang xích giao chống đỡ.","anchor":"Sau đó hai tay của Cổ trưởng lão đột nhiên xuất ra, nhanh chóng biến thành Nguyệt Nha quang nhận"}]},"capNhatToi":"@c0383","nguon":["@c0383"]},{"id":"huyet-quang-xich-giao-cua-khuc-hon","name":"Huyết quang xích giao của Khúc Hồn","cn":"","loai":"than-thong","loaiLabel":"Huyết quang thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Khúc Hồn"],"blurb":"Huyết quang xích giao là thủ đoạn Khúc Hồn dùng để chống đỡ quang nhận của Cổ trưởng lão. Huyết quang bộc phát rồi hóa thành xích giao hồng quang trong thời gian ngắn.","detail":"Khi các pháp khí của Hàn Lập bị Nguyệt Nha quang nhận phá vỡ, Khúc Hồn gầm lớn, khiến huyết quang quanh thân điên cuồng tuôn ra và hóa thành xích giao. Thủ đoạn này phối hợp với quang xử từ khôi lỗi thú để tạm giữ thế giằng co với hai đạo quang nhận.","thuocTinh":"Huyết quang","uyLuc":"Có thể tạm thời chống đỡ công kích của tu sĩ Kết Đan khi phối hợp với khôi lỗi thú.","dacDiem":"Hóa huyết quang thành xích giao để va chạm trực diện với quang nhận.","congNang":["Chặn Nguyệt Nha quang nhận của Cổ trưởng lão trong thời gian ngắn @c0383"],"nguoiTu":[{"ten":"Khúc Hồn","tuChuong":"@c0383","tangDatToi":"Thi triển trong giao chiến","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0383","loai":"thi triển","importance":"normal","giaiDoan":"Chống quang nhận","text":"Khúc Hồn bộc phát huyết quang hóa thành xích giao để giằng co với công kích của Cổ trưởng lão.","anchor":"tiếp theo đó hồng quang huyết sắc bên người điên cuồng mà tuông ra"}]},"capNhatToi":"@c0383","nguon":["@c0383"]},{"id":"vo-danh-khau-quyet","name":"Vô danh khẩu quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp/khẩu quyết","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập","Khúc Hồn"],"blurb":"Khẩu quyết được Hàn Lập và Khúc Hồn vận dụng để thu liễm khí tức khi ẩn dưới biển.","detail":"Trong lúc né luồng thần thức cường đại truy tìm, Hàn Lập và Khúc Hồn phối hợp vô danh khẩu quyết với tấm lụa mỏng đoạn tuyệt khí tức để che giấu tung tích dưới đáy biển.","thuocTinh":"ẩn nấp, thu liễm khí tức","congNang":["Thu liễm khí tức, hỗ trợ Hàn Lập và Khúc Hồn ẩn dưới biển tránh thần thức truy tìm @c0384"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0384","tangDatToi":"","trangThai":"đang dùng"},{"ten":"Khúc Hồn","tuChuong":"@c0384","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn nấp dưới biển","text":"Hàn Lập và Khúc Hồn vận dụng vô danh khẩu quyết cùng tấm lụa mỏng để che giấu khí tức trước thần thức cường đại.","anchor":"đồng thời hai người cũng vận dụng vô danh khẩu quyết"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"tho-ly-quyet","name":"Thổ Ly Quyết","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"thượng tầng","hePhai":"hệ thổ","soHuu":["Cổ trưởng lão","Hàn Lập"],"blurb":"Thổ Ly Quyết là công pháp thượng tầng hệ thổ xuất hiện trong túi trữ vật Cổ trưởng lão.","detail":"Hàn Lập phát hiện đạo thư Thổ Ly Quyết khi kiểm kê túi trữ vật của Cổ trưởng lão. Hắn nhận định đây là công pháp thượng tầng nhưng không tu luyện.","thuocTinh":"hệ thổ","dacDiem":"Công pháp thượng tầng, tồn tại dưới dạng đạo thư trong túi trữ vật Cổ trưởng lão.","nguonGoc":"Thu được từ túi trữ vật của Cổ trưởng lão.","congNang":["Dùng làm công pháp tu luyện hệ thổ, được Hàn Lập nhận định là công pháp thượng tầng @c0384"],"nguoiTu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0384","tangDatToi":"","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0384","tangDatToi":"","trangThai":"thu giữ, không tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"xuất hiện","importance":"normal","giaiDoan":"Chiến lợi phẩm","text":"Thổ Ly Quyết xuất hiện trong túi trữ vật của Cổ trưởng lão và được Hàn Lập nhận định là công pháp thượng tầng.","anchor":"chỉ là công pháp thượng tầng “Thổ Ly Quyết” mà thôi"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"dai-tran-vay-khon-co-truong-lao","name":"Đại trận vây khốn Cổ trưởng lão","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Đại trận Hàn Lập dùng để hạn chế Cổ trưởng lão trên biển, tăng áp lực nước biển và phối hợp vây sát.","detail":"Trận pháp làm Cổ trưởng lão chịu áp lực nước biển tăng mạnh, khiến pháp lực tiêu hao nặng khi duy trì Hỗn Nguyên Bát và hoàng quang hộ thể. Nhờ áp chế này, Hàn Lập và Khúc Hồn phá được phòng hộ của đối phương.","congNang":["Hạn chế hành động và tăng áp lực lên người bị vây trong trận @c0384","Phối hợp công kích khiến hoàng quang hộ thể của Cổ trưởng lão tan vỡ @c0384"],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"thi triển","importance":"normal","giaiDoan":"Vây sát Cổ trưởng lão","text":"Đại trận tăng áp lực lên Cổ trưởng lão, buộc Hỗn Nguyên Bát và hoàng quang hộ thể của ông ta tiêu hao mạnh trong trận phục kích.","anchor":"áp lực vốn đã rất lớn trên người hắn đột nhiên tăng lên mấy lần"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"don-thuat-quy-di-cua-han-lap","name":"Độn thuật quỷ dị của Hàn Lập","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông/độn thuật","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Độn thuật giúp Hàn Lập vô thanh vô tức xuất hiện và biến mất trong cận chiến.","detail":"Trong trận vây giết Cổ trưởng lão, Hàn Lập nhiều lần bất ngờ xuất hiện cạnh đối phương rồi biến mất, khiến Cổ trưởng lão kinh hãi vì không nhận ra loại độn thuật đang được dùng.","congNang":["Ẩn hiện bất ngờ trong cận chiến, tạo thế tập kích đối thủ @c0384"],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"thi triển","importance":"normal","giaiDoan":"Cận chiến trong đại trận","text":"Hàn Lập dùng độn thuật xuất hiện và biến mất bất ngờ bên cạnh Cổ trưởng lão, phối hợp phi châm và cự kiếm ép đối thủ lộ sơ hở.","anchor":"đối phương dùng là loại độn thuật quỷ dị nào"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"phi-cham-am-khi","name":"Phi châm / Âm Khí","cn":"","aliases":["Âm Khí"],"loai":"khac","loaiLabel":"Pháp khí ám kích","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Phi châm là thủ đoạn ám kích âm độc được Hàn Lập dùng để xuyên phá phòng hộ và đánh vào yếu hại Cổ trưởng lão.","detail":"Hơn mười đạo huyền ti hoặc phi châm vây quanh Cổ trưởng lão, chui vào hoàng quang hộ thể và sau khi phòng hộ tan vỡ thì công kích yếu hại. Cổ trưởng lão nhận ra đây là loại Âm Khí âm độc trong tu tiên giới.","dacDiem":"Âm độc, khó phòng bị, thích hợp đánh lén vào yếu hại.","congNang":["Xuyên vào lớp hộ thể và chờ thời cơ công kích yếu hại đối phương @c0384"],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"thi triển","importance":"normal","giaiDoan":"Phá hộ thể Cổ trưởng lão","text":"Phi châm của Hàn Lập chui vào hoàng quang, chờ lúc phòng hộ Cổ trưởng lão tan vỡ để đánh vào yếu hại.","anchor":"Đối với tu tiên giới có loại mệnh danh là “Âm Khí”"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"thuy-tien-thuat","name":"Thủy Tiến Thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp thuật cấp thấp","phamCap":"cấp thấp","hePhai":"Hải Viên","soHuu":["Hải Viên"],"blurb":"Pháp thuật cấp thấp mà yêu thú Hải Viên có thể sử dụng.","detail":"Thủy Tiến Thuật khiến Hải Viên khác với viên hầu thường và góp phần làm chúng có giá trị để tu sĩ cấp thấp thu phục làm tạp dịch động phủ.","congNang":["Yêu thú Hải Viên thi triển thủy pháp cấp thấp @c0385"],"tabs":{"tienTrinh":[{"chuong":"@c0385","loai":"xuất hiện","importance":"normal","giaiDoan":"Đặc tính Hải Viên","text":"Hải Viên được mô tả là yêu thú cấp thấp có thể dùng Thủy Tiến Thuật.","anchor":"yêu thú này có thể sử dụng pháp thuật cấp thấp “Thủy Tiến Thuật”"}]},"capNhatToi":"@c0385","nguon":["@c0385"]},{"id":"an-nac-tran-phap-binh-thuong","name":"Ẩn nặc trận pháp bình thường","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp che giấu động khẩu động phủ tạm trên Hải Viên Đảo.","detail":"Hàn Lập phối hợp trận pháp này với một bộ trận khí đầy đủ để che lại động khẩu trước khi vào mật thất bế quan.","congNang":["Che giấu động khẩu động phủ tạm @c0385"],"tabs":{"tienTrinh":[{"chuong":"@c0385","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí động phủ tạm","text":"Hàn Lập dùng ẩn nặc trận pháp bình thường để che động khẩu động phủ tạm.","anchor":"một bộ trận khí đầy đủ và một cái ẩn nặc trận pháp bình thường che lại động khẩu"}]},"capNhatToi":"@c0385","nguon":["@c0385"]},{"id":"ba-dai-tran-che-day-dong-phu-tieu-hoan-dao","name":"Ba đại trận che đậy động phủ Tiểu Hoàn Đảo","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Ba đại trận bên ngoài động phủ cũ của Hàn Lập tại Tiểu Hoàn Đảo.","detail":"Các đại trận này có thể che giấu động phủ, nhưng Hàn Lập cho rằng khó chống đỡ lâu nếu bị tu sĩ Kết Đan Kỳ cường công.","congNang":["Che giấu động phủ cũ tại Tiểu Hoàn Đảo @c0385"],"tabs":{"tienTrinh":[{"chuong":"@c0385","loai":"nhắc tới","importance":"normal","giaiDoan":"Nguy cơ động phủ cũ","text":"Hàn Lập đánh giá ba đại trận che đậy động phủ cũ khó chống lâu trước tu sĩ Kết Đan Kỳ.","anchor":"Tuy bên ngoài động phủ kia có ba đại trận che đậy"}]},"capNhatToi":"@c0385","nguon":["@c0385"]},{"id":"ma-hoa-cua-khuc-hon","name":"Ma hỏa của Khúc Hồn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Khúc Hồn"],"blurb":"Tử diễm ma hỏa do Khúc Hồn thi triển khi kiểm nghiệm ngân cầu Phệ Kim Trùng.","detail":"Khúc Hồn khiến huyết quang chuyển thành tử diễm ma hỏa để thiêu đốt ngân cầu. Phệ Kim Trùng không bị hại, trái lại còn cắn nuốt ngọn lửa, cho thấy ma hỏa này bị đàn trùng khắc chế trong lần thử nghiệm.","thuocTinh":"ma hỏa","uyLuc":"Dùng để thiêu đốt kiểm nghiệm mục tiêu, nhưng bị Phệ Kim Trùng cắn nuốt trong chương này.","dacDiem":"Từ huyết quang chuyển thành tử diễm ma hỏa.","congNang":["Thiêu đốt mục tiêu để thử sức chịu đựng và uy lực phòng ngự của ngân cầu Phệ Kim Trùng."],"nguoiTu":[{"ten":"Khúc Hồn","tuChuong":"@c0387","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0387","loai":"thi triển","importance":"normal","giaiDoan":"Thử Phệ Kim Trùng","text":"Khúc Hồn chuyển huyết quang thành tử diễm ma hỏa để đốt ngân cầu, nhưng Phệ Kim Trùng không bị thiêu hủy mà còn cắn nuốt ngọn lửa.","anchor":"Nhất thời, huyết quang bổng nhiên từ hồng chuyển sang tử, đảo mắt liền hung hung thiêu đốt"}]},"capNhatToi":"@c0387","nguon":["@c0387"]},{"id":"huyet-quang-cua-khuc-hon","name":"Huyết quang của Khúc Hồn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Khúc Hồn"],"blurb":"Huyết quang do Khúc Hồn phóng ra để bao phủ ngân cầu Phệ Kim Trùng.","detail":"Theo lệnh Hàn Lập, Khúc Hồn phát ra huyết mang từ trước thân và năm ngón tay để chụp tới ngân cầu. Huyết quang này là bước thử đầu trước khi hắn chuyển sang tử diễm ma hỏa.","thuocTinh":"huyết quang","uyLuc":"Bao phủ mục tiêu trong quá trình kiểm nghiệm Phệ Kim Trùng.","dacDiem":"Có thể chuyển hóa thành tử diễm ma hỏa trong lần thi triển này.","congNang":["Phóng huyết mang bao lấy ngân cầu Phệ Kim Trùng."],"nguoiTu":[{"ten":"Khúc Hồn","tuChuong":"@c0387","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0387","loai":"thi triển","importance":"normal","giaiDoan":"Bao phủ ngân cầu","text":"Khúc Hồn phóng huyết quang từ trước thân và năm ngón tay để bao lấy ngân cầu Phệ Kim Trùng.","anchor":"Trước thân Khúc Hồn toát ra huyết quang, nhất thời từ trong năm ngón tay của quả đấm hé ra một tảng lớn huyết mang đánh tới"}]},"capNhatToi":"@c0387","nguon":["@c0387"]},{"id":"huyet-quang-cam-phap-cua-khuc-hon","name":"Huyết quang cấm pháp của Khúc Hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Kết Đan kỳ","hePhai":"","soHuu":["Khúc Hồn"],"blurb":"Thần thông huyết quang Khúc Hồn dùng để cấm chế và thu pháp khí đang công kích.","detail":"Khi nhóm chấp pháp tế pháp khí đánh tới, Khúc Hồn bộc phát huyết quang, kết pháp ấn và hô một chữ Cấm, khiến các pháp khí bị huyết quang bao phủ, dừng lại rồi bị thu mất.","dinhDanh":"goc","thuocTinh":"huyết quang","uyLuc":"Có thể chặn và thu pháp khí của nhiều tu sĩ Trúc Cơ kỳ cùng lúc.","dacDiem":"Kích phát bằng huyết quang, pháp ấn và khẩu lệnh Cấm.","congNang":["Cấm chế pháp khí đang công kích và thu lấy chúng @c0388"],"nguoiTu":[{"ten":"Khúc Hồn","tuChuong":"@c0388","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"thi triển","importance":"normal","giaiDoan":"Lộ uy trước nhóm chấp pháp","text":"Khúc Hồn dùng huyết quang cấm pháp khiến các pháp khí của nhóm Trúc Cơ kỳ dừng lại rồi thu mất.","anchor":"Mặt không chút thay đổi kết pháp ấn, mở miệng nói một chử “Cấm”"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"huyet-tru-cua-khuc-hon","name":"Huyết trụ của Khúc Hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Kết Đan kỳ","hePhai":"","soHuu":["Khúc Hồn"],"blurb":"Thần thông huyết trụ từ lòng bàn tay Khúc Hồn, dùng để truy sát kẻ bỏ chạy.","detail":"Khúc Hồn phun hai đạo huyết trụ màu đỏ từ lòng bàn tay, chớp mắt đuổi kịp hai tu sĩ bỏ chạy và đánh cả người lẫn hộ thân pháp khí thành bụi phấn.","dinhDanh":"goc","thuocTinh":"huyết quang","uyLuc":"Diệt tu sĩ Trúc Cơ cùng pháp khí hộ thân trong khoảnh khắc.","dacDiem":"Huyết trụ phóng ra từ lòng bàn tay, tốc độ truy kích rất nhanh.","congNang":["Truy sát mục tiêu bỏ chạy và phá hủy hộ thân pháp khí @c0388"],"nguoiTu":[{"ten":"Khúc Hồn","tuChuong":"@c0388","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát hai tu sĩ bỏ chạy","text":"Khúc Hồn phun hai đạo huyết trụ đánh nát hai tu sĩ bỏ chạy cùng pháp khí hộ thân của họ.","anchor":"hai đạo huyết trụ màu đỏ từ trong lòng bàn tay cuồng phún ra ngoài"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"huyet-van-tu-hoa-cua-khuc-hon","name":"Huyết vân tử hỏa của Khúc Hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Kết Đan kỳ","hePhai":"","soHuu":["Khúc Hồn"],"blurb":"Thần thông biến huyết vân thành tử hỏa phủ xuống, dùng để thiêu diệt nhiều mục tiêu.","detail":"Khúc Hồn tách huyết quang thành huyết vân, đánh pháp quyết màu tím vào đó khiến huyết vân hóa thành tử hỏa kín trời, thiêu nhóm chấp pháp và phòng ngự pháp khí thành tro bụi.","dinhDanh":"goc","thuocTinh":"huyết quang, tử hỏa","uyLuc":"Thiêu hủy cả tu sĩ Trúc Cơ và phòng ngự pháp khí.","dacDiem":"Từ huyết vân chuyển hóa thành lửa tím trên phạm vi rộng.","congNang":["Phủ lửa tím diện rộng để thiêu hủy người và pháp khí phòng ngự @c0388"],"nguoiTu":[{"ten":"Khúc Hồn","tuChuong":"@c0388","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"thi triển","importance":"normal","giaiDoan":"Thiêu sạch nhóm chấp pháp","text":"Khúc Hồn biến huyết vân thành tử hỏa, thiêu các tu sĩ còn lại và pháp khí phòng ngự thành tro bụi.","anchor":"huyết vân kia trong khoảnh khắc liền biến thành những ngọn lửa tím tỏa ra kín bầu trời"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"bi-thuat-nguyen-than-bai-cua-vien-dao-chu","name":"Bí thuật nguyên thần bài của Viên đảo chủ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Khôi Tinh Đảo","soHuu":["Viên đảo chủ"],"blurb":"Bí thuật Viên đảo chủ thi triển lên nguyên thần bài của đệ tử để nhận biết khi đệ tử gặp bất trắc.","detail":"Khi đệ tử trong nhóm chấp pháp chết, nguyên thần bài đã được Viên đảo chủ thi triển bí thuật lập tức xuất hiện dị biến, nhờ đó ông biết đệ tử gặp nạn.","dinhDanh":"goc","congNang":["Báo biến khi đệ tử liên hệ với nguyên thần bài chết @c0388"],"nguoiTu":[{"ten":"Viên đảo chủ","tuChuong":"@c0388","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"xuất hiện","importance":"normal","giaiDoan":"Nguyên thần bài báo biến","text":"Bí thuật trên nguyên thần bài phát sinh dị biến khi đệ tử của Viên đảo chủ chết.","anchor":"bên trong nguyên thần bài được trung niên nhân thi triển bí thuật liền xuất hiện dị biến"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"phu-van-tam-tung-thuat","name":"Phù Vân Tầm Tung Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Truy tung thuật","phamCap":"","hePhai":"","soHuu":["Tề đạo hữu"],"blurb":"Thuật truy tung Tề đạo hữu nói có thể dùng để xem hướng hung thủ rời khỏi hiện trường.","detail":"Sau khi tới nơi nhóm chấp pháp bị diệt, Tề đạo hữu nói có thể dùng Phù Vân Tầm Tung Thuật để tra phương hướng hung thủ rời đi và còn cơ hội đuổi kịp.","dinhDanh":"goc","congNang":["Xem xét phương hướng hung thủ rời đi để truy tung @c0388"],"nguoiTu":[{"ten":"Tề đạo hữu","tuChuong":"@c0388","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"xuất hiện","importance":"normal","giaiDoan":"Đề xuất truy tung","text":"Tề đạo hữu nêu Phù Vân Tầm Tung Thuật như cách xem hướng rời đi của hung thủ.","anchor":"Ta dùng “Phù Vân Tầm Tung Thuật” xem xét một chút"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"bi-thuat-che-day-tuong-mao","name":"Bí thuật che đậy tướng mạo","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật ngụy trang","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Hàn Lập","Khúc Hồn"],"blurb":"Bí thuật dùng để che dung mạo khi Hàn Lập và Khúc Hồn vào phường thị vùng biên. Người có tu vi không cao hơn Khúc Hồn nếu dùng thần thức dò xét cũng chỉ thấy hồng quang mơ hồ.","detail":"Hàn Lập và Khúc Hồn đồng thời thi triển bí thuật này để che đậy tướng mạo, tránh bị nhận diện sau khi Hàn Lập bị truy nã. Tác dụng được mô tả là che dung mạo và chống thần thức dò xét của tu sĩ không vượt quá Khúc Hồn.","thuocTinh":"ngụy trang, che giấu dung mạo","uyLuc":"Có thể khiến tu sĩ tu vi không cao hơn Khúc Hồn khó nhìn rõ tướng mạo thật.","dacDiem":"Khi bị thần thức dò xét, đối phương chỉ thấy một mảng hồng quang mơ hồ.","congNang":["Che dung mạo của người thi triển khi xuất hiện tại phường thị vùng biên @c0389","Gây nhiễu thần thức dò xét của tu sĩ có tu vi không cao hơn Khúc Hồn @c0389"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0389","tangDatToi":"đã dùng để che dung mạo","trangThai":"đang dùng"},{"ten":"Khúc Hồn","tuChuong":"@c0389","tangDatToi":"đã dùng để che dung mạo","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"thi triển","importance":"normal","giaiDoan":"Che giấu tại phường thị vùng biên","text":"Hàn Lập và Khúc Hồn dùng bí thuật này để che đậy tướng mạo trước khi mua nguyên liệu, hải đồ và điển tịch.","anchor":"Hàn Lập cùng Khúc Hồn dùng bí thuật đồng thời che đậy đi tướng mạo của hai người"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"truyen-tong-tran-di-ngoai-tinh-hai","name":"Truyền tống trận đi Ngoại Tinh Hải","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"không rõ","hePhai":"Tinh Cung","soHuu":["Tinh Cung"],"blurb":"Truyền tống trận do Thiên Tinh Cung xây trong Thiên Tinh Thành. Tu sĩ có thể trả nhiều linh thạch để tới các Yêu Thú Đảo ở Ngoại Tinh Hải.","detail":"Trận pháp này nối Thiên Tinh Thành với hơn mười Yêu Thú Đảo lớn nhỏ ở Ngoại Tinh Hải. Nó là một lý do quan trọng khiến Hàn Lập quyết định đến Thiên Tinh Thành, vì mở ra đường săn yêu thú lấy Yêu Đan.","nguonGoc":"Do Thiên Tinh Cung kiến tạo trong Thiên Tinh Thành.","uyLuc":"Có thể trực tiếp đưa tu sĩ từ Thiên Tinh Thành tới Ngoại Tinh Hải.","dacDiem":"Muốn sử dụng cần trả lượng lớn linh thạch.","congNang":["Truyền tống tu sĩ từ Thiên Tinh Thành tới hơn mười Yêu Thú Đảo ở Ngoại Tinh Hải @c0389"],"tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"xuất hiện","importance":"normal","giaiDoan":"Được điển tịch giới thiệu","text":"Truyền tống trận đi Ngoại Tinh Hải được giới thiệu là công trình của Thiên Tinh Cung trong Thiên Tinh Thành.","anchor":"Thiên Tinh Cung cũng có kiến tạo truyền tống trận trực tiếp đi đến Ngoại Tinh Hải"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"ba-bo-dai-tran-ngoai-dong-phu-thien-tinh","name":"Ba bộ đại trận ngoài động phủ Thiên Tinh","cn":"","loai":"khac","loaiLabel":"Trận pháp phòng hộ","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Ba bộ đại trận Hàn Lập tự bố trí bên ngoài động phủ tầng ba mươi chín ở Thánh sơn để tăng cường phòng hộ, do hắn không hoàn toàn tin vào cấm chế sẵn có.","detail":"Sáng hôm sau khi nhận động phủ, Hàn Lập một hơi bố trí ba bộ đại trận ngoài động phủ trước khi bắt đầu tu luyện lâu dài.","nguon":["@c0391"],"tabs":{"tienTrinh":[{"chuong":"@c0391","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí lần đầu","text":"Hàn Lập bố trí ba bộ đại trận bên ngoài động phủ tầng ba mươi chín để tăng phòng hộ, vì không hoàn toàn tin vào cấm chế sẵn có của Tinh Cung.","anchor":"Hắn một hơi bố trí ngoài động phủ ba bộ đại trận"}]}},{"id":"tran-phap-cam-che-dong-phu-tang-39","name":"Trận pháp cấm chế động phủ tầng ba mươi chín","cn":"","loai":"khac","loaiLabel":"Cấm chế / Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Tinh Cung"],"blurb":"Cấm chế sẵn có trong động phủ thuê ở Thánh sơn, được quảng cáo là thập phần lợi hại nhưng Hàn Lập không hoàn toàn tin tưởng.","detail":"Động phủ thuê tầng ba mươi chín có trận pháp cấm chế được xưng là rất lợi hại, tuy nhiên Hàn Lập vẫn tự bố trí thêm ba bộ đại trận vì không dám đặt hết niềm tin.","nguon":["@c0391"]},{"id":"ky-trung-bang","name":"Kỳ trùng bảng","cn":"","loai":"khac","loaiLabel":"Bảng xếp hạng","phamCap":"","hePhai":"","soHuu":["Tu sĩ Ngự Linh Tông"],"blurb":"Bảng xếp hạng kỳ trùng thượng cổ, Phệ Kim Trùng đứng hạng mười hai. Phần lớn kỳ trùng nhóm đầu đã diệt tích, độ tin cậy nhóm bài danh đầu không chắc chắn.","detail":"Bảng xếp hạng các loại kỳ trùng thượng cổ, được ghi trong ngọc giản nuôi trùng của tu sĩ Ngự Linh Tông. Phệ Kim Trùng xếp hạng mười hai, thuộc nhóm đầu. Các kỳ trùng đứng đầu bảng phần lớn đã tuyệt tích, độ đáng tin cậy của thứ hạng nhóm đầu cũng chỉ có trời mới biết.","tabs":{"tienTrinh":[{"chuong":"@c0392","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập tra cứu đánh giá Phệ Kim Trùng","text":"Hàn Lập dựa vào Kỳ trùng bảng để đánh giá giá trị thật của Phệ Kim Trùng, xác định chỉ khi đạt số lượng mười mấy vạn mới xứng thứ hạng.","anchor":"Còn độ đáng tin cậy của nhóm bài danh đầu trên Kỳ trùng bảng này thì cũng chỉ có trời mới biết"}]},"nguon":["@c0392"]},{"id":"dien-dao-ngu-hanh-tran","name":"Điên Đảo Ngũ Hành trận","cn":"颠倒五行阵","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Một trong ba đại trận Hàn Lập sai Khúc Hồn bố trí trên đường vào trung tâm Hồng Hô đảo, dùng phòng ngự chặn đường.","detail":"Đại trận phòng ngự được bố trí trên một trong ba con đường vào trung tâm Hồng Hô đảo, cùng hai trận Thiên Phong Cuồng Liệt và Huyễn Hình Thiên La tạo thế thiên la địa võng bảo vệ căn cứ sát yêu của Hàn Lập.","nguon":["@c0395"],"congNang":["Phòng ngự, chặn đường vào trung tâm đảo"],"tabs":{"tienTrinh":[{"chuong":"@c0395","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí tại Hồng Hô đảo","text":"Khúc Hồn bố trí Điên Đảo Ngũ Hành trận trên một trong ba con đường vào trung tâm đảo theo chỉ thị Hàn Lập.","anchor":"bắt đầu bố trí ba tòa đại trận \"Điên đảo Ngũ hành trận\""}]}},{"id":"huyen-hinh-thien-la-tran","name":"Huyễn Hình Thiên La trận","cn":"幻形天罗阵","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Đại trận thứ ba trong ba trận phòng ngự bố trí tại Hồng Hô đảo, có yếu tố ẩn hình/huyễn thuật.","detail":"Trận pháp mang tính chất ẩn hình và huyễn thuật, do Khúc Hồn bố trí theo chỉ thị Hàn Lập trên đường vào trung tâm Hồng Hô đảo, cùng Điên Đảo Ngũ Hành trận và Thiên Phong Cuồng Liệt trận hoàn thành thế thiên la địa võng.","nguon":["@c0395"],"congNang":["Phòng ngự, ẩn hình/huyễn thuật chặn đường vào trung tâm đảo"],"tabs":{"tienTrinh":[{"chuong":"@c0395","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí tại Hồng Hô đảo","text":"Được Khúc Hồn bố trí trên đường vào trung tâm đảo cùng hai trận pháp khác.","anchor":"\"Thiên phong cuồng liệt trận\" và \"Huyễn hình thiên la trận\""}]}},{"id":"dai-dien-quyet","name":"Đại Diễn Quyết","cn":"大衍诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Công pháp mà tu luyện tầng cao có thể đề cao khả năng Kết đan. Hàn Lập tu luyện tầng thứ ba mất hơn 20 năm.","detail":"Lâm sư huynh (thiếu chủ Thiên Trúc giáo) từng nói tu Đại Diễn Quyết tới tầng cao có thể đề cao khả năng Kết đan. Hàn Lập dựa vào lời này tu luyện, mất hơn 20 năm vất vả đột phá luyện thành tầng thứ ba. Không tu tầng thứ tư vì quá tốn thời gian.","thuocTinh":"","nguonGoc":"Lâm sư huynh (thiếu chủ Thiên Trúc giáo) đã nhắc tới tác dụng","yeuCau":"","uyLuc":"Tu tầng cao đề cao khả năng Kết đan","dacDiem":"Mỗi tầng tốn thời gian rất dài","cacTang":[{"ten":"Tầng thứ ba","moTa":"Hàn Lập mất hơn 20 năm vất vả đột phá luyện thành","chuong":"@c0398"}],"congNang":["Tu tầng cao đề cao khả năng Kết đan","Tăng cường thần thức vượt xa đồng cấp Kết Đan kỳ, cảm ứng được Nguyên Anh sơ kỳ"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0398","tangDatToi":"Tầng thứ ba","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0398","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Hàn Lập luyện thành tầng thứ ba","text":"Hàn Lập mất hơn 20 năm vất vả đột phá luyện thành tầng thứ ba Đại Diễn Quyết, theo gợi ý Lâm sư huynh rằng tu tầng cao có thể đề cao khả năng Kết đan. Không tu tầng thứ tư vì quá tốn thời gian.","anchor":"Hàn Lập dùng hơn hai mươi năm thời gian mới vất vả đột phá bình cảnh, miễn cưỡng luyện thành"},{"chuong":"@c0499","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hé lộ uy lực thần thức","text":"Hàn Lập tu luyện Đại Diễn quyết, thần thức vượt xa đồng cấp Kết Đan kỳ, tuy không bằng lão quái Cực Âm nhưng có thể cảm ứng tu sĩ Nguyên Anh sơ kỳ.","anchor":"tu luyện Đại Diễn quyết, thần thức tuy không cường đại như mấy lão quái vật Cực Âm nhưng cũng không kém quá xa"}]},"capNhatToi":"@c0398","nguon":["@c0398","@c0436","@c0499"]},{"id":"ho-my-chi-cong","name":"Hồ mỵ chi công","cn":"狐魅之功","aliases":["Mỵ thuật","Mê hồn thuật"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Diệu Âm Môn","soHuu":["Phạm Tĩnh Mai"],"blurb":"Mỵ thuật mê hồn thi triển qua ánh mắt chứa xuân ý nồng đậm nhằm khống chế tâm thần đối phương, khiến người trúng thuật trầm luân khó tự kiềm chế.","detail":"Phạm phu nhân thi triển qua ánh mắt nhằm khống chế Hàn Lập nhưng bị phản phệ bởi hàn ý trong mắt hắn, mất hiệu lực tức thì, người thi triển phun máu bị thương. Bị gọi là mỵ thuật, mê hồn thuật. Phản phệ khi gặp đối thủ tâm thần cường đại hơn.","congNang":["Mê hoặc tâm thần qua ánh mắt, tạo cảm giác trầm luân khó tự kiềm chế"],"nguoiTu":[{"ten":"Phạm Tĩnh Mai","tuChuong":"@c0401","tangDatToi":"Không rõ","trangThai":"thất bại bị phản phệ"}],"tabs":{"tienTrinh":[{"chuong":"@c0401","loai":"thi triển","importance":"normal","giaiDoan":"Phạm phu nhân thi triển nhắm Hàn Lập","text":"Phạm phu nhân dùng hồ mỵ chi công qua ánh mắt nhằm khống chế tâm thần Hàn Lập nhưng bị hàn ý phản phệ, mất hiệu lực tức thì, phun máu bị thương.","anchor":"một thân hồ mỵ chi công trong nháy mắt mất đi hiệu lực"}]},"nguon":["@c0401"]},{"id":"ho-my-thuat","name":"Hồ mỵ thuật","cn":"狐媚术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Diệu Âm Môn","soHuu":[],"blurb":"Mỵ công đặc sắc của Diệu Âm môn, có danh tiếng tại Loạn tinh hải, khiến nhiều nam tu sĩ thần hồn điên đảo.","detail":"Thuật mê hoặc đặc trưng của Diệu Âm môn, nổi tiếng trong vùng Loạn tinh hải. Nữ tu sĩ Diệu Âm môn xinh đẹp đa tài, kết hợp Hồ mỵ thuật khiến nhiều thế lực tranh đoạt làm bạn lữ song tu, tạo nên trợ lực đáng kể cho môn phái.","thuocTinh":"Mỵ hoặc","nguonGoc":"Diệu Âm môn truyền thừa","congNang":["Mê hoặc nam tu sĩ, khiến thần hồn điên đảo"],"tabs":{"tienTrinh":[{"chuong":"@c0402","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập điều tra Diệu Âm môn","text":"Được nhắc tới khi Hàn Lập thu thập tin tức về Diệu Âm môn, xác nhận Hồ mỵ thuật có danh tiếng tại Loạn tinh hải.","anchor":"Hồ mỵ thuật của Diệu Âm môn tại Loạn tinh hải xem như cũng có chút danh tiếng"}]},"nguon":["@c0402"]},{"id":"quy-thuy-ma-cong","name":"Quỳ Thủy ma công","cn":"","loai":"cong-phap","loaiLabel":"Ma công","phamCap":"","hePhai":"Ma đạo","soHuu":["Xích Hỏa lão quái"],"blurb":"Ma công của Xích Hỏa lão quái, biến hóa khó lường.","detail":"Công pháp ma đạo do Xích Hỏa lão quái tu luyện, được mô tả là biến hóa khó lường, góp phần khiến lão nổi tiếng khắp Loạn Tinh Hải.","congNang":["Biến hóa khó lường"],"nguoiTu":[{"ten":"Xích Hỏa lão quái","tuChuong":"@c0403","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0403","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc tới khi Xích Hỏa lão quái xuất hiện","text":"Được tu sĩ thì thầm nhắc tới như ma công biến hóa khó lường của Xích Hỏa lão quái.","anchor":"một thân Quỳ Thủy ma công biến hóa khó lường"}]},"nguon":["@c0403"]},{"id":"sat-yeu-bien-than-thuat-bien-the","name":"Sát yêu biến thân thuật (biến thể)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ẩn Sát Môn","soHuu":[],"blurb":"Biến thể của Sát yêu biến thân thuật: không cần niệm chú hóa kén liền biến thân thành công, bên trong cơ thể không có ngưng kết Huyết Ngưng Ngũ Hành Đan. Tu vi tăng một phần sau biến thân.","detail":"Tà tu trên đảo sử dụng, khác với Hắc Sát Giáo ở hai điểm: không cần niệm chú hóa kén đã biến thân thành công, và bên trong cơ thể không có ngưng kết Huyết Ngưng Ngũ Hành Đan. Hàn Lập nghi vấn mối liên hệ giữa nhóm này và Hắc Sát Giáo.","thuocTinh":"Ma đạo","dacDiem":"Không cần chú/kén, không có Huyết Ngưng Ngũ Hành Đan bên trong","congNang":["Biến thân thành hình tượng Sát Yêu, tu vi tăng một phần sau biến thân"],"nguon":["@c0404"]},{"id":"quy-dau-thuat","name":"Quỷ đầu thuật","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Ẩn Sát Môn","soHuu":["Môn chủ Ẩn Sát Môn"],"blurb":"Thuật ma khí của môn chủ Ẩn Sát Môn: toát ra ma khí trắng cao hơn mười trượng biến thành mặt quỷ khổng lồ, có thể nuốt hỏa quang đối thủ và phun quang cầu trắng đẩy lùi pháp bảo.","detail":"Môn chủ Ẩn Sát Môn thi triển: trên người toát ra đám ma khí màu trắng cao hơn mười trượng, quay cuồng biến thành mặt quỷ thật lớn. Quỷ đầu nuốt hỏa quang Kết Đan kỳ của Triệu trưởng lão, phun quang cầu trắng đánh tản pháp khí và pháp bảo đang tấn công. Công thủ toàn diện.","congNang":["Hình thành quỷ đầu khổng lồ công thủ toàn diện","Nuốt hỏa quang cấp Kết Đan kỳ","Phun quang cầu trắng đẩy lùi pháp bảo"],"nguon":["@c0404"]},{"id":"phu-than-thuat","name":"Phụ Thân thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tà đạo","soHuu":["Cực Âm lão tổ"],"blurb":"Tà thuật phụ hồn vào thân thể người khác để chiếm xác điều khiển, khuôn mặt vật chủ biến đổi thành dung mạo người phụ hồn. Hạn chế chỉ phát huy được ba phần tu vi.","detail":"Cực Âm lão tổ dùng thuật này phụ hồn vào thân Ô Sửu, chiếm xác điều khiển. Khuôn mặt Ô Sửu biến đổi thành lão già xấu xí nhỏ gầy mắt híp — dung mạo thật của lão tổ. Người trung niên Ẩn Sát Môn nhận định phụ thân thuật chỉ phát huy được ba phần tu vi so với bản thể, nhưng Cực Âm lão tổ ám chỉ thực lực hiện tại vượt hơn.","thuocTinh":"Âm / hồn phách","nguonGoc":"Cực Âm lão tổ thi triển","uyLuc":"Chiếm xác hoàn toàn, nhưng bị hạn chế ba phần tu vi khi không dùng bản thể","dacDiem":"Khuôn mặt vật chủ biến đổi thành dung mạo người phụ hồn","congNang":["Phụ hồn vào thân thể người khác để chiếm xác điều khiển"],"nguoiTu":[{"ten":"Cực Âm lão tổ","tuChuong":"@c0405","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0405","loai":"thi triển","importance":"major","giaiDoan":"Cực Âm lão tổ phụ hồn vào Ô Sửu","text":"Cực Âm lão tổ dùng phụ thân thuật chiếm thân Ô Sửu, khuôn mặt vặn vẹo biến thành lão già xấu xí. Người trung niên Ẩn Sát Môn nhận ra và quát hiện thân, tuyên bố chỉ ba phần tu vi nên dám đối đầu.","anchor":"khuôn mặt Ô Sửu bắt đầu trở nên mơ hồ vặn vẹo, méo mó, trong chốc lát mọi người ở đây kinh ngạc thấy hắn biến thành một lão già xấu xí, nhỏ gầy, hai mắt híp lại"}]},"nguon":["@c0405"]},{"id":"thien-do-thi-hoa","name":"Thiên đô thi hỏa","cn":"天都尸火","aliases":["Thiên đô thi hoả"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực cao (Nguyên Anh kỳ)","hePhai":"Ma đạo","soHuu":["Cực Âm tổ sư","Cực Âm lão tổ"],"blurb":"Ma hỏa đen như mực do Cực Âm tổ sư luyện thành, tạo hỏa cầu truy kích mục tiêu thiêu thành tro trong nháy mắt. Uy lực vượt Thanh dương ma hỏa của Ma đạo lục tông.","detail":"Hỏa cầu hắc vụ màu đen như mực bay lơ lửng trong lòng bàn tay, khi ném ra biến thành hắc diễm truy kích mục tiêu với tốc độ cực nhanh. Trong khoảng cách vài chục trượng, tu sĩ Kết Đan kỳ không thể tránh được. Thiêu tu sĩ mũi ưng Kết Đan kỳ thành tro bụi trong nháy mắt, pháp bảo bình thường không ngăn nổi. Hàn Lập đánh giá uy lực vượt Thanh dương ma hỏa. Tuy nhiên khi phụ thân vào người khác thì nhiều lắm chỉ dùng được vài lần, nếu dùng nhiều thì thể xác bị phụ thân sẽ tự bạo chết.","congNang":["Tạo hỏa cầu hắc vụ truy kích mục tiêu, thiêu thành tro trong nháy mắt","Tốc độ cực nhanh, vài chục trượng Kết Đan kỳ không tránh được","Pháp bảo bình thường không ngăn nổi","Ma hỏa uy lực cực mạnh","Thiên Đô Yêu Thi là sản phẩm phụ khi luyện"],"nguoiTu":[{"ten":"Cực Âm tổ sư","tuChuong":"@c0406","tangDatToi":"Đại thành","trangThai":"đang tu"},{"ten":"Cực Âm lão tổ","tuChuong":"@c0455","tangDatToi":"Có chút thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0406","loai":"xuat-hien","importance":"major","giaiDoan":"Luyện thành, lần đầu phô diễn","text":"Cực Âm tổ sư phô diễn Thiên đô thi hỏa vừa luyện thành, tạo hỏa cầu đen như mực rồi ném ra thiêu sát tu sĩ mũi ưng Kết Đan kỳ thành tro trong nháy mắt. Hàn Lập đánh giá uy lực vượt Thanh dương ma hỏa.","anchor":"một hỏa cầu hắc vụ màu đen như mực bay lơ lửng trong lòng tay của hắn"},{"chuong":"@c0455","loai":"nhắc tới","importance":"normal","giaiDoan":"Nhắc tên lần đầu","text":"Cực Âm lão tổ tiết lộ Thiên Đô thi hỏa đã có chút thành nhưng vẫn không tự tin đối kháng Thác Thiên ma công của Man Hồ Tử.","anchor":"Thiên Đô thi hỏa đã có chút thành công"},{"chuong":"@c0517","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Hàn Lập phát hiện bí thuật trong Huyền Âm Kinh","text":"Hàn Lập giải mã Huyền Âm Kinh, phát hiện Thiên Đô Thi Hỏa là bí thuật của Cực Âm tổ sư. Biết được nhược điểm qua khẩu quyết tu luyện nhưng không thể tu vì thiếu nền tảng và tu vi.","anchor":"Thiên Đô Thi Hỏa của Cực Âm tổ sư rõ ràng cũng ở trong đó"}]},"capNhatToi":"@c0406","nguon":["@c0406","@c0455","@c0517"]},{"id":"cam-than-thuat","name":"Cấm Thần thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Nguyên Anh kỳ","hePhai":"","soHuu":["Cực Âm tổ sư"],"blurb":"Thần thông cấp Nguyên Anh kỳ dùng Cấm Thần bài thu nhận ba phần nguyên thần của đối phương để khống chế sinh tử. Bị Tinh Cung nghiêm cấm sử dụng.","detail":"Cực Âm tổ sư dùng Cấm Thần bài yêu cầu mỗi tu sĩ giao ba phần nguyên thần. Đối phương có thể hủy thần thức trong bài khiến nạn nhân nhẹ thì ngu ngốc điên tàng, nặng thì chết tại chỗ. Chỉ tu sĩ Nguyên Anh kỳ mới thi triển được. Thiên Tinh song thánh từng nghiêm cấm tu sĩ Nguyên Anh kỳ sử dụng thuật này, nhưng Cực Âm tổ sư cho rằng cấm lệnh đã lỗi thời.","congNang":["Thu nhận ba phần nguyên thần đối phương vào Cấm Thần bài","Khống chế sinh tử: hủy thần thức trong bài → nạn nhân ngu ngốc hoặc chết"],"nguoiTu":[{"ten":"Cực Âm tổ sư","tuChuong":"@c0406","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0406","loai":"xuat-hien","importance":"major","giaiDoan":"Lần đầu xuất hiện, Cực Âm tổ sư uy hiếp toàn trường","text":"Cực Âm tổ sư dùng Cấm Thần bài yêu cầu mọi tu sĩ giao ba phần nguyên thần để quy thuận Cực Âm đảo. Tử Linh tiên tử cho biết Thiên Tinh song thánh đã nghiêm cấm tu sĩ Nguyên Anh kỳ sử dụng thuật này.","anchor":"mỗi người phải giao ra ba phần nguyên thần lên Cấm Thần bài này mới được yên ổn rời đi"}]},"capNhatToi":"@c0406","nguon":["@c0406"]},{"id":"huyen-am-dai-phap","name":"Huyền Âm đại pháp","cn":"玄陰大法","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Tà đạo","soHuu":["Ô Sửu","Cực Âm lão tổ"],"blurb":"Công pháp do Ô Sửu tu luyện, Hàn Lập suy luận có liên quan đến Huyền Âm Kinh trong ngọc giản.","detail":"Hàn Lập nhận ra công pháp Huyền Âm đại pháp mà Ô Sửu tu luyện có liên hệ với Huyền Âm Kinh, từ đó suy đoán mối liên quan giữa hai người — một ở Thiên Nam, một ở Loạn Tinh Hải — qua cổ Truyền Tống trận.","nguonGoc":"Liên quan Huyền Âm Kinh","nguoiTu":[{"ten":"Ô Sửu","tuChuong":"@c0407","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Cực Âm lão tổ","tuChuong":"@c0449","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0407","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập suy luận liên hệ","text":"Hàn Lập nghe Cực Âm lão tổ nói Sát Đan phân thân, suy luận ra Huyền Âm đại pháp của Ô Sửu liên quan Huyền Âm Kinh trong ngọc giản, và cả hai người ở Thiên Nam — Loạn Tinh Hải liên quan cổ Truyền Tống trận.","anchor":"công pháp \"Huyền Âm đại pháp\" mà Ô Sửu tu luyện có liên quan với \"Huyền Âm Kinh\" được nói đến trong ngọc giản"},{"chuong":"@c0449","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ bí mật bị cài sơ hở","text":"Huyền Cốt tiết lộ Huyền Âm đại pháp truyền cho Cực Âm đã bị cài sơ hở từ đầu, có thể đưa Cực Âm vào chỗ chết khi cần.","anchor":"Huyền Âm đại pháp của Cực Âm là do chính ta truyền thụ nên trong công pháp sớm đã lưu lại một ít sơ hở"}]},"nguon":["@c0407","@c0449"],"congNang":["Công pháp tu luyện quỷ đạo, chi tiết chưa rõ"]},{"id":"sat-dan-phan-than","name":"Sát Đan phân thân","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Ẩn Sát Môn","soHuu":["Tu sĩ Kết Đan kỳ Ẩn Sát Môn"],"blurb":"Bí thuật đặc thù của Ẩn Sát Môn, Cực Âm lão tổ nhận ra tu sĩ Ẩn Sát Môn dùng loại phân thân hy sinh chiến đấu.","detail":"Cực Âm lão tổ gọi nhóm tu sĩ Kết Đan kỳ Ẩn Sát Môn xả thân tấn công là Sát Đan phân thân, ám chỉ họ sử dụng loại bí thuật hy sinh phân thân để chiến đấu liều mạng.","nguon":["@c0407"]},{"id":"tu-sac-hoa-diem","name":"Tử sắc hỏa diễm","cn":"","aliases":["Hỏa xà tím"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Huyết đạo","soHuu":["Khúc Hồn"],"blurb":"Biến huyết đao thành tử hỏa bốc cháy không dập tắt được, sau biến hóa thành hỏa xà tím to bằng miệng bát bám trên đối thủ, hạn chế hành động.","detail":"Khúc Hồn bắt quyết biến huyết đao thành tử sắc hỏa diễm thiêu đốt trên người yêu thi, ngọn lửa tím không thể dập tắt. Sau đó tử hỏa biến hóa thành hỏa xà tím to bằng miệng bát, hung hăng bò trên thân thể đối phương, phối hợp lưới nhện Huyết ngọc tri thù tạo thành hai tầng vây khốn.","congNang":["Đốt cháy không dập tắt","Biến hình thành hỏa xà tím trói buộc đối thủ"],"nguoiTu":[{"ten":"Khúc Hồn","tuChuong":"@c0408","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0408","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Khúc Hồn bắt quyết biến huyết đao thành tử sắc hỏa diễm thiêu đốt yêu thi, sau biến thành hỏa xà tím bám trên người yêu thi phối hợp lưới nhện vây khốn.","anchor":"tử hỏa lại hóa thành hỏa xà màu tím to bằng miệng bát, hung hăng bò trên người nó"}]},"nguon":["@c0408"]},{"id":"nguyen-tu-than-quang","name":"Nguyên Từ thần quang","cn":"元磁神光","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực cao (chưa rõ cấp bậc cụ thể)","hePhai":"","soHuu":["Thiên Tinh song thánh","Thánh chủ Tinh Cung"],"blurb":"Thần thông do Thiên Tinh song thánh tu luyện, chưa luyện thành thì bị giam lỏng tại Thiên Tinh thành, nếu luyện thành sẽ vô địch Loạn Tinh hải.","detail":"Thiên Tinh song thánh tu luyện Nguyên Từ thần quang nhưng chưa thành, hậu quả là bị ràng buộc phải ở Thiên Tinh thành, mỗi năm chỉ rời đi nửa tháng vào mấy ngày cố định, rời đi lâu hơn tu vi đại giảm. Tuy nhiên khi ở Thiên Tinh thành dựa vào Nguyên Từ sơn phong thì gần như vô địch. Xích Hỏa tiết lộ nếu luyện thành thì sẽ không còn bị vây khốn, Loạn Tinh hải sẽ thuộc về họ.","congNang":["Sức mạnh vô địch khi ở Thiên Tinh thành (dựa Nguyên Từ sơn phong)","Chưa thành: bị ràng buộc địa điểm, rời đi tu vi đại giảm","Uy lực uy hiếp chiến lược: khiến cường giả tầm Nguyên Anh phải tránh lui ba thước"],"nguoiTu":[{"ten":"Thiên Tinh song thánh","tuChuong":"@c0408","tangDatToi":"Chưa thành","trangThai":"dang-tu"},{"ten":"Thánh chủ Tinh Cung","tuChuong":"@c0463","tangDatToi":"","trangThai":""}],"tabs":{"tienTrinh":[{"chuong":"@c0408","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hé lộ qua lời Cực Âm tổ sư và Xích Hỏa","text":"Thiên Tinh song thánh tu luyện Nguyên Từ thần quang chưa thành, bị giam lỏng tại Thiên Tinh thành mỗi năm chỉ rời nửa tháng. Nếu luyện thành sẽ vô địch Loạn Tinh hải.","anchor":"Thiên Tinh song thánh miễn là ở Thiên Tinh thành không ra, cơ hồ là tồn tại vô địch khi dựa vào Nguyên Từ sơn phong"},{"chuong":"@c0463","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc tới như vũ khí chiến lược","text":"Hai trưởng lão Tinh Cung nhắc tới Nguyên Từ Thần Quang như thần thông tuyệt đỉnh của thánh chủ, khiến Phong Bà Tử và lục đảo Thánh ma đạo phải tránh lui ba thước.","anchor":"đối mặt với Nguyên Từ Thần Quang của thánh chủ chúng ta, cũng chỉ có thể tránh lui ba thước"}]},"nguon":["@c0408","@c0463"]},{"id":"cong-phap-te-luyen-phan-than-dieu-am-mon","name":"Công pháp tế luyện phân thân (Diệu Âm Môn)","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Diệu Âm Môn","soHuu":["Diệu Âm Môn"],"blurb":"Công pháp tế luyện phân thân thuộc Diệu Âm Môn, hao phí rất lớn và xác suất thành công thấp nên rất ít người tu luyện.","detail":"Diệu Âm Môn sở hữu loại công pháp có thể tế luyện phân thân. Tuy nhiên hao phí cực lớn, xác suất thành công thấp, nên hiếm đệ tử tu luyện. Tử Linh tiên tử nhờ hiểu biết về loại công pháp này mà nhận ra Khúc Hồn là Thân Ngoại Hóa Thân của Hàn Lập.","congNang":["Tế luyện phân thân"],"dacDiem":"Hao phí rất lớn, xác suất thành công thấp, ít người tu luyện.","tabs":{"tienTrinh":[{"chuong":"@c0410","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Tử Linh tiên tử nhắc đến","text":"Tử Linh tiên tử cho biết Diệu Âm Môn có công pháp tế luyện phân thân nhưng hao phí lớn, xác suất thấp, ít người tu. Nhờ đó nhận ra Khúc Hồn là phân thân Hàn Lập.","anchor":"bổn môn cũng có một loại công pháp có thể tế luyện phân thân"}]},"nguon":["@c0410"]},{"id":"van-tieu-tam-dac","name":"Vân Tiêu Tâm Đắc","cn":"云霄心得","loai":"khac","loaiLabel":"Sách luyện khí","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Quyển sách chuyên sâu về luyện khí, Hàn Lập phục chế từ ngọc giản và nghiên cứu kỹ lưỡng để tự học luyện chế pháp khí.","detail":"Sách tri thức luyện khí mà Hàn Lập nghiên cứu suốt ngày tại Thanh Trúc Tiểu Hiên, được phục chế từ ngọc giản. Là tài liệu chính giúp hắn tự học luyện khí từ con số không, phục vụ cho mục tiêu luyện chế Thanh Trúc Phong Vân Kiếm.","congNang":["Cung cấp tri thức luyện khí chuyên sâu"],"nguon":["@c0412"],"tabs":{"tienTrinh":[{"chuong":"@c0412","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập bắt đầu nghiên cứu","text":"Hàn Lập cầm đọc suốt ngày trong Thanh Trúc Tiểu Hiên, đi sâu nghiên cứu để tự học luyện khí.","anchor":"đi sâu nghiên cuốn \"Vân Tiêu Tâm Đắc\""}]}},{"id":"dien-tich-tran-phap-tan-nhu-am","name":"Điển tịch trận pháp (Tân Như Âm tặng)","cn":"","loai":"khac","loaiLabel":"Sách trận pháp","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Sách trận pháp mà Tân Như Âm tặng Hàn Lập, hắn dùng để tự học trận pháp song song với luyện khí.","detail":"Điển tịch trận pháp do Tân Như Âm tặng cho Hàn Lập, cung cấp kiến thức nền tảng về trận pháp. Hàn Lập nghiên cứu để học cách luyện chế trận kỳ và trận bàn, phục vụ cho pháp trận đặc thù tế luyện phi kiếm thành bộ Thanh Trúc Phong Vân Kiếm.","congNang":["Cung cấp tri thức trận pháp cơ bản và nâng cao"],"nguon":["@c0412"],"tabs":{"tienTrinh":[{"chuong":"@c0412","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập bắt đầu nghiên cứu","text":"Hàn Lập nghiên cứu song song với Vân Tiêu Tâm Đắc, mục tiêu tự luyện chế trận kỳ và trận bàn đơn giản nhất.","anchor":"điển tịch trận pháp mà Tân Như Âm đã tặng"}]}},{"id":"thanh-nguyen-kiem-quyet","name":"Thanh Nguyên kiếm quyết","cn":"青元劍訣","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Quyển sách công pháp chứa phương pháp luyện chế Thanh trúc phong vân kiếm, bao gồm đồ hình pháp trận cỡ nhỏ khắc lên từng thanh phi kiếm.","detail":"Quyển sách công pháp kiếm quyết, chứa đồ hình pháp trận cỡ nhỏ dùng khắc lên phi kiếm trong quá trình luyện chế Thanh trúc phong vân kiếm. Hàn Lập dựa theo đồ hình y nguyên trong sách để khắc lên từng thanh, dù bản thân không lý giải được nguyên lý pháp trận bên trong.","thuocTinh":"Không rõ","nguonGoc":"Không rõ","dacDiem":"Chứa đồ hình pháp trận cỡ nhỏ mà người tu luyện không lý giải được nguyên lý","congNang":["Chứa phương pháp luyện chế Thanh trúc phong vân kiếm","Đồ hình pháp trận nhỏ dùng khắc lên từng thanh phi kiếm","Hộ thể kiếm thuẫn: dùng kiếm khí trong cơ thể trải rộng phòng hộ, không cần phóng pháp bảo ra ngoài"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0414","tangDatToi":"Tầng 8 (đang tu tầng 9)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0414","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu tiết lộ tên sách","text":"Tên sách công pháp Thanh Nguyên kiếm quyết lần đầu được nhắc đến khi Hàn Lập khắc pháp trận nhỏ lên 72 phi kiếm theo đồ hình trong sách.","anchor":"giống đúc như đồ hình trong quyển sách công pháp “Thanh Nguyên kiếm quyết”"},{"chuong":"@c0438","loai":"thi triển","importance":"normal","giaiDoan":"Hộ thể kiếm thuẫn lần đầu sử dụng","text":"Hàn Lập triển khai thần thông hộ thể kiếm thuẫn mới tham ngộ, dùng kiếm khí Thanh Trúc Phong Vân Kiếm trải rộng phòng hộ trong quỷ vụ, cố ý giữ điện quang màu trắng để che giấu Kim Lôi Trúc.","anchor":"Thanh Nguyên Kiếm Quyết hộ thể kiếm thuẫn thần thông mới không cần pháp bảo thả ra"},{"chuong":"@c0527","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hàn Lập tu thành tầng 8, đột phá Kết Đan trung kỳ","text":"Hàn Lập sau 15-16 năm bế quan phá tan chướng ngại Kết Đan trung kỳ, tu thành tầng thứ tám. Đan dược còn thừa, tiếp tục tu luyện tầng thứ chín.","anchor":"tu thành tầng thứ tám của Thanh Nguyên Kiếm Quyết"}]},"dinhDanh":"goc","nguon":["@c0414","@c0438","@c0527"]},{"id":"phap-tran-luyen-che-thanh-truc","name":"Pháp trận luyện chế Thanh trúc phong vân kiếm","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Pháp trận cực kỳ phức tạp bố trí trong mật thất, là mấu chốt luyện chế Thanh trúc phong vân kiếm, phát ra 72 cột sáng khống chế lục dịch.","detail":"Pháp trận mấu chốt trong việc luyện chế Thanh trúc phong vân kiếm, được đề cập ba lần bảy lượt trong tài liệu. Hàn Lập mất nửa tháng bố trí cẩn thận trong mật thất, dùng hơn mười khối linh thạch bậc trung thử nghiệm xác nhận vận hành bình thường. Khi kích hoạt, linh thạch khảm trên trận phát sáng chói mắt, bắn ra 72 cột sáng to như cái bát bao phủ từng khối lục dịch, kết hợp thần thức biến đổi màu sắc thành hỏa hồng.","congNang":["Cố định và biến đổi lục dịch Thiên Lôi trúc trong quá trình luyện kiếm","Phát ra 72 cột sáng to như cái bát bao phủ lục dịch"],"tabs":{"tienTrinh":[{"chuong":"@c0414","loai":"xuất hiện","importance":"major","giaiDoan":"Bố trí và kích hoạt lần đầu","text":"Hàn Lập mất nửa tháng bố trí pháp trận trong mật thất, dùng hơn mười linh thạch bậc trung thử nghiệm, rồi kích hoạt tạo 72 hỏa trụ cao hơn hai trượng để luyện chế phi kiếm.","anchor":"Chỉ biết pháp trận này là mấu chốt trong việc luyện chế “Thanh trúc phong vân kiếm”, được đề cập ba lần bảy lượt"}]},"dinhDanh":"goc","nguon":["@c0414"]},{"id":"khong-than-phap-tran","name":"Khống thần pháp trận","loai":"bi-thuat","loaiLabel":"Trận pháp","soHuu":["Hàn Lập"],"blurb":"Trận pháp lớn khắc trên nền đất, dùng tinh huyết để tiến hành nghi thức nhận chủ linh trùng từ trứng.","detail":"Hàn Lập khắc họa trận pháp này trên nền trùng thất mới, nhỏ một lượng lớn tinh huyết vào bên trong, dùng để cho Phệ Kim Trùng mới nở nhận chủ thành công.","congNang":["Nhận chủ linh trùng từ trứng, cần tinh huyết kích hoạt, khắc trên nền đất","Lấy máu nhận chú trứng linh trùng để khống chế sau khi nở"],"tabs":{"tienTrinh":[{"chuong":"@c0415","loai":"thi triển","importance":"normal","giaiDoan":"Sử dụng lần đầu","text":"Hàn Lập khắc họa Khống thần pháp trận trên nền trùng thất mới, nhỏ tinh huyết, tiến hành nghi thức nhận chủ Phệ Kim Trùng từ trứng thành công.","anchor":"trên nền đất trong căn trùng thất mới này khắc họa một cái Khống thần pháp trận thật lớn, nhỏ vào bên trong một lượng lớn tinh huyết"},{"chuong":"@c0520","loai":"thi triển","importance":"normal","giaiDoan":"Nhận chú trứng Phệ Kim Trùng biến dị","text":"Hàn Lập họa ra Khống Thần pháp trận để lấy máu nhận chú toàn bộ trứng Phệ Kim Trùng mới đẻ có dấu hiệu biến dị.","anchor":"kềm chế nỗi chờ mong trong lòng mà họa ra Khống Thần pháp trận, đem toàn bộ chỗ trứng này tiến hành lấy máu nhận chú"}]},"nguon":["@c0415","@c0520"],"cn":"控神法阵","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0520","tangDatToi":"","trangThai":"dang-dung"}]},{"id":"dai-tran-phong-an-co-tu-si","name":"Đại trận phong ấn cổ tu sĩ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Cổ tu sĩ","soHuu":[],"blurb":"Trận pháp do cổ tu sĩ thiết lập bao phủ sườn núi đất trên đảo hoang, phong ấn di chỉ bên trong. Cực kỳ phức tạp, cần nhiều người phối hợp và ít nhất một hai tháng thăm dò mới có thể phá giải.","detail":"Đại trận phong ấn nằm trên sườn tòa núi đất cao ngàn trượng trên đảo hoang Loạn Tinh Hải. Bên trong nghi là di chỉ cổ tu sĩ chứa tài liệu hoặc pháp bảo. Kim Thanh tổ chức nhóm sáu tu sĩ (gồm cao thủ trận pháp Thạch Điệp) để thăm dò và phá giải.","congNang":["Phong ấn di chỉ cổ tu sĩ trên sườn núi đất"],"tabs":{"tienTrinh":[{"chuong":"@c0416","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện đại trận","text":"Nhóm Kim Thanh và Hàn Lập đến chân núi đất trên đảo hoang, xác nhận đại trận phong ấn do cổ tu sĩ thiết lập bao phủ sườn núi. Cần ít nhất một hai tháng thăm dò nghiên cứu mới có thể phá giải.","anchor":"đại trận do cổ tu sĩ thiết lập nếu không có một hai tháng thăm dò nghiên cứu thì sao có thể dễ dàng phá giải"}]},"nguon":["@c0416"]},{"id":"bac-dau-luong-nghi-tran","name":"Bắc Đẩu Lưỡng Nghi Trận","cn":"北斗两仪阵","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Trận đạo","soHuu":["Hàn Lập"],"blurb":"Trận pháp dùng mười cây trận kỳ bố trí theo thế Bắc Đẩu, hợp cột sáng xạ xuống phá trận pháp đối phương. Phương thức dĩ trận phá trận lấy từ cuốn tâm đắc của Tân Như Âm.","detail":"Hàn Lập lấy mười cây trận kỳ nhiều màu bố trí trên không theo thế Bắc Đẩu Lưỡng Nghi, mười cột sáng hợp nhất thành một cột lớn xạ xuống hoàng vụ bao phủ đại trận cổ đại. Ban đầu không có phản ứng, nhưng ngay sau đó hoàng vụ sôi trào, chấn động có quy luật rồi phình lên, cuối cùng nổ tung tán loạn — phá thành công tầng huyễn trận che mắt ngoài cùng. Phương pháp này có trong cuốn tâm đắc trận pháp mà Tân Như Âm tặng Hàn Lập.","thuocTinh":"Không rõ","nguonGoc":"Cuốn tâm đắc trận pháp của Tân Như Âm","congNang":["Dùng trận kỳ lập trận để phá trận pháp đối phương — dĩ trận phá trận"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0417","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0417","loai":"thi triển","importance":"major","giaiDoan":"Thi triển lần đầu","text":"Hàn Lập lần đầu sử dụng Bắc Đẩu Lưỡng Nghi Trận với mười cây trận kỳ, phá thành công tầng huyễn trận ngoài cùng của đại trận cổ đại song thuộc tính Thổ–Phong.","anchor":"dùng trận kỳ của bộ \"Bắc đẩu lưỡng nghi trận\" để phá giải"}]},"nguon":["@c0417"]},{"id":"dai-tran-co-dai-tho-phong","name":"Đại trận cổ đại song thuộc tính Thổ–Phong","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Đại trận cổ đại bao phủ sườn núi bằng hoàng vụ dày đặc, mang song thuộc tính Thổ–Phong, có nhiều tầng và miễn nhiễm ngoại lực cường công.","detail":"Trận pháp tồn tại trên sườn núi, tầng ngoài là huyễn trận che mắt tạo hoàng vụ nồng đậm. Hồ Nguyệt cùng Kim Thanh từng công kích một ngày đêm bằng ngoại lực mà không phá nổi. Thạch Điệp nhận ra đây là trận song thuộc tính Thổ–Phong. Hàn Lập dùng Bắc Đẩu Lưỡng Nghi Trận phá tầng huyễn trận ngoài, lộ ra tầng hào quang vàng nhạt bao phủ hơn trăm trượng — đại trận thực sự bên trong.","dacDiem":"Song thuộc tính Phong–Thổ, miễn nhiễm ngoại lực cường công, nhiều tầng","tabs":{"tienTrinh":[{"chuong":"@c0417","loai":"xuất hiện","importance":"major","giaiDoan":"Tầng ngoài bị phá","text":"Thạch Điệp thử nhiều pháp khí đều thất bại. Hàn Lập dùng Bắc Đẩu Lưỡng Nghi Trận phá tầng huyễn trận ngoài cùng, lộ ra tầng hào quang vàng nhạt phạm vi hơn trăm trượng bên trong.","anchor":"trận pháp song thuộc tính thổ, phong, thật sự có chút ý tứ"}]},"nguon":["@c0417"]},{"id":"thach-hoa-thuat","name":"Thạch Hóa thuật","cn":"石化术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Thuật pháp biến bùn đất thành đá, dùng để tạo thạch ốc tạm thời.","detail":"Nhóm Hàn Lập dùng Thạch Hóa thuật xây thạch ốc từ bùn đất rồi biến thành phòng đá để ở tạm trong thời gian phá đại trận cổ tại cổ tu sĩ di chỉ.","congNang":["Biến bùn đất thành đá cứng"],"nguon":["@c0418"]},{"id":"dai-tran-co-bao-ve-cot-da","name":"Đại trận cổ bảo vệ cột đá","cn":"","loai":"khac","loaiLabel":"Trận pháp cổ","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Trận pháp cổ nhiều tầng cấm chế bao quanh cột đá khắc cổ văn, có tà khí, tầng cuối tạo Tam dương chi địa sinh yêu linh Sí Ác vĩnh sinh.","detail":"Đại trận bao quanh cột đá hình trụ cao mấy trượng có khắc cổ văn ở trung tâm cổ tu sĩ di chỉ. Màn sáng vàng đục, thần thức bị bắn ngược khi tiếp xúc, bên trong có hào quang bảy màu chuyển động quỷ dị. Khí tức trận pháp có vài phần tà khí, không giống trận pháp cổ thông thường. Sau ba tháng bị Hàn Lập và Thạch Điệp phá gần hết, màn sáng thu nhỏ non nửa, đổi từ vàng tối sang đỏ như lửa. Đạo cấm chế cuối cùng biến nơi này thành Tam dương chi địa, khiến yêu linh Sí Ác vĩnh sinh bất diệt bên trong.","congNang":["Bảo vệ cột đá cổ văn bằng nhiều tầng cấm chế","Thần thức bị bắn ngược khi chạm màn sáng","Tầng cuối tạo Tam dương chi địa sinh Sí Ác vĩnh sinh"],"tabs":{"tienTrinh":[{"chuong":"@c0418","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị phá gần hết sau ba tháng","text":"Nhóm Hàn Lập phát hiện đại trận bảo vệ cột đá cổ văn. Hàn Lập và Thạch Điệp phối hợp phá trận suốt ba tháng, phá gần hết chỉ còn cấm chế cuối cùng với yêu linh Sí Ác. Hàn Lập bố trận kỳ và trận bàn Thủy thuộc tính chuẩn bị phá cấm chế cuối.","anchor":"hình dáng cũng như khí tức của trận pháp trước mặt này tựa hồ không giống các loại loại trận pháp cổ khác"}]},"nguon":["@c0418"]},{"id":"quy-dau-thuat-quai-nhan","name":"Quỷ đầu thuật (quái nhân đảo chủ)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Tà đạo","soHuu":["Quái nhân đảo chủ"],"blurb":"Tà thuật cổ quái: niệm chú kích hoạt hai đầu lâu đen gắn trên ngực, đầu lâu cắn đứt ngón tay chủ nhân rồi tự chủ bay ra nghênh chiến.","detail":"Quái nhân đảo chủ niệm chú kích hoạt hai đầu lâu đen gắn cố định trên ngực, chúng chuyển động như vật sống, cắn đứt hai ngón tay chủ nhân để hấp thu máu thịt rồi bay ra tự chủ chiến đấu, nghênh đón lôi hỏa và hắc kỳ đối phương.","nguon":["@c0419"]},{"id":"bich-uyen-quy-hoa","name":"Bích Uyên Quỷ Hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Mạnh hơn đan hỏa ba phần","hePhai":"Ma đạo / Tà thuật","soHuu":["Quái nhân đảo chủ"],"blurb":"Lân hỏa xanh biếc do quỷ đầu (khô lâu biến hình) phun ra, uy lực mạnh hơn đan hỏa ba phần nhưng hoàn toàn vô hiệu trước Phệ Kim Trùng.","detail":"Quỷ đầu sau khi nâng cấp bằng ngón tay chủ nhân sẽ phun Bích Uyên Quỷ Hỏa — loại lân hỏa xanh biếc có sức công kích diện rộng. Đánh bật được Phệ Kim Trùng nhưng không gây tổn thương cho chúng, giáp trùng chỉ lăn lộn rồi bay lên bình thường.","congNang":["Phun lửa quỷ tấn công diện rộng","Uy lực mạnh hơn đan hỏa ba phần"],"nguon":["@c0420"],"tabs":{"tienTrinh":[{"chuong":"@c0420","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Quỷ đầu (khô lâu biến hình sau khi nuốt ngón tay quái nhân) phun Bích Uyên Quỷ Hỏa đánh bật Phệ Kim Trùng nhưng không gây tổn thương.","anchor":"Bích Uyên Quỉ Hỏa so với đan hỏa còn ghê gớm hơn ba phần"}]}},{"id":"kiem-quang-phan-than","name":"Kỹ thuật kiếm quang phân thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Pháp quyết biến hai thanh phi kiếm thành bốn đạo kiếm quang thật giả khó phân, phân công tấn công nhiều mục tiêu cùng lúc.","detail":"Hàn Lập dùng pháp quyết khiến hai thanh phi kiếm xanh biếc lục quang lóe lên, phân thành bốn đạo kiếm quang thật giả lẫn lộn. Hai đạo đánh quỷ đầu, hai đạo lặng lẽ vọt tới sau lưng quái nhân ám sát.","congNang":["Phân thân phi kiếm thành kiếm quang thật giả lẫn lộn, tấn công nhiều mục tiêu đồng thời"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0421","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0421","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu sử dụng","text":"Hàn Lập dùng pháp quyết biến hai thanh phi kiếm thành bốn đạo kiếm quang thật giả phối hợp tiêu diệt quái nhân.","anchor":"lục quang của hai thanh phi kiếm lóe lên, đột nhiên biến thành bốn đạo kiếm quang thật giả khó phân"}]},"nguon":["@c0421"]},{"id":"than-thong-doi-pho-quy-ma-gian","name":"Thần thông đối phó quỷ ma (công pháp tu sĩ họ Giản)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Giản huynh"],"blurb":"Thần thông chuyên môn đối phó quỷ ma, nằm trong công pháp tu luyện của tu sĩ họ Giản, cần thời gian chuẩn bị trước mới sử dụng được.","detail":"Tu sĩ họ Giản tiết lộ công pháp hắn tu luyện có một loại thần thông chuyên môn đối phó quỷ ma. Tuy nhiên loại thần thông này cần có thời gian chuẩn bị trước mới phát huy được, giải thích vì sao khi bất ngờ đấu với yêu nhân trước đó hắn bị chật vật.","thuocTinh":"Không rõ","dacDiem":"Cần thời gian chuẩn bị trước mới sử dụng được","congNang":["Chuyên đối phó quỷ ma"],"nguoiTu":[{"ten":"Giản huynh","tuChuong":"@c0422","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0422","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Tiết lộ sự tồn tại","text":"Tu sĩ họ Giản tiết lộ công pháp tu luyện có thần thông chuyên đối phó quỷ ma, cần thời gian chuẩn bị trước.","anchor":"công pháp mà tại hạ tu luyện chính xác có một loại thần thông chuyên môn đối phó quỷ ma"}]},"nguon":["@c0422"]},{"id":"ich-ta-than-loi","name":"Ích Tà Thần Lôi","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần lôi đặc thù gắn liền với Thanh Trúc Phong Vân Kiếm, có thể phóng ra khi sử dụng kiếm. Hàn Lập cố ý giấu kín để không lộ bí mật kiếm luyện từ Thiên Lôi Trúc.","detail":"Ích Tà Thần Lôi là thần lôi có thể phóng ra qua Thanh Trúc Phong Vân Kiếm. Hàn Lập cố tình không kích hoạt nó trước mặt đồng hành để đề phòng người khác nhận ra thanh kiếm do Thiên Lôi Trúc luyện chế thành.","congNang":["Phóng thần lôi qua phi kiếm Thanh Trúc Phong Vân Kiếm"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0424","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0424","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị giấu kỹ","text":"Hàn Lập cố ý không phóng Ích Tà Thần Lôi khi dùng Thanh Trúc Phong Vân Kiếm chiến đấu với Yêu Quan Xà, để đề phòng bị lộ kiếm do Thiên Lôi Trúc luyện chế.","anchor":"không phóng ra Ích Tà Thần Lôi đề phòng người khác nhận ra thanh kiếm đó là do Thiên Lôi Trúc luyện chế thành"}]},"nguon":["@c0424"]},{"id":"khu-linh-thuat","name":"Khu Linh Thuật","cn":"驅靈術","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Thuật pháp khu sử linh vật/linh điểu chiến đấu, đã thất truyền từ lâu tại Loạn Tinh Hải. Hàn Lập sử dụng qua bức họa đỏ rực phóng Chi Dương Điểu chống quỷ vụ.","detail":"Khu Linh Thuật cho phép khu sử linh vật hoặc linh điểu thông qua pháp bảo chứa tinh hồn. Đã thất truyền từ lâu tại Loạn Tinh Hải, quái ảnh xanh biếc nhận ra thuật này và tỏ vẻ kinh ngạc. Hàn Lập dùng bức họa đỏ rực (Khu Linh đồ) phóng ra Chi Dương Điểu — loài chim sinh trong tinh hỏa, khắc tinh âm vật, đã tuyệt chủng — để chống lại quỷ vụ trong đại sảnh.","thuocTinh":"Không rõ","nguonGoc":"Thất truyền tại Loạn Tinh Hải","dacDiem":"Khu sử linh vật/linh điểu qua pháp bảo chứa tinh hồn","congNang":["Khu sử linh vật, linh điểu chiến đấu thông qua pháp bảo phong ấn tinh hồn"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0425","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0425","loai":"thi triển","importance":"major","giaiDoan":"Lộ diện","text":"Hàn Lập dùng bức họa đỏ rực phóng Chi Dương Điểu chống quỷ vụ trong đại sảnh. Quái ảnh xanh biếc nhận ra đây là Khu Linh Thuật thất truyền, kinh ngạc.","anchor":"Khu Linh Thuật đã thất truyền từ lâu, xem ra bổn tọa thật sự quá xem nhẹ các ngươi rồi"}]},"capNhatToi":"@c0425","nguon":["@c0425"]},{"id":"huyen-hon-luyen-yeu","name":"Huyền Hồn Luyện Yêu","cn":"玄魂炼妖","aliases":["Huyền Hồn luyện yêu đại pháp","Huyền Hồn đại pháp"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Yêu cầu Nguyên Anh kỳ","hePhai":"Ma đạo","soHuu":["Quái vật thánh tổ (phụ thân Khúc Hồn)"],"blurb":"Công pháp cấp Nguyên Anh kỳ do quái vật thánh tổ tu luyện, cho phép dùng Huyền hồn phụ thân tùy ý mà hầu như không bị hạn chế.","detail":"Chỉ tu sĩ Nguyên Anh kỳ mới có tư cách tu luyện. Cho phép người tu tùy ý phụ thân (đoạt xá) mà không bị ràng buộc hạn chế thông thường. Quái vật tự xưng thánh tổ đã đại thành công pháp này, nhờ đó chiếm đoạt thân xác Khúc Hồn hoàn toàn.","thuocTinh":"Phụ thân / đoạt xá","nguonGoc":"Do quái vật thánh tổ (sư phụ gốc của Cực Âm, Cực Huyễn) tu luyện","yeuCau":"Nguyên Anh kỳ","uyLuc":"Phụ thân tùy ý, không bị hạn chế khi đoạt xá","dacDiem":"Vượt trội các thuật phụ thân thông thường về mức độ tự do","congNang":["Phụ thân/đoạt xá tùy ý, hầu như không bị hạn chế"],"nguoiTu":[{"ten":"Quái vật thánh tổ","tuChuong":"@c0427","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0427","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu tiết lộ","text":"Quái vật thánh tổ tự tiết lộ công pháp Huyền Hồn Luyện Yêu khi giải thích lý do có thể phụ thân Khúc Hồn tùy ý mà không bị hạn chế. Tuyên bố chỉ tu sĩ Nguyên Anh kỳ mới đủ tư cách tu luyện.","anchor":"Chỉ có tu sĩ Nguyên Anh kỳ mới có tư cách tu luyện"}]},"nguon":["@c0427"]},{"id":"huyen-hon-ngung-cot-thuat","name":"Huyền Hồn Ngưng Cốt thuật","cn":"玄魂凝骨术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Ma đạo","soHuu":["Quái vật thánh tổ (phụ thân Khúc Hồn)"],"blurb":"Thuật dung hợp bạch cốt vào thân xác bị phụ thân, biến đổi hình dạng hoàn toàn.","detail":"Do quái vật thánh tổ thi triển. Triệu hồi bộ bạch cốt dung nhập vào thân xác Khúc Hồn đã bị phụ thân, khiến thân thể co lại biến hình thành thanh niên mi thanh mục tú, tu vi vượt Kết Đan sơ kỳ. Được quái vật tuyên bố đã luyện thành.","congNang":["Dung hợp cốt vào thân xác bị phụ thân, biến đổi hình dạng và nâng tu vi"],"nguoiTu":[{"ten":"Quái vật thánh tổ","tuChuong":"@c0427","tangDatToi":"Luyện thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0427","loai":"thi triển","importance":"major","giaiDoan":"Luyện thành và thi triển","text":"Quái vật triệu hồi bạch cốt dung nhập vào thân Khúc Hồn, thi triển Huyền Hồn Ngưng Cốt thuật biến đổi hình dạng thành thanh niên mi thanh mục tú.","anchor":"Huyền Hồn Ngưng Cốt thuật của ta đã luyện thành"}]},"nguon":["@c0427"]},{"id":"phan-than-thuat","name":"Phân Thân thuật","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Cực Âm lão tổ","Cực Huyễn"],"blurb":"Thuật luyện chế phân thân, do quái vật thánh tổ truyền dạy cho Cực Âm và Cực Huyễn.","detail":"Cùng Sát Đan được quái vật thánh tổ truyền dạy cho hai đệ tử phản đồ (Cực Âm, Cực Huyễn). Phân thân luyện bằng thuật này có thể bị người sáng tạo khống chế dễ dàng mà không tốn sức.","congNang":["Luyện chế phân thân"],"dacDiem":"Người sáng tạo gốc có thể khống chế phân thân không tốn sức","nguoiTu":[{"ten":"Cực Âm lão tổ","tuChuong":"@c0427","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Cực Huyễn","tuChuong":"@c0427","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0427","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Tiết lộ nguồn gốc","text":"Quái vật thánh tổ tiết lộ Phân Thân thuật do chính hắn truyền dạy cho Cực Âm và Cực Huyễn, người sáng tạo có thể khống chế phân thân không tốn sức.","anchor":"Phân Thân thuật là do lúc đầu ta truyền dạy cho hai tên phản đồ"}]},"nguon":["@c0427"]},{"id":"huyen-hon-dai-phap","name":"Huyền Hồn đại pháp","cn":"玄魂大法","aliases":["Huyền Hồn luyện yêu đại pháp","Huyền Hồn Luyện Yêu"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Tiêu Sá"],"blurb":"Pháp môn ma đạo cho phép tán Nguyên Anh hóa thành Huyền hồn thân thể, đột phá giới hạn tuổi thọ, sống thêm hàng trăm năm.","detail":"Tiêu Sá tu luyện pháp môn này sau khi đã sống hơn sáu trăm năm, tán hết Nguyên Anh chuyển sang hóa Huyền hồn thân thể, tồn tại thêm bốn năm trăm năm. Hàn Lập nghi ngờ pháp môn có khuyết điểm: không thể hành tẩu ban ngày, bị pháp khí đặc thù khắc chế. Tiêu Sá giận dữ từ chối xác nhận.","thuocTinh":"Ma đạo, hồn thể","nguonGoc":"Không rõ","yeuCau":"Tán Nguyên Anh","uyLuc":"Đột phá giới hạn tuổi thọ, cho phép tồn tại dưới dạng Huyền hồn thân thể hàng trăm năm","dacDiem":"Nghi không thể hành tẩu ban ngày, bị pháp khí đặc thù khắc chế","congNang":["Tán Nguyên Anh hóa Huyền hồn thân thể, vượt hạn chế tuổi thọ @c0428"],"nguoiTu":[{"ten":"Tiêu Sá","tuChuong":"@c0428","tangDatToi":"Đã thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0428","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ diện qua lời Tiêu Sá","text":"Tiêu Sá tiết lộ đã tán Nguyên Anh tu luyện Huyền Hồn đại pháp, hóa Huyền hồn thân thể sống thêm bốn năm trăm năm. Hàn Lập nổi hứng thú vì pháp môn có thể đột phá hạn chế tuổi thọ.","anchor":"Ta tán hết Nguyên Anh, chuyển qua tu luyện nó nếu không với chính thân thể đó có lẽ ta đã sớm toạ hoá rồi"}]},"capNhatToi":"@c0428","nguon":["@c0428"]},{"id":"huyen-am-kinh","name":"Huyền Âm Kinh","cn":"玄阴经","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Công pháp được Tiêu Sá nhắc tới khi xác nhận công pháp Hàn Lập tu luyện không phải Huyền Âm Kinh.","detail":"Tiêu Sá dùng huyết quang đọc ngọc giản xong, xác nhận công pháp Hàn Lập không phải Huyền Âm Kinh, cũng không phải ma đạo.","nguon":["@c0428"]},{"id":"thac-thien-quyet","name":"Thác Thiên quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Man Hồ Tử"],"blurb":"Ma công phòng ngự đệ nhất Loạn Tinh hải, do Man Hồ Tử tu luyện.","detail":"Công pháp được xưng là ma công phòng ngự đệ nhất Loạn Tinh hải. Vạn Thiên Minh cũng ngưỡng mộ đã lâu. Thuộc hệ ma đạo, chuyên về phòng ngự.","thuocTinh":"Phòng ngự","uyLuc":"Đệ nhất phòng ngự Loạn Tinh hải","dacDiem":"Ma công chuyên về phòng ngự","congNang":["Phòng ngự đệ nhất Loạn Tinh hải"],"nguoiTu":[{"ten":"Man Hồ Tử","tuChuong":"@c0434","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0434","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu được nhắc tới","text":"Được giới thiệu là ma công phòng ngự đệ nhất Loạn Tinh hải khi Man Hồ Tử xuất hiện. Vạn Thiên Minh nói ngưỡng mộ đã lâu.","anchor":"Tại hạ cũng ngưỡng mộ Thác Thiên quyết được xưng là ma công phòng ngự đệ nhất Loạn Tinh hải của Man huynh"}]},"nguon":["@c0434"]},{"id":"thien-la-chan-cong","name":"Thiên La chân công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Chính đạo","soHuu":["Vạn Thiên Minh"],"blurb":"Công pháp của Vạn Thiên Minh, môn chủ Vạn Pháp môn, được Man Hồ Tử ngưỡng mộ.","detail":"Công pháp tu luyện chính của Vạn Thiên Minh. Man Hồ Tử nói ngưỡng mộ đã lâu.","nguoiTu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0434","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0434","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu được nhắc tới","text":"Được nhắc tới khi Man Hồ Tử khiêu khích Vạn Thiên Minh, nói ngưỡng mộ Thiên La chân công đã lâu.","anchor":"Thiên La chân công của Vạn môn chủ tại hạ cũng ngưỡng mộ đã lâu"}]},"nguon":["@c0434"]},{"id":"loan-phuong-kiem-quyet","name":"Loan Phượng kiếm quyết","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"","soHuu":["Ôn phu nhân"],"blurb":"Kiếm pháp của Ôn phu nhân, đe dọa dùng để luận bàn với Vạn Thiên Minh.","detail":"Công pháp kiếm thuật của mỹ phụ họ Ôn, đe dọa dùng để luận bàn với Vạn Thiên Minh về việc đệ tử đả thương tì nữ.","nguoiTu":[{"ten":"Ôn phu nhân","tuChuong":"@c0434","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0434","loai":"nhac-toi","importance":"bridge","giaiDoan":"Được nhắc trong lời đe dọa","text":"Ôn phu nhân đe dọa dùng Loan Phượng kiếm quyết luận bàn với Vạn Thiên Minh.","anchor":"ta cũng muốn dùng Loan Phượng kiếm quyết luận bàn với Vạn tông chủ một phen"}]},"nguon":["@c0434"]},{"id":"bang-he-cong-phap","name":"Băng hệ công pháp","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Băng","soHuu":["Ngọc chân nhân"],"blurb":"Công pháp Ngọc chân nhân tu luyện, phù hợp dị linh căn thuộc tính hiếm của hắn.","detail":"Công pháp băng hệ mà Ngọc chân nhân tu luyện, phù hợp dị linh căn thuộc tính hiếm. Cát Lạp tự nhận pháp lực không bằng Ngọc chân nhân dù cùng Kết Đan sơ kỳ.","nguoiTu":[{"ten":"Ngọc chân nhân","tuChuong":"@c0438","tangDatToi":"","trangThai":"da-chet"}],"nguon":["@c0438"]},{"id":"cau-hon-quy-am","name":"Câu hồn quỷ âm","cn":"","loai":"bi-thuat","loaiLabel":"Quỷ dị pháp thuật","phamCap":"Cao giai","hePhai":"Quỷ đạo","soHuu":[],"blurb":"Cao giai quỷ dị pháp thuật tấn công tinh thần, khiến đối thủ tu vi thấp hơn bị nghịch chuyển máu huyết, nhảy múa gào thét điên cuồng đến chết.","detail":"Khi thi triển, âm thanh quỷ dị mê hoặc tinh thần đối phương, đối với địch nhân tu vi thấp hơn sẽ làm nghịch chuyển máu huyết, nhảy múa gào thét điên cuồng không ngừng cho đến chết. Tử Linh tiên tử suýt bị mê hoặc bởi pháp thuật này, được Hàn Lập cứu thoát kịp thời.","congNang":["Tấn công tinh thần, khiến địch nghịch chuyển máu huyết gào thét đến chết"],"tabs":{"tienTrinh":[{"chuong":"@c0440","loai":"thi triển","importance":"normal","giaiDoan":"Quỷ ảnh sử dụng tấn công Tử Linh","text":"Quỷ ảnh sử dụng Câu hồn quỷ âm tấn công tinh thần Tử Linh tiên tử, suýt mê hoặc nàng tiến về phía tiếng gào thét trước khi Hàn Lập can thiệp.","anchor":"công pháp này chính là cao giai quỷ dị pháp thuật, khi thi triển ra đối với địch nhân có tu vi thấp hơn sẽ làm cho đối thủ bị nghịch chuyển máu huyết"}]},"nguon":["@c0440"]},{"id":"khi-linh","name":"Khí linh","cn":"器灵","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Kỹ thuật phong ấn nguyên thần tinh phách yêu thú hoặc quỷ quái vào pháp bảo, khi chiến đấu hóa thành hình dạng sống của khí linh cùng thần thông, tăng uy lực pháp bảo rất lớn.","detail":"Mỗi pháp bảo từ khi luyện chế thành chỉ có MỘT cơ hội phong ấn nguyên thần tinh phách yêu thú hay quỷ quái vào bên trong. Khi đối địch, khí linh hóa thành hình dạng sống kèm thần thông vốn có, uy lực cực lớn. Nguyên thần càng mạnh, tỉ lệ phong ấn thành công càng thấp; thất bại thì không có lần hai. Nam Cung Uyển từng thu nguyên thần Mặc giao tại Huyết sắc cấm địa chính là để phong ấn khí linh.","thuocTinh":"","nguonGoc":"","yeuCau":"Pháp bảo chưa từng phong ấn khí linh, cần nguyên thần tinh phách yêu thú/quỷ quái","uyLuc":"Hóa hình thực thể kèm thần thông nguyên bản của yêu thú/quỷ quái, tăng uy lực pháp bảo rất lớn","dacDiem":"Mỗi pháp bảo chỉ 1 cơ hội, tỉ lệ thành công nghịch với sức mạnh nguyên thần","congNang":["Phong ấn nguyên thần tinh phách yêu thú/quỷ quái vào pháp bảo","Khi chiến đấu hóa thành hình dạng sống kèm thần thông nguyên bản"],"trangThai":"dang-dung","capNhatToi":"@c0441","tabs":{"tienTrinh":[{"chuong":"@c0441","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lần đầu giải thích toàn diện cơ chế","text":"Quỷ ảnh đen kích hoạt quỷ châu biến thành yêu hổ đen khí linh khổng lồ. Tác giả giải thích cơ chế phong ấn khí linh: mỗi pháp bảo chỉ 1 cơ hội, tỉ lệ thành công nghịch sức mạnh nguyên thần. Hàn Lập hồi tưởng Nam Cung Uyển thu nguyên thần Mặc giao để phong ấn, bản thân chưa tìm được linh giao phù hợp.","anchor":"mỗi kiện pháp bảo từ khi luyện chế thành đều có một cơ hội đem nguyên thần tinh phách của yêu thú quỷ quái phong ấn vào trong"}]},"nguon":["@c0441"]},{"id":"phu-linh-thuat","name":"Phụ Linh thuật","cn":"附靈術","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ (mật thuật cực kỳ hiếm)","hePhai":"Không rõ","soHuu":["Huyền Cốt thượng nhân"],"blurb":"Mật thuật cực kỳ hiếm cho phép tu sĩ hoặc yêu quỷ dung hợp với yêu thú trí tuệ thấp, tu vi sau dung hợp gấp nhiều lần tổng hai bên, đổi lại lập ước sinh tử và tuổi thọ tiêu hao kinh người.","detail":"Phụ Linh thuật khác Phụ Thân đại pháp — chỉ thi triển trên yêu thú trí tuệ thấp, sau khi nhập vào tu vi gấp nhiều lần tổng cộng. Đổi lại phải lập ước sinh tử (một chết cả hai tiêu biến), tuổi thọ tiêu hao kinh người, cuối cùng biến thành nửa người nửa quái rồi chết. Tương truyền hồn phách tu sĩ tu luyện thuật này sẽ vĩnh viễn rơi xuống vực sâu vô tận, không thể luân hồi. Bình thường chỉ tu tiên giả thi triển, nhưng quỷ ảnh đen (yêu quỷ) cũng tu luyện được và còn dùng trên khí linh của chính mình — điều Hàn Lập chưa từng nghe.","congNang":["Dung hợp tu sĩ/yêu quỷ với yêu thú trí tuệ thấp, tu vi cộng hưởng gấp bội @c0442"],"nguonGoc":"Mật thuật cực kỳ hiếm, rất ít người biết","dacDiem":"Ước sinh tử (một chết cả hai), thọ nguyên tiêu hao cực lớn, biến nửa người nửa yêu rồi chết, hồn phách không luân hồi","nguoiTu":[{"ten":"Huyền Cốt thượng nhân","tuChuong":"@c0442","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0442","loai":"thi triển","importance":"major","giaiDoan":"Quỷ ảnh đen dung hợp với yêu hổ hai đầu","text":"Quỷ ảnh đen biến thành quỷ vụ đen sì nhập vào yêu hổ hai đầu, thi triển Phụ Linh thuật tạo thân thể nửa người nửa hổ. Hàn Lập nhận diện mật thuật này và hồi tưởng đặc tính: ước sinh tử, tuổi thọ tiêu hao, hồn phách vĩnh viễn rơi vực sâu.","anchor":"Bộ dáng quỷ ảnh cùng cự hổ dung hợp trước mắt cùng với Phụ Linh thuật trong truyền thuyết giống nhau như đúc"}]},"nguon":["@c0442"]},{"id":"phu-than-dai-phap","name":"Phụ Thân đại pháp","cn":"附身大法","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Pháp thuật nhập vào thân thể sinh linh khác để thao túng từ xa, hiệu quả kém xa Phụ Linh thuật, không gia tăng thực lực mà chỉ phát huy vài phần sức.","detail":"Phụ Thân đại pháp cũng nhập vào thân thể sinh linh khác nhưng bản chất là mượn cơ thể thao túng từ xa, không tăng thực lực, chỉ dùng được vài phần sức của thân thể bị nhập. Hàn Lập so sánh với Phụ Linh thuật để phân biệt hai loại — Phụ Thân đại pháp không có hậu quả lớn, không lập ước sinh tử.","congNang":["Mượn thể sinh linh khác thao túng từ xa, phát huy vài phần sức @c0442"],"dacDiem":"Không tăng thực lực, không có hậu quả sinh tử như Phụ Linh thuật","tabs":{"tienTrinh":[{"chuong":"@c0442","loai":"nhắc tới","importance":"bridge","giaiDoan":"Hàn Lập so sánh với Phụ Linh thuật","text":"Hàn Lập nhắc tới Phụ Thân đại pháp để phân biệt với Phụ Linh thuật, nhận định hiệu quả kém xa.","anchor":"sử dụng phụ thân đại pháp chẵng những không có khả năng gia tăng thực lực"}]},"nguon":["@c0442"]},{"id":"tam-chuyen-trong-nguyen-cong","name":"Tam Chuyển Trọng Nguyên công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Công pháp đặc thù giúp Hàn Lập có khả năng đột phá Kết Đan kỳ dù linh căn không lý tưởng, nếu không tu luyện công pháp này thì căn bản không thể luyện đến Kết Đan.","detail":"Hàn Lập thầm nghĩ nếu không nhờ tu luyện Tam Chuyển Trọng Nguyên công thì không có khả năng luyện đến Kết Đan kỳ, ngụ ý công pháp này bù đắp cho linh căn kém.","congNang":["Giúp tu sĩ linh căn kém có khả năng đột phá Kết Đan kỳ"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0445","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0445","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập hồi tưởng","text":"Hàn Lập thầm nghĩ nếu không nhờ tu luyện Tam Chuyển Trọng Nguyên công thì căn bản không có khả năng luyện đến Kết Đan kỳ.","anchor":"Nếu không phải là do tu luyện Tam Chuyển Trọng Nguyên công, chỉ sợ căn bản không có khả năng luyện đến Kết đan kỳ rồi"}]},"nguon":["@c0445"]},{"id":"cong-phap-quy-dao","name":"Công pháp quỷ đạo","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Quỷ đạo","soHuu":["Huyền Cốt thượng nhân","Nam tử bí ẩn trong thân Huyền Cốt"],"blurb":"Công pháp quỷ đạo mà Huyền Cốt thượng nhân và đồng minh bí ẩn đều nửa đường chuyên tu, có ưu thế đào thoát trong quỷ vụ nhưng bị khắc chế bởi pháp bảo và thần thông đặc thù của tu sĩ Nguyên Anh kỳ.","detail":"Huyền Cốt cảnh báo rằng ba bốn tu sĩ Nguyên Anh kỳ ở đây có pháp bảo và thần thông khắc chế công pháp quỷ dị. Hai người có thủ đoạn đào mạng thần diệu trong quỷ vụ nhờ công pháp này.","congNang":["Thủ đoạn đào thoát thần diệu trong quỷ vụ"],"nguon":["@c0446"]},{"id":"dai-than-thong-khai-thien","name":"Đại thần thông khai thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cổ đại thần thông (thất truyền)","hePhai":"Cổ tu sĩ","soHuu":[],"blurb":"Đại thần thông của cổ tu sĩ thời xa xưa, có thể khai phá thiên địa tạo ra không gian nhỏ độc lập. Hậu nhân không thể tái hiện, đã thất truyền.","detail":"Huyền Cốt thượng nhân giải thích rằng không gian bên trong Hư Thiên Điện — bầu trời xanh mây trắng, thảo nguyên bao la, linh khí tràn trề — chính là sản phẩm của đại thần thông này. Cổ tu sĩ thần thông quảng đại nhưng đã biến mất vô ảnh vô tung, Tu tiên giới từ đó không vực dậy.","congNang":["Khai phá thiên địa, tạo ra không gian nhỏ độc lập với linh khí tràn trề"],"nguonGoc":"Thần thông của cổ tu sĩ thời xa xưa","dacDiem":"Hậu nhân không thể tái hiện, đã thất truyền hoàn toàn","trangThai":"thất truyền","tabs":{"tienTrinh":[{"chuong":"@c0447","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Huyền Cốt giải thích nguồn gốc không gian Hư Thiên Điện","text":"Huyền Cốt thượng nhân cho Hàn Lập biết không gian thực bên trong Hư Thiên Điện là sản phẩm đại thần thông cổ tu sĩ, có thể tạo ra không gian nhỏ. Hậu nhân không tái hiện được, cổ tu sĩ đã biến mất khiến Tu tiên giới suy tàn.","anchor":"Đây chính đại thần thông của cổ tu sĩ vào thời xa xưa, có thể tạo ra một cái không gian nhỏ"}]},"capNhatToi":"@c0447","nguon":["@c0447"]},{"id":"tu-tuong-huyen-vu-tran","name":"Tứ Tượng Huyền Vũ trận","cn":"四象玄武陣","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thổ thuộc tính","soHuu":["Huyền Cốt thượng nhân"],"blurb":"Cổ trận pháp Thổ thuộc tính, chỉ cần bốn cây trận kỳ màu vàng đất phủ phù văn tạo thành đại trận biến đất đá trong vài chục trượng cứng rắn như sắt.","detail":"Trận pháp cổ xưa chỉ cần bốn cây cờ nhỏ nhưng tạo thành đại trận Thổ thuộc tính, biến tất cả đất đá trong phương viên vài chục trượng cứng như sắt. Dùng để vây khốn Cửu Khúc Linh Sâm vốn có thể độn thổ thoát mọi vật liệu. Trận kỳ do Huyền Cốt luyện chế, đã bí mật cài bẫy lên trận kỳ trước khi giao cho Hàn Lập bố trí.","congNang":["Biến đất đá trong phương viên vài chục trượng cứng rắn như sắt, ngăn linh vật độn thổ thoát"],"tabs":{"tienTrinh":[{"chuong":"@c0449","loai":"xuất hiện","importance":"major","giaiDoan":"Huyền Cốt lấy ra trận kỳ, giao Hàn Lập bố trí","text":"Huyền Cốt lấy ra bốn cây cờ nhỏ màu vàng đất phủ phù văn. Hàn Lập nhận ra là khí cụ bày Tứ Tượng Huyền Vũ trận, cổ trận pháp Thổ thuộc tính biến đất đá cứng như sắt. Huyền Cốt giao cho Hàn Lập bố trí, nhưng đã bí mật cài bẫy trên trận kỳ.","anchor":"chỉ bốn cây cờ nhỏ nhưng có thể tạo thành một cái đại trận Thổ thuộc tính"}]},"nguon":["@c0449"]},{"id":"suu-linh-dai-phap","name":"Sưu Linh đại pháp","cn":"搜灵大法","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Huyền Cốt thượng nhân","Nam tử lệ hồn"],"blurb":"Thần thông dò tìm linh vật, Huyền Cốt và nam tử lệ hồn phối hợp phóng hắc khí và lục quang vào lòng đất để tìm ra vị trí Cửu Khúc Linh Sâm.","detail":"Huyền Cốt và nam tử lệ hồn phối hợp thi triển, phóng hai đạo hắc khí và một đạo lục quang chui vào lòng đất dò xét, xác định được Cửu Khúc Linh Sâm giấu bản thể trong hốc đá. Được Huyền Cốt đánh giá là dễ như trở bàn tay khi hai người hợp lực.","congNang":["Dò tìm linh vật ẩn náu dưới lòng đất bằng cách phóng hắc khí/lục quang thăm dò"],"nguoiTu":[{"ten":"Huyền Cốt thượng nhân","tuChuong":"@c0450","tangDatToi":"","trangThai":"dang-tu"},{"ten":"Nam tử lệ hồn","tuChuong":"@c0450","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0450","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Huyền Cốt và nam tử lệ hồn phối hợp thi triển Sưu Linh đại pháp, phóng hắc khí và lục quang vào lòng đất, tìm ra vị trí Cửu Khúc Linh Sâm giấu bản thể trong hốc đá.","anchor":"Bằng vào hai người chúng ta dùng Sưu Linh đại pháp tìm kiếm Linh Sâm thực dễ như trở bàn tay"}]},"nguon":["@c0450"]},{"id":"hoa-hinh-chi-thuat","name":"Hoá Hình Chi Thuật","cn":"化形之术","aliases":["Hóa hình chi thuật"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Quỷ đạo","soHuu":["Nam tử lệ hồn","Nam tử bí ẩn trong thân Huyền Cốt"],"blurb":"Thuật che giấu hình thể mà nam tử lệ hồn sử dụng, chỉ thần thức tu sĩ Nguyên Anh kỳ mới có khả năng phát hiện.","detail":"Thuật ẩn giấu hình thể thuộc quỷ đạo, cho phép lệ hồn vô hình che giấu hoàn toàn sự tồn tại. Chỉ tu sĩ đạt tới Nguyên Anh kỳ với thần thức cực mạnh mới có thể phát hiện ra người sử dụng.","congNang":["Che giấu hoàn toàn hình thể lệ hồn, chỉ thần thức Nguyên Anh kỳ mới phá được","Biến đổi hình dạng ngụy trang"],"nguoiTu":[{"ten":"Nam tử lệ hồn","tuChuong":"@c0450","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0450","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nam tử lệ hồn tiết lộ Hoá Hình Chi Thuật mà hắn sử dụng chỉ thần thức Nguyên Anh kỳ mới phát hiện, giải thích vì sao hắn ẩn náu trong cơ thể Huyền Cốt mà không ai hay biết.","anchor":"Hoá Hình Chi Thuật mà ta sử dụng chỉ với thần thức của tu sĩ Nguyên Anh kỳ mới có khả năng phát hiện ra"},{"chuong":"@c0451","loai":"thi triển","importance":"normal","giaiDoan":"Trợ thủ Huyền Cốt sử dụng khi truy tìm Linh Sâm","text":"Trợ thủ bí ẩn của Huyền Cốt dùng Hóa hình chi thuật hóa hình truy tìm Cửu Khúc Linh Sâm, bị Hàn Lập phát hiện.","anchor":"Ta không tin ngươi có khả năng nhìn ra Hóa hình chi thuật"}]},"nguon":["@c0450","@c0451"]},{"id":"vo-hinh-phap-the","name":"Vô hình pháp thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Quỷ đạo","soHuu":["Nam tử lệ hồn"],"blurb":"Thần thông của quỷ tu cho phép xuyên qua trận pháp cấm chế mà không cần phá vỡ, nhập vào bên trong dưới dạng vô hình.","detail":"Gã bóng xanh (quỷ ảnh cấp Quỷ Vương) sử dụng để xuyên qua trận pháp phòng hộ của Hàn Lập mà không phá cấm chế. Tuy nhiên dạng vô hình này vẫn bị Phệ Kim Trùng cắn nuốt lục quang.","congNang":["Xuyên qua cấm chế trận pháp mà không phá vỡ, cho phép xâm nhập dạng vô hình"],"nguoiTu":[{"ten":"Nam tử lệ hồn","tuChuong":"@c0452","tangDatToi":"","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0452","loai":"thi triển","importance":"normal","giaiDoan":"Gã bóng xanh dùng xuyên trận pháp","text":"Gã bóng xanh dùng vô hình pháp thể xuyên qua trận pháp phòng hộ xâm nhập bên trong, nhưng lục quang trên thân bị Phệ Kim Trùng cắn nuốt.","anchor":"đây là loại quỷ trùng gì mà ngay cả vô hình pháp thể của ta cũng bị cắn nuốt luôn"}]},"nguon":["@c0452"]},{"id":"phuong-phap-luyen-che-linh-thi","name":"Phương pháp luyện chế linh thi","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Tà đạo","soHuu":["Cực Âm lão tổ"],"blurb":"Phương pháp tà thuật của Cực Âm lão tổ, có thể giết linh thú rồi biến thành yêu thi, nhưng tu vi linh thú sẽ giảm mạnh.","detail":"Cực Âm lão tổ tiết lộ mình nắm giữ phương pháp giết linh thú rồi biến thành yêu thi, dùng làm con bài uy hiếp Hàn Lập. Nhược điểm là tu vi linh thú sẽ giảm mạnh sau khi biến thành yêu thi, nên chỉ là phương án cuối cùng.","congNang":["Giết linh thú rồi biến thành yêu thi @c0455","Yêu thi sau biến hóa tu vi giảm mạnh so với nguyên thể @c0455"],"nguoiTu":[{"ten":"Cực Âm lão tổ","tuChuong":"@c0455","tangDatToi":"nắm giữ phương pháp","trangThai":"chua-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0455","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu được hé lộ","text":"Cực Âm lão tổ tiết lộ có phương pháp luyện chế linh thi, dùng uy hiếp Hàn Lập rằng có thể giết Huyết Ngọc Tri Chu rồi biến thành yêu thi dù tu vi sẽ giảm mạnh.","anchor":"bổn tổ sự có một phương pháp luyện chế linh thi"}]},"nguon":["@c0455"]},{"id":"thac-thien-ma-cong","name":"Thác Thiên ma công","cn":"託天魔功","aliases":["Thác Thiên Công"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Đệ nhất ma công","hePhai":"Ma đạo","soHuu":["Man Hồ Tử"],"blurb":"Ma công cốt lõi của Man Hồ Tử, khi thi triển toàn thân phủ lớp vảy vàng kim dày đặc cứng rắn, hình dáng quỷ dị tựa yêu thần. Được coi là đệ nhất ma công.","detail":"Khi vận công, toàn thân mọc lớp vảy dày đặc như đồng tiền, cực kỳ cứng rắn, phát hào quang vàng kim. Hình dáng quỷ dị phảng phất giống yêu thần. Man Hồ Tử dùng nội đan Băng Tuyết thiềm để tinh tiến thêm. Thanh Dịch cư sĩ nhận xét nếu tinh tiến nữa có thể đánh trận với Song Thánh và Lục Đạo.","thuocTinh":"Kim / Thể tu","nguonGoc":"Ma công của Man Hồ Tử","dacDiem":"Toàn thân mọc vảy vàng kim cứng rắn, phòng ngự cực mạnh","nguoiTu":[{"ten":"Man Hồ Tử","tuChuong":"@c0457","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0457","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu phô diễn","text":"Man Hồ Tử bay đến trong quang cầu vàng kim, toàn thân phủ vảy vàng — lần đầu lộ diện uy năng Thác Thiên ma công trước các tu sĩ Nguyên Anh. Man Hồ Tử muốn giành Hàn Lập vì cảm thấy hắn thích hợp tu luyện công pháp này.","anchor":"trên cánh tay trần và khuôn mặt còn có lớp vảy dày đặc như đồng tiền vậy"}]},"congNang":["Toàn thân mọc lớp vảy vàng kim dày đặc, cứng rắn, phòng ngự cực mạnh","Tinh tiến bằng nội đan linh thú (Băng Tuyết thiềm)"],"capNhatToi":"@c0457","nguon":["@c0457"]},{"id":"thai-duong-quyet","name":"Thái Dương quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ (top 10 hỏa hệ Loạn Tinh Hải)","hePhai":"Hỏa hệ","soHuu":["Bặc Tự"],"blurb":"Hỏa hệ công pháp nổi tiếng Loạn Tinh Hải, xếp trong mười đứng đầu. Có Thái Dương chân hỏa, khả năng tị hỏa. Tuy nhiên trên Dung Nham lộ bị cấm chế khắc chế hoàn toàn.","detail":"Thái Dương quyết có tiếng tăm không nhỏ ở Loạn Tinh Hải, xếp vào hàng mười hỏa hệ công pháp đứng đầu. Tuy nhiên trên Dung Nham lộ trong Hư Thiên Điện, cấm chế đặc thù khắc chế hỏa hệ khiến công pháp này gần như vô hiệu, buộc tu sĩ phải vận dụng toàn lực mới chống được nhiệt độ, pháp lực tiêu hao cực nhanh.","thuocTinh":"Hỏa","congNang":["Tị hỏa","Phóng Thái Dương chân hỏa"],"dacDiem":"Bị cấm chế Dung Nham lộ khắc chế, pháp lực tiêu hao cực nhanh trong hạp cốc","nguoiTu":[{"ten":"Bặc Tự","tuChuong":"@c0458","tangDatToi":"","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0458","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Lần đầu đề cập","text":"Bặc Tự tu luyện Thái Dương quyết trên Dung Nham lộ nhưng bị cấm chế khắc chế, pháp lực tiêu hao cực nhanh, không cứu nổi mạng.","anchor":"Thái Dương quyết có tiếng tăm không nhỏ ở Loạn Tinh Hải"}]},"nguon":["@c0458"]},{"id":"cong-phap-vo-danh","name":"Công pháp vô danh","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Công pháp không rõ tên mà Hàn Lập tu luyện, có thuật ẩn thân giúp tránh thoát dò tìm của tu sĩ Kết Đan trung kỳ khi kết hợp La Yên bộ.","detail":"Hàn Lập sử dụng thuật ẩn thân từ công pháp này cộng với La Yên bộ, dễ dàng tránh thoát công kích dò tìm của nam tử mặt vàng tu vi Kết Đan trung kỳ mà không bị phát hiện.","congNang":["Thuật ẩn thân: kết hợp La Yên bộ giúp tránh thoát dò tìm Kết Đan trung kỳ"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0459","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0459","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn thân tại hắc sa mạc","text":"Hàn Lập dùng thuật ẩn thân từ công pháp vô danh kết hợp La Yên bộ, tránh thoát hoàn toàn dò tìm của tu sĩ Kết Đan trung kỳ trên đỉnh núi cạnh hắc sa mạc.","anchor":"thuật ẩn thân từ công pháp vô danh kia, cộng với việc thi triển La Yên bộ"}]},"nguon":["@c0459"]},{"id":"thuat-khong-che-cam-che-phe-kim-trung","name":"Thuật khống chế cấm chế không gian bằng Phệ Kim Trùng","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Mẹo tả đạo dùng năng lực thôn phệ thiên địa linh khí của Phệ Kim Trùng để cắt liên hệ linh lực với cấm chế không gian, tạm khống chế cấm chế trong thời gian rất ngắn.","detail":"Hàn Lập vận dụng kiến thức trận pháp học từ Tân Như Âm cùng sách cổ về không gian cấm chế, kết hợp năng lực đặc dị của Phệ Kim Trùng. Tế xuất mấy vạn Phệ Kim Trùng bao phủ toàn thân, che giấu toàn bộ linh lực để cắt liên hệ với cấm chế. Cách này bị Tân Như Âm chê là tả đạo, đến tu sĩ Nguyên Anh kỳ cũng khó thực hiện. Chỉ duy trì được thời gian rất ngắn trước khi cấm chế phản ứng phá vỡ.","thuocTinh":"Không gian, cấm chế","nguonGoc":"Sách cổ về không gian cấm chế + kiến thức trận pháp từ Tân Như Âm","yeuCau":"Phệ Kim Trùng số lượng lớn, hiểu biết trận pháp và cấm chế","uyLuc":"Tạm khống chế cấm chế không gian trong thời gian rất ngắn, đủ để di chuyển đoạt bảo","dacDiem":"Bị coi là tả đạo, đến Nguyên Anh kỳ cũng khó làm, thời gian duy trì cực ngắn","congNang":["Cắt liên hệ linh lực với cấm chế không gian","Tạm khống chế cấm chế trong khoảng thời gian rất ngắn"],"trangThai":"Đã sử dụng thành công","capNhatToi":"@c0468","tabs":{"tienTrinh":[{"chuong":"@c0468","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu sử dụng thực chiến","text":"Hàn Lập tế xuất mấy vạn Phệ Kim Trùng tạo khôi giáp đen bao toàn thân, khống chế cấm chế thạch điện đủ lâu để đoạt hai cổ bảo trước khi lam quang phá vỡ hắc giáp.","anchor":"khống chế được cấm chế trong khoảng thời gian rất ngắn"}]},"nguon":["@c0468"]},{"id":"thien-ngoai-am-ma","name":"Thiên ngoại âm ma","cn":"天外音魔","loai":"bi-thuat","loaiLabel":"Bí thuật âm thanh","phamCap":null,"hePhai":"Tà đạo","soHuu":[],"blurb":"Âm thanh tà mị trong Cực Diệu Huyễn Cảnh, phối hợp huyễn cảnh mỹ nữ để mê hoặc thần trí người vượt ải.","detail":"Loại âm thanh xuất hiện trong hành lang Cực Diệu Huyễn Cảnh, biến đổi từ vui tươi sang hòa nhã rồi bi ai oán than, cuối cùng chuyển sang tà mỵ kích thích dục vọng. Phối hợp với huyễn cảnh bạch hạc hóa mỹ nữ rồi mỹ phụ khiêu gợi để tấn công tinh thần người đi qua. Hàn Lập nhờ Đại Diễn Quyết hộ thần nên không bị ảnh hưởng.","nguon":["@c0470"]},{"id":"thien-ma-cong","name":"Thiên ma công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Man Hồ Tử"],"blurb":"Công pháp sở trường của Man Hồ Tử, đệ nhất nhân ma đạo. Man Hồ Tử dùng để đe dọa Thiên Ngộ Tử thử thực lực.","detail":"Công pháp chiến đấu ma đạo mà Man Hồ Tử tu luyện. Khi đe dọa Thiên Ngộ Tử, Man Hồ Tử hỏi lão đạo có muốn thử thực lực của Thiên ma công hay không, cho thấy sự tự tin tuyệt đối vào uy lực công pháp này.","thuocTinh":"Ma đạo","nguonGoc":"Không rõ","yeuCau":"Không rõ","uyLuc":"Khiến Thiên Ngộ Tử (Nguyên Anh kỳ chính đạo) phải kiêng dè","dacDiem":"Công pháp chiến đấu sở trường của đệ nhất nhân ma đạo Man Hồ Tử","congNang":["Công pháp chiến đấu uy lực mạnh, khiến đối thủ Nguyên Anh kỳ chính đạo kiêng kỵ"],"nguoiTu":[{"ten":"Man Hồ Tử","tuChuong":"@c0472","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0472","loai":"nhắc tới","importance":"normal","giaiDoan":"Man Hồ Tử đe dọa Thiên Ngộ Tử","text":"Man Hồ Tử đe dọa Thiên Ngộ Tử có muốn thử thực lực Thiên ma công hay không, khiến Thiên Ngộ Tử phải bỏ qua.","anchor":"hay là bản thân ngươi muốn thử xem một ít thực lực của Thiên ma công?"}]},"nguon":["@c0472"]},{"id":"ngoc-dan-cong","name":"Ngọc Đan công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Lão giả gầy gò giống lão nông"],"blurb":"Công pháp do lão giả gầy ốm phe chính đạo tu luyện, thần thông không nhỏ, thực lực chân chính thậm chí trên Thiên Ngộ Tử.","detail":"Công pháp được nhắc đến khi giới thiệu lão giả gầy ốm giống lão nông trong nhóm ba tu sĩ Nguyên Anh kỳ chính đạo. Tu luyện công pháp này cho phép đạt thực lực vượt trên cả Thiên Ngộ Tử.","nguoiTu":[{"ten":"Lão giả gầy gò giống lão nông","tuChuong":"@c0475","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0475","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu được nhắc tên","text":"Được giới thiệu là công pháp của lão giả gầy ốm phe chính đạo, thần thông không nhỏ, thực lực trên cả Thiên Ngộ Tử.","anchor":"tu luyện “Ngọc Đan công” thần thông không nhỏ, thực lực chân chính thậm chí còn trên Thiên Ngộ Tử"}]},"nguon":["@c0475"]},{"id":"thien-cuong-trao-cam-che","name":"Thiên cương tráo cấm chế","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế / Trận pháp","phamCap":"Thượng cổ","hePhai":"","soHuu":[],"blurb":"Cấm chế thượng cổ nổi danh bao phủ thạch đài tầng năm, biểu hiện là màn hào quang trắng có lam quang lấp lòe, chỉ có một lối ra duy nhất.","detail":"Cấm chế thời thượng cổ phong tỏa không gian thạch đài tầng năm. Bên ngoài biểu hiện là màn hào quang trắng lấp lòe lam quang. Ngoài lối ra đặc biệt tại chỗ, không thể trong thời gian ngắn thoát khỏi. Nhóm ma đạo lợi dụng điểm này để phục kích nhóm chính đạo khi họ ra.","nguonGoc":"Thời thượng cổ","congNang":["Phong tỏa không gian, chỉ có một lối ra duy nhất, không thể phá trong thời gian ngắn","Phong tỏa khu vực, chỉ cho phép một lối ra vào duy nhất"],"tabs":{"tienTrinh":[{"chuong":"@c0475","loai":"xuất hiện","importance":"normal","giaiDoan":"Bao phủ thạch đài tầng năm","text":"Lão giả nho sam nhận ra và giải thích đây là Thiên cương tráo cấm chế thượng cổ nổi danh. Vạn Thiên Minh dùng tử khí đậm đặc bổ mở tạo lối vào.","anchor":"chính là Thiên cương tráo cấm chế nổi danh thời thượng cổ"}]},"nguon":["@c0475"]},{"id":"cuong-bao-chi-thuat","name":"Cuồng bạo chi thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Man Hồ Tử","Huyền Cốt"],"blurb":"Pháp thuật tăng sức mạnh cho linh thú hoặc mục tiêu, Man Hồ Tử thi triển lên Huyết Ngọc Tri Thù để tăng lực kéo Hư Thiên đỉnh.","detail":"Man Hồ Tử thi triển lên Huyết Ngọc Tri Thù theo yêu cầu Cực Âm vì pháp lực Hàn Lập không đủ để sử dụng pháp thuật này. Khi thi triển, Man Hồ Tử nhìn chằm chằm vào Tri Thù lẩm nhẩm, miệng mơ hồ lộ hồng quang.","thuocTinh":"Tăng cường lực lượng","nguonGoc":"","yeuCau":"Pháp lực đủ mạnh, tu sĩ Trúc Cơ kỳ không đủ thi triển","uyLuc":"Tăng sức mạnh cho linh thú để kéo vật cực nặng","dacDiem":"Khi thi triển miệng lộ hồng quang","congNang":["Tăng sức mạnh cho linh thú/mục tiêu","Kích thích linh thú vào trạng thái cuồng bạo tăng mạnh sức mạnh thể chất"],"nguoiTu":[{"ten":"Man Hồ Tử","tuChuong":"@c0478","tangDatToi":"","trangThai":"thi triển"},{"ten":"Huyền Cốt","tuChuong":"@c0488","tangDatToi":"Không thể thi triển trọn vẹn do công pháp hạn chế","trangThai":"han-che"}],"tabs":{"tienTrinh":[{"chuong":"@c0478","loai":"thi triển","importance":"normal","giaiDoan":"Man Hồ Tử thi triển lên Huyết Ngọc Tri Thù","text":"Cực Âm yêu cầu Man Hồ Tử cấp Cuồng bạo chi thuật lên Huyết Ngọc Tri Thù vì pháp lực Hàn Lập không đủ. Man Hồ Tử lập tức đáp ứng, nhìn chằm chằm vào Tri Thù lẩm nhẩm, miệng mơ hồ lộ hồng quang.","anchor":"Phiền huynh đem Cuồng bạo chi thuật cấp lên trên Huyết Ngọc Tri Thù"},{"chuong":"@c0479","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Man Hồ Tử thi triển lên Huyết Ngọc Tri Thù, phun huyết hồng hóa cột sáng kích thích linh thú cuồng bạo để tăng sức kéo Hư Thiên đỉnh. Có giới hạn thời gian và hậu hoạn.","anchor":"Cuồng bạo chi thuật vừa nghe danh xưng của pháp thuật này, liền biết là ma đạo bí thuật, khẳng định là có mang theo cả hậu hoạn"},{"chuong":"@c0488","loai":"thi triển","importance":"normal","giaiDoan":"Huyền Cốt dùng phiên bản hạn chế","text":"Huyền Cốt thi triển pháp thuật phụ trợ thay thế Cuồng Bạo chi thuật, khiến Huyết Ngọc Tri Thù vào trạng thái cuồng bạo nhưng thừa nhận công pháp bị hạn chế không dùng được trọn vẹn.","anchor":"Mặc dù công pháp của ta có hạn chế, không cách nào thi triển ra Cuồng bạo chi thuật"}]},"nguon":["@c0478","@c0479","@c0488"]},{"id":"di-hoa-thuat","name":"Dị hóa thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Báo ba mắt (Man Hồ Tử)"],"blurb":"Năng lực đặc biệt của linh thú biến dị, biến pháp khí/pháp bảo thành đá. Cực kỳ nổi danh, từng có tu sĩ Kết Đan kỳ dùng năng lực này giết sạch ba bốn tu sĩ đồng cấp, chấn động Loạn Tinh Hải.","detail":"Năng lực chỉ linh thú biến dị mới sở hữu. Con mắt thứ ba của báo ba mắt phóng cột sáng màu vàng đất, bất kỳ pháp khí hay pháp bảo nào bị trúng đều hóa thành tảng đá rồi nát vụn. Không công kích trực tiếp bản thân tu sĩ, chỉ cần cẩn thận tránh hoàng quang bắn trúng pháp bảo. Linh thú biến dị cực hiếm, Loạn Tinh Hải từ trước đến nay chỉ xuất hiện hơn mười con, lần gần nhất đã hơn ngàn năm trước.","congNang":["Biến pháp khí/pháp bảo thành đá"],"tabs":{"tienTrinh":[{"chuong":"@c0480","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện trong đại chiến Hư Thiên Điện","text":"Báo ba mắt của Man Hồ Tử phóng cột sáng vàng đất từ mắt thứ ba, biến pháp khí/pháp bảo tử quang của Vạn Thiên Minh thành đá vụn. Tất cả chấn kinh nhận ra đây là linh thú biến dị.","anchor":"Dị hóa thuật, con báo ba mắt của ngươi là một linh thú biến dị?"}]},"nguon":["@c0480"]},{"id":"cong-phap-canh-lieu-moc-thuoc-tinh","name":"Công pháp cành liễu (mộc thuộc tính)","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Mộc","soHuu":["Lão giả gầy gò giống lão nông"],"blurb":"Công pháp mộc thuộc tính của lão giả gầy gò phe chính đạo, dùng cành liễu xanh biếc tạo hải dương ảo ảnh và phóng lục ti trói buộc đối phương.","detail":"Dùng cành liễu xanh biếc giữa hai ngón tay phóng vô số ảo ảnh xanh biếc, trong phạm vi hơn mười trượng biến thành hải dương xanh biếc. Từ trong đó phóng vô số lục ti trói chặt mục tiêu. Mộc thuộc tính rõ ràng, bị Thiên Đô Thi Hỏa (hỏa thuộc tính) khắc chế gấp bội.","congNang":["Tạo hải dương ảo ảnh xanh biếc","Phóng lục ti trói buộc/khống chế đối phương"],"tabs":{"tienTrinh":[{"chuong":"@c0480","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu sử dụng trong đại chiến Hư Thiên Điện","text":"Lão giả gầy gò dùng cành liễu xanh biếc tạo hải dương ảo ảnh, phóng lục ti trói chặt ba con Thiết giáp yêu thi của Cực Âm.","anchor":"vô số ảo ảnh màu xanh biếc từ trên người hắn bắn ra ngoài, trong phạm vi hơn mười trượng phảng phất như biến thành hải dương xanh biếc"}]},"nguon":["@c0480"]},{"id":"hoa-nhan-hoa-than","name":"Hỏa nhân hóa thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hỏa","soHuu":["Vạn Thiên Minh"],"blurb":"Pháp thuật của Vạn Thiên Minh, biến toàn thân thành hỏa nhân hỏa diễm màu tím để tấn công.","detail":"Vạn Thiên Minh hai tay chập lại trước ngực, hỏa diễm màu tím bừng cháy, cả người trong nháy mắt hóa thành một hỏa nhân để tấn công đối thủ.","congNang":["Biến thân thành hỏa nhân chiến đấu"],"tabs":{"tienTrinh":[{"chuong":"@c0480","loai":"thi triển","importance":"normal","giaiDoan":"Khai chiến với Man Hồ Tử","text":"Vạn Thiên Minh hóa hỏa nhân hỏa diễm màu tím bay đến tấn công Man Hồ Tử trong đại chiến Nguyên Anh kỳ.","anchor":"hỏa diễm màu tím bừng cháy lên, cả người hắn trong nháy mắt hóa thành một hỏa nhân"}]},"nguon":["@c0480"]},{"id":"thien-la-cong","name":"Thiên La Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Vạn Thiên Minh"],"blurb":"Công pháp của Vạn Thiên Minh, biến hóa tử sắc hỏa long và cự kiếm tấn công, có thể dùng phân thần biến ảo tạo phân thân giống hệt.","detail":"Vạn Thiên Minh thi triển Thiên La Công biến hóa tử sắc hỏa long và tử sắc cự kiếm tấn công. Có khả năng phân thần biến ảo tạo phân thân giống hệt bản thân, phân thân có thể phóng tử hồng hỏa diễm uy lực không nhỏ.","congNang":["Biến hóa tử sắc hỏa long tấn công","Thao túng tử sắc cự kiếm","Phân thần biến ảo tạo phân thân giống hệt, phóng tử hồng hỏa diễm"],"nguoiTu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0481","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0481","loai":"thi triển","importance":"normal","giaiDoan":"Trận chiến Hư Thiên Điện","text":"Vạn Thiên Minh thi triển Thiên La Công biến hóa tử hỏa long và cự kiếm đấu Man Hồ Tử, sau đó dùng phân thần biến ảo tạo phân thân tranh đoạt hỏa lang.","anchor":"tử sắc hỏa long do Thiên La Công của Vạn Thiên Minh biến thành"}]},"nguon":["@c0481"]},{"id":"thien-la-chan-loi","name":"Thiên La chân lôi","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cực cao (tự tu luyện từ pháp lực, nguy hiểm tính mạng mới dùng)","hePhai":"","soHuu":["Vạn Thiên Minh"],"blurb":"Lôi châu tử sắc cực mạnh, tu luyện từ pháp lực bản thân, uy lực cực lớn, chỉ dám dùng khi nguy hiểm đến tính mạng.","detail":"Thiên La chân lôi là loại lôi châu tử sắc tu luyện từ chính pháp lực của tu sĩ, hao tổn rất lớn nên chỉ khi nguy hiểm đến tính mạng mới dám sử dụng. Vạn Thiên Minh dùng hai viên giả Thiên La chân lôi châu dọa Cực Âm sư tổ và lão giả nho sam hoảng sợ né tránh, sau đó lộ thêm một viên thật để đe dọa.","congNang":["Phóng lôi châu tử sắc uy lực cực lớn, khiến tu sĩ Nguyên Anh kỳ cũng phải hoảng sợ né tránh"],"nguoiTu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0482","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0482","loai":"thi triển","importance":"major","giaiDoan":"Vạn Thiên Minh dùng giả lôi châu đoạt Cổ Bội","text":"Vạn Thiên Minh phun hai viên giả Thiên La chân lôi châu dọa Cực Âm và lão giả nho sam hoảng sợ né tránh, nhờ đó đoạt Cổ Bội. Sau đó lộ thêm một viên thật đe dọa.","anchor":"Thiên La chân lôi này nếu không có nguy hiểm đến tánh mạng, thì sao bổn nhân dám sử dụng bảo vật này"}]},"nguon":["@c0482"]},{"id":"thuat-che-mat-huyen-cot","name":"Thuật che mắt của Huyền Cốt","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Huyền Cốt"],"blurb":"Pháp thuật che giấu diện mạo pháp bảo, dùng biến đổi thanh tiểu đao Kim Lôi Trúc thành tiểu đao xanh biếc thường. Cực kỳ cao minh, nếu không phải bổn mạng pháp bảo cùng loại thì không phát giác được.","detail":"Huyền Cốt dùng thuật che mắt thi triển lên thanh tiểu đao do Kim Lôi Trúc nhỏ tạo thành, biến đổi hoàn toàn diện mạo thành tiểu đao xanh biếc bình thường. Hàn Lập nhờ bổn mạng pháp bảo cũng là Kim Lôi Trúc nên mới cảm ứng nhận ra bản chất thực sự.","congNang":["Che giấu bản chất và diện mạo pháp bảo Kim Lôi Trúc"],"nguon":["@c0483"],"tabs":{"tienTrinh":[{"chuong":"@c0483","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu lộ diện","text":"Huyền Cốt phun ra thanh tiểu đao xanh biếc tấn công ngân lang, Hàn Lập cảm ứng phát hiện đó thực chất là Kim Lôi Trúc bị thuật che mắt che giấu diện mạo.","anchor":"thuật che mắt thi triển quả thật rất cao minh"}]}},{"id":"nguyen-anh-xuat-khieu","name":"Nguyên Anh xuất khiếu","cn":"元婴出窍","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vạn Thiên Minh"],"blurb":"Thần thông cho Nguyên Anh rời khỏi thân xác, hiện hình bên ngoài để chiến đấu hoặc sử dụng bảo vật, nhưng có nguy cơ thần hồn câu diệt.","detail":"Tu sĩ vỗ thiên linh cái, Nguyên Anh rời thể xác hiện ra trên đỉnh đầu — hình trẻ con trần truồng khoảng hai tấc, tướng mạo giống hệt bản thể, bao quanh quang mang, có thể cầm bảo vật. Thân xác bản thể nhắm mắt bất động trong lúc Nguyên Anh xuất khiếu. Đây là chiêu liều mạng vì một khi Nguyên Anh bị diệt ở bên ngoài sẽ thần hồn câu diệt.","congNang":["Nguyên Anh rời thân xác chiến đấu/sử dụng bảo vật bên ngoài"],"nguon":["@c0485"]},{"id":"nguyen-anh-ngu-kiem","name":"Nguyên Anh ngự kiếm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Nguyên Anh kỳ chuyên dụng","hePhai":"","soHuu":["Vạn Thiên Minh"],"blurb":"Thuấn di chân chính của tu sĩ Nguyên Anh kỳ sau khi nguyên anh xuất khiếu — nguyên anh cưỡi kiếm di chuyển tức thời, cực tốn bổn mạng nguyên khí nên không dễ thi triển.","detail":"Năng lực đặc thù chỉ tu sĩ Nguyên Anh kỳ mới có thể sử dụng: sau khi nguyên anh thoát ly thân thể, cưỡi kiếm thực hiện thuấn di chân chính chứ không phải ảo ảnh do tốc độ. Mỗi tu sĩ Nguyên Anh kỳ đều có khẩu quyết nhưng không dễ dàng thi triển do tổn hao bổn mạng nguyên khí cực lớn. Vạn Thiên Minh dùng thần thông này cưỡi tiểu kiếm tử sắc thuấn di liên tục hai lần, huyễn hóa bàn tay tím khổng lồ chộp Bổ Thiên đan.","thuocTinh":"Thuấn di","yeuCau":"Nguyên Anh kỳ, nguyên anh phải xuất khiếu","uyLuc":"Thuấn di chân chính, tốc độ vượt xa độn quang thường, khiến bốn tu sĩ Nguyên Anh kỳ đang giao chiến đồng thời biến sắc","dacDiem":"Tổn hao bổn mạng nguyên khí cực lớn, tu sĩ Nguyên Anh kỳ không dễ dàng sử dụng","nguoiTu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0486","tangDatToi":"","trangThai":"đã thi triển thực chiến"}],"tabs":{"tienTrinh":[{"chuong":"@c0486","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện và thi triển","text":"Vạn Thiên Minh nguyên anh xuất khiếu cưỡi tiểu kiếm tử sắc thuấn di liên tục hai lần để đoạt Bổ Thiên đan, khiến bốn tu sĩ Nguyên Anh kỳ đang giao chiến đồng thời biến sắc kinh hãi.","anchor":"trực tiếp thuấn di chân chính. Cũng là năng lực đặc thù của tu sĩ Nguyên Anh kỳ sau khi Nguyên Anh xuất khiếu thoát ly khỏi thân thể"}]},"nguon":["@c0486"]},{"id":"tu-la-thanh-hoa","name":"Tu La thánh hỏa","cn":"修罗圣火","aliases":["Tu La thanh hỏa"],"loai":"bi-thuat","loaiLabel":"Dị hỏa truyền thuyết","phamCap":"Truyền thuyết","hePhai":"Tà đạo","soHuu":["Huyền Cốt"],"blurb":"Loại lửa truyền thuyết, được dung hợp từ ba thành phần: Kiềm Lam Băng Diễm, Huyền hồn âm tỏa và Ích tà thần lôi. Là mục đích cuối cùng của Huyền Cốt khi đến tế đàn Hư Thiên Đỉnh.","detail":"Huyền Cốt tiết lộ khi ba thứ Kiềm Lam Băng Diễm, Huyền hồn âm tỏa, Ích tà thần lôi cùng ở một chỗ thì có thể dung hợp thành Tu La thanh hỏa trong truyền thuyết. Quang cầu dung hợp đường kính một thước, hai màu xanh đen, trung tâm có ngọn lửa lam muốn xông ra, bên ngoài có dòng điện đen nhánh bắn tia kèm tiếng sấm nhỏ.","thuocTinh":"Chí âm chí hàn + tà lôi","nguonGoc":"Dung hợp từ Kiềm Lam Băng Diễm + Huyền hồn âm tỏa + Ích tà thần lôi","congNang":["Uy lực chưa rõ, thuộc hạng truyền thuyết, dung hợp từ ba thành phần chí hàn chí tà hiếm gặp","Hợp nhất ba loại năng lượng (lam sắc băng diễm + Huyền Hồn âm hỏa + hắc sắc điện hồ) thành hỏa diễm xám trắng cực lạnh","Phun tia lửa công kích với khí thế long trời lở đất"],"dacDiem":"Quang cầu hai màu xanh đen, trung tâm lửa lam, ngoài có dòng điện đen kèm tiếng sấm","trangThai":"Mới hợp thành, chưa ổn định","capNhatToi":"@c0489","tabs":{"tienTrinh":[{"chuong":"@c0489","loai":"xuất hiện","importance":"major","giaiDoan":"Bắt đầu dung hợp","text":"Huyền Cốt tiết lộ mục đích thật, dung hợp ba thành phần Kiềm Lam Băng Diễm, Huyền hồn âm tỏa, Ích tà thần lôi thành Tu La thanh hỏa truyền thuyết tại tế đàn Hư Thiên Đỉnh.","anchor":"có thể dung hợp lại làm một. Như vậy ta có thể tu luyện thành Tu La thanh hỏa trong truyền thuyết"},{"chuong":"@c0490","loai":"xuất hiện","importance":"major","giaiDoan":"Hợp thành lần đầu","text":"Huyền Cốt lâm thế cưỡi hổ, liều mạng ném quang cầu phóng pháp quyết hợp nhất lam sắc băng diễm, Huyền Hồn âm hỏa và hắc sắc điện hồ thành Tu La thánh hỏa xám trắng cực lạnh, phun tia lửa long trời lở đất công kích Hàn Lập.","anchor":"chưa bị luyện hóa để dung hợp thành “Tu La thánh hỏa”"}]},"nguon":["@c0489","@c0490"],"nguoiTu":[{"ten":"Huyền Cốt","tuChuong":"@c0490","tangDatToi":"Mới hợp thành (chưa luyện hóa hoàn chỉnh)","trangThai":"dang-dung"}]},{"id":"huyen-hon-am-hoa","name":"Huyền Hồn âm hỏa","cn":"玄魂阴火","aliases":["Huyền hồn âm tỏa","Huyền hồn quỷ hỏa"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Quỷ đạo","soHuu":["Huyền Cốt"],"blurb":"Hỏa diễm quỷ đạo thuộc về Huyền Cốt, là một trong ba thành phần hợp thành Tu La thánh hỏa.","detail":"Hỏa diễm quỷ đạo sẵn có của Huyền Cốt. Quay ở lớp ngoài quang cầu cùng hắc sắc điện hồ, theo hướng ngược lại với lam sắc băng diễm bên trong. Là một trong ba nguyên liệu hợp thành Tu La thánh hỏa.","congNang":["Thành phần hợp thành Tu La thánh hỏa"],"nguoiTu":[{"ten":"Huyền Cốt","tuChuong":"@c0490","tangDatToi":"","trangThai":"dang-dung"}],"capNhatToi":"@c0490","tabs":{"tienTrinh":[{"chuong":"@c0490","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện trong quang cầu, được dùng hợp thành Tu La thánh hỏa","text":"Huyền Hồn âm hỏa quay ở lớp ngoài quang cầu của Huyền Cốt cùng hắc sắc điện hồ, được hợp nhất cùng lam sắc băng diễm để tạo Tu La thánh hỏa.","anchor":"Huyền Hồn âm hỏa và hắc sắc điện hồ ở bên ngoài lại quay theo hướng ngược lại"}]},"nguon":["@c0490"]},{"id":"thanh-nguyen-cong-phap","name":"Thanh Nguyên công pháp","cn":"清元功法","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Công pháp mà Hàn Lập sử dụng, chứa chiêu thức Kiếm Ảnh Phân Quang thuật cho phép phân thân cự kiếm.","detail":"Công pháp Hàn Lập tu luyện, trong đó có chiêu Kiếm Ảnh Phân Quang thuật cho phép biến một cự kiếm thành ba thanh giống hệt nhau, mỗi bản sao đều có thể phóng Ích Tà Thần Lôi thật.","congNang":["Chứa chiêu Kiếm Ảnh Phân Quang thuật — phân thân cự kiếm thành 3 thanh, bản sao phóng được thần lôi thật"],"chieuTieuBieu":["Kiếm Ảnh Phân Quang thuật"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0490","tangDatToi":"","trangThai":"dang-dung"}],"capNhatToi":"@c0490","tabs":{"tienTrinh":[{"chuong":"@c0490","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập thi triển chiêu Kiếm Ảnh Phân Quang thuật trong trận chiến","text":"Hàn Lập thi triển Kiếm Ảnh Phân Quang thuật trong Thanh Nguyên công pháp, biến cự kiếm thành ba thanh, hai thanh phóng Ích Tà Thần Lôi chống băng long, một thanh chém Huyền Cốt.","anchor":"chiêu “Kiếm ảnh phân quang thuật” trong Thanh Nguyên công pháp"}]},"nguon":["@c0490"]},{"id":"huyen-hon-luyen-yeu-dai-phap","name":"Huyền Hồn luyện yêu đại pháp","cn":"玄魂炼妖大法","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Quỷ tu","soHuu":["Huyền Cốt"],"blurb":"Bí thuật do Huyền Cốt nắm giữ, liên quan đến luyện yêu. Tàn hồn Huyền Cốt nhắc đến khi cầu xin Hàn Lập tha mạng, nguyện giao nộp nhưng đã bị tiêu diệt trước khi truyền thụ.","detail":"Bí pháp được tàn hồn Huyền Cốt đề cập cùng với tầng cuối Huyền Âm đại pháp khi cầu xin tha mạng. Chi tiết tác dụng cụ thể chưa được tiết lộ, chỉ biết liên quan đến luyện yêu và thuộc hệ thống bí thuật quỷ tu của Huyền Cốt.","congNang":["Liên quan đến luyện yêu, chi tiết chưa rõ"],"nguoiTu":[{"ten":"Huyền Cốt","tuChuong":"@c0493","tangDatToi":"Không rõ","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0493","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến lần đầu","text":"Tàn hồn Huyền Cốt nhắc đến Huyền Hồn luyện yêu đại pháp khi cầu xin Hàn Lập tha mạng, nguyện giao nộp nhưng bị tiêu diệt trước khi truyền.","anchor":"Còn thêm Huyền Hồn luyện yêu đại pháp nữa"}]},"nguon":["@c0493"]},{"id":"truyen-tong-tran","name":"Truyền Tống trận","cn":"传送阵","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Diệu Âm Môn"],"blurb":"Trận pháp truyền tống cự ly ngắn trong mật thất nội điện Hư Thiên điện, bố trí thô sơ xiên xẹo nhưng vẫn hoạt động.","detail":"Tòa Truyền Tống trận nằm giữa mật thất nhỏ phủ đầy bụi trong nội điện Hư Thiên điện. Phù văn vẽ thô sơ như do người không rành trận pháp bắt chước, bố trí xiên xẹo. Hàn Lập kiểm tra bằng kiến thức trận pháp xác nhận vẫn dùng được, là loại truyền tống cự ly ngắn, kích hoạt bằng linh thạch đặt bốn phía. Trận đã truyền tống hắn đến thạch thất chứa hồ Linh nhãn chi tuyền.","congNang":["Truyền tống cự ly ngắn trong nội điện Hư Thiên điện, kích hoạt bằng linh thạch đặt bốn phía","Truyền tống tu sĩ từ Ngoại Tinh Hải về Nội Tinh Hải"],"tabs":{"tienTrinh":[{"chuong":"@c0494","loai":"dùng","importance":"normal","giaiDoan":"Hàn Lập kích hoạt","text":"Hàn Lập tìm thấy trong mật thất nội điện, kiểm tra xác nhận còn dùng được, đặt linh thạch kích hoạt truyền tống đến thạch thất chứa hồ Linh nhãn chi tuyền.","anchor":"Tuy nó cực kỳ thô sơ nhưng vẫn có thể dùng được"},{"chuong":"@c0537","loai":"xuất hiện","importance":"normal","giaiDoan":"Kế hoạch xây dựng được công bố","text":"Phạm phu nhân tiết lộ Diệu Âm Môn đang chuẩn bị Truyền Tống Trận để đưa tu sĩ về Nội Tinh Hải, đã có Truyền tống phù nhưng thiếu Huyễn Mộng Thạch, mời các tu sĩ hợp lực thanh trừ yêu thú.","anchor":"tài liệu trọng yếu nhất của pháp trận này là Huyễn Mộng Thạch, thật sự rất thưa thớt"}]},"nguon":["@c0494","@c0537"],"trangThai":"Đang chuẩn bị, thiếu Huyễn Mộng Thạch"},{"id":"tho-don-chi-thuat","name":"Thổ độn chi thuật","cn":"土遁之术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thổ thuộc tính","soHuu":["Hàn Lập"],"blurb":"Pháp thuật thổ thuộc tính cho phép độn thổ di chuyển qua đất, Hàn Lập trước đó muốn học nhưng không lĩnh ngộ được, nay có thể sử dụng thông qua triệu hoán tiểu lang vàng của Ngọc Như Ý.","detail":"Thuộc bẩm sinh của tiểu lang thổ thuộc tính — khí linh Ngọc Như Ý. Hàn Lập từ lâu muốn tu luyện nhưng không thành, nay có thể gián tiếp sử dụng qua triệu hoán tiểu lang vàng.","congNang":["Độn thổ, di chuyển xuyên qua đất đá"],"nguon":["@c0497"]},{"id":"an-nac-thuat","name":"Ẩn nặc thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật ẩn thân khiến thân hình biến mất vô ảnh vô tung, Hàn Lập sử dụng để tránh bị phát hiện giữa chiến trường.","detail":"Hàn Lập giậm chân, thân hình vặn vẹo biến mất vô ảnh vô tung, triệt để ẩn nặc. Tu sĩ Kết Đan trung kỳ cách bảy tám dặm cũng không phát giác được hắn.","congNang":["Ẩn thân triệt để, biến mất vô ảnh vô tung, tu sĩ Kết Đan trung kỳ không phát giác"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0499","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0499","loai":"thi triển","importance":"normal","giaiDoan":"Ẩn thân tại chiến trường Nam Minh đảo","text":"Hàn Lập giậm chân, thân hình vặn vẹo biến mất vô ảnh vô tung, triệt để ẩn nặc giữa trận chiến Nghịch Tinh minh tấn công Nam Minh đảo.","anchor":"thân hình hắn vặn vẹo, biến mất vô ảnh vô tung, triệt để ẩn nặc"}]},"capNhatToi":"@c0499","nguon":["@c0499"]},{"id":"dai-tran-phong-thu-tinh-cung","name":"Đại trận phòng thủ Tinh Cung (hồng quang)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Tinh Cung","soHuu":["Tinh Cung"],"blurb":"Đại trận phát hồng quang bảo vệ bến cảng Nam Minh đảo. Khi sắp tan có khả năng hồi quang phản chiếu lóe đầy trời gây hỗn loạn cho kẻ tấn công, tạo cơ hội cho tu sĩ Tinh Cung tẩu thoát.","detail":"Đại trận phòng thủ do Tinh Cung bố trí tại bến cảng Nam Minh đảo, phát ra hồng quang che chắn. Bị liên thủ chính ma lưỡng đạo (tu sĩ ngân sam kim đái và tu sĩ lục bào) của Nghịch Minh Tinh phá vỡ. Đặc điểm nổi bật: trước khi tan biến hoàn toàn, hồng quang hồi quang phản chiếu lóe ra đầy trời, gây đại loạn cho phe tấn công, tạo cơ hội cho tu sĩ Tinh Cung phi độn tẩu thoát.","congNang":["Phát hồng quang phòng thủ bến cảng","Hồi quang phản chiếu khi sắp tan — gây hỗn loạn cho địch, tạo cơ hội tẩu thoát"],"tabs":{"tienTrinh":[{"chuong":"@c0500","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị phá vỡ","text":"Đại trận hồng quang bảo vệ bến cảng Nam Minh đảo bị liên thủ chính ma lưỡng đạo phá vỡ. Trước khi tan, hồi quang phản chiếu lóe đầy trời gây hỗn loạn, tạo cơ hội cho tu sĩ Tinh Cung tẩu thoát.","anchor":"hồng quang tưởng chừng sắp tan biến kia, bỗng như hồi quang phản chiếu lóe ra đầy trời"}]},"nguon":["@c0500"]},{"id":"that-sat-quyet","name":"Thất Sát Quyết","cn":"七杀诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ (không phải đỉnh cấp)","hePhai":"","soHuu":["Thương Vân Long"],"blurb":"Công pháp cho phép cảm ứng sát khí trên người đối phương rất rõ ràng, đồng thời tu vi tinh tiến nhờ sát khí. Thuộc số ít công pháp nhờ sát khí tu luyện ở Loạn Tinh Hải.","detail":"Thương hộ pháp Nghịch Minh Tinh tu luyện công pháp này, nhờ đó cảm ứng được sát khí cực dày đặc trên người Hàn Lập mà người thường không nhận ra. Lão nhận xét nếu Hàn Lập tu luyện Thất Sát Quyết thì tu vi sẽ mỗi ngày đi ngàn dặm nhờ lượng sát khí khổng lồ.","nguoiTu":[{"ten":"Thương Vân Long","tuChuong":"@c0501","tangDatToi":"","trangThai":"dang-tu"}],"congNang":["Cảm ứng sát khí trên người đối phương rất rõ ràng","Tu vi tinh tiến nhờ sát khí tích lũy"],"tabs":{"tienTrinh":[{"chuong":"@c0501","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Thương hộ pháp tiết lộ tu luyện Thất Sát Quyết, dùng cảm ứng sát khí nhận ra Hàn Lập che giấu chín phần mười sát khí bằng Liễm khí thuật.","anchor":"công pháp mà ta tu luyện là “Thất sát quyết”, mặc dù không tính là công pháp đỉnh cấp gì, nhưng đối với sát khí của một người nào đó, nhiều ít bao nhiêu ta đều cảm ứng rất rõ ràng"}]},"nguon":["@c0501"]},{"id":"luu-thuy-tran","name":"Lưu thủy trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thấp (chỉ báo động, vô dụng trước tu sĩ Kết Đan)","hePhai":"","soHuu":[],"blurb":"Trận pháp nhỏ bố trí quanh trạch viện tầng 4 Thánh sơn, chỉ có tác dụng báo động khi có người xâm nhập, không có khả năng phòng ngự thực sự.","detail":"Vô dụng trước tu sĩ Kết Đan kỳ hoặc người giỏi trận pháp. Hàn Lập thu liễm pháp lực, dùng ẩn thân thuật vượt qua dễ dàng mà không kích hoạt.","congNang":["Báo động khi có người xâm nhập khu vực trận pháp bảo vệ"],"tabs":{"tienTrinh":[{"chuong":"@c0506","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập vượt qua","text":"Trận pháp nhỏ bố trí quanh trạch viện tầng 4 Thánh sơn. Hàn Lập dùng ẩn thân thuật vượt qua dễ dàng, không bị phát hiện.","anchor":"bố trí một cái pháp trận “Lưu thủy trận” nhỏ"}]},"nguon":["@c0506"]},{"id":"truyen-tong-tran-tinh-khong-dien","name":"Truyền tống trận (Tinh Không Điện)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Tinh Cung","soHuu":["Tinh Cung"],"blurb":"Trận pháp trong Tinh Không Điện, mỗi lần chỉ truyền tống tối đa bảy tu sĩ đi Ngoại Tinh Hải, mỗi người cần một tấm Truyền tống phù và linh thạch.","detail":"Trận pháp đặt trong Tinh Không Điện trên Thánh sơn. Mỗi lần kích hoạt chỉ có thể truyền tống tối đa bảy người. Hai tu sĩ Tinh Cung (Cố tiền bối, Kiền tiền bối) lén mở trận thu linh thạch riêng, chỉ dám mở một lần để tránh thượng cấp kiểm tra phát hiện. Mỗi người truyền tống cần được cấp một tấm Truyền tống phù.","congNang":["Truyền tống tối đa 7 tu sĩ đi Ngoại Tinh Hải mỗi lần kích hoạt"],"dacDiem":"Giới hạn 7 người/lần, cần Truyền tống phù, do hai tu sĩ Tinh Cung quản lý","tabs":{"tienTrinh":[{"chuong":"@c0507","loai":"xuất hiện","importance":"normal","giaiDoan":"Lén mở trận cho nhóm ngoài","text":"Hai tu sĩ Tinh Cung lén mở Truyền tống trận thu linh thạch từ nhóm đại hán cẩm y. Trận giới hạn tối đa bảy người/lần, Hàn Lập là người thứ tám gây ra mâu thuẫn.","anchor":"Truyền tống trận một lần chỉ có thể truyền tống tối đa bảy người"}]},"nguon":["@c0507"]},{"id":"me-hon-chi-thuat","name":"Mê hồn chi thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Bí thuật dùng kết hợp với thần thức cường đại để làm hôn mê đối phương và bắt thổ lộ bí mật trong khi ngủ, không phải pháp thuật khống chế thần thức chân chính.","detail":"Hàn Lập dùng bí thuật này kết hợp thần thức cường đại để lén vào phòng hán tử gầy gò, làm hôn mê rồi bắt đối phương thổ lộ bí mật cấu kết nâng giá truyền tống. Cần thần thức đủ mạnh mới phát huy hiệu quả.","congNang":["Làm hôn mê đối phương rồi bắt thổ lộ bí mật giấu trong lòng khi kết hợp thần thức cường đại"],"dacDiem":"Không phải khống chế thần thức chân chính, cần kết hợp thần thức mạnh mới đủ hiệu quả","nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0508","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0508","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập dùng thăm dò bí mật","text":"Hàn Lập dùng mê hồn chi thuật kết hợp thần thức cường đại lén vào phòng hán tử gầy gò, bắt đối phương thổ lộ bí mật cấu kết nâng giá truyền tống.","anchor":"cộng với mê hồn chi thuật và thần thức cường đại cũng đủ để đối tượng thổ lộ ra một số bí mật giấu trong lòng"}]},"nguon":["@c0508"]},{"id":"truyen-tong-tran-trong-dien","name":"Truyền tống trận (trong điện)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Tinh Cung"],"blurb":"Trận pháp truyền tống trong điện do hai tu sĩ Kết Đan Tinh Cung canh giữ, bị đặt cấm chế cần ngọc bài trắng và niệm chú để dỡ bỏ, đích đến ghi trên bia là Kỳ Uyên.","detail":"Truyền tống trận bị cấm chế, thường có ba người canh giữ. Hàn Lập nhận ra trận đã bị động tay động chân nên chọn cách hối lộ pháp bảo thay vì liều xông qua. Tấm bia phía trước trận ghi hai chữ Kỳ Uyên.","congNang":["Truyền tống tu sĩ tới Ngoại Tinh Hải (đích đến Kỳ Uyên)"],"dacDiem":"Bị đặt cấm chế, cần ngọc bài trắng kích hoạt + niệm chú, thường có ba người canh giữ","tabs":{"tienTrinh":[{"chuong":"@c0508","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập qua trận","text":"Hai tu sĩ Kết Đan dùng ngọc bài trắng niệm chú dỡ cấm chế. Hàn Lập dùng thần thức quét xác nhận an toàn rồi bước lên trận đầu tiên.","anchor":"Tòa truyền tống trận quả nhiên đã bị động tay động chân"}]},"nguon":["@c0508"]},{"id":"tang-nac-thuat","name":"Tàng Nặc thuật","cn":"藏匿术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Người áo trắng bí ẩn"],"blurb":"Thuật ẩn nấp cao cấp, giấu khí tức và hình thể khiến tu sĩ cao hơn một bậc cũng không thể phát hiện.","detail":"Kỹ thuật ẩn thân được người áo trắng bí ẩn sử dụng khi ẩn nấp sau bức tranh sơn thủy trong phòng Ly Tầm. Ly Tầm đánh giá tu sĩ cao hơn một bậc cũng không thể phát hiện người dùng thuật này. Tuy nhiên, người áo trắng nghi ngờ Hàn Lập (Kết Đan Kỳ) đã cảm nhận được sự hiện diện của mình.","nguon":["@c0514"],"congNang":["Ẩn giấu khí tức và hình thể, khiến tu sĩ cao hơn một bậc không phát hiện được"],"nguoiTu":[{"ten":"Người áo trắng bí ẩn","tuChuong":"@c0514","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0514","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu nhắc đến","text":"Người áo trắng bí ẩn dùng Tàng Nặc thuật ẩn nấp trong phòng Ly Tầm, Ly Tầm đánh giá tu sĩ cao hơn một bậc cũng không phát hiện. Tuy nhiên người áo trắng nghi Hàn Lập đã cảm nhận được mình.","anchor":"Tàng Nặc thuật của ngươi cho dù là tu sĩ cao hơn một bậc cũng không thể phát hiện"}]}},{"id":"ao-giac-cam-phap","name":"Ảo giác cấm pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Cấm pháp dùng khí cụ bày trận bao bọc khu vực, tạo ảo giác khiến nhìn từ xa địa hình bị biến dạng (núi thành rừng cây).","detail":"Hàn Lập dùng mấy bộ khí cụ bày trận bao bọc toàn bộ dãy núi trên hoang đảo, mở cấm pháp hình thành ảo giác khiến nhìn từ xa núi biến thành rừng cây xanh ngắt, che giấu động phủ bên trong.","congNang":["Tạo ảo giác che giấu địa hình thật, biến núi thành rừng cây khi nhìn từ xa"],"tabs":{"tienTrinh":[{"chuong":"@c0515","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập bố trận trên hoang đảo","text":"Hàn Lập dùng mấy bộ khí cụ bày trận bao bọc dãy núi chứa động phủ, mở cấm pháp tạo ảo giác che giấu toàn bộ dãy núi thành rừng cây.","anchor":"dùng mấy bộ khí cụ bày trận, mà bao bọc lấy toàn bộ dãy núi, rồi mở ra cấm pháp, hình thành ảo giác"}]},"nguon":["@c0515"]},{"id":"tran-phap-suong-mu-nhan-tao","name":"Trận pháp sương mù nhân tạo","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Trận pháp do Hàn Lập tự luyện chế khí cụ bố trí khắp hoang đảo, tạo sương mù nhân tạo hòa nhập sương tự nhiên che phủ toàn đảo.","detail":"Hàn Lập luyện chế mười mấy bộ khí cụ bố trận trong 6-7 ngày, bố trí khắp đảo. Khi mở ra, hàng loạt luồng sương mù thoát ra bao phủ hoàn toàn hòn đảo, hòa nhập với sương tự nhiên của Thôn Hải Ngư, khiến người bay cao không biết có đảo bên dưới.","congNang":["Tạo sương mù nhân tạo hòa nhập sương tự nhiên, che phủ toàn đảo phòng bị tu sĩ cấp cao phát hiện"],"tabs":{"tienTrinh":[{"chuong":"@c0515","loai":"thi triển","importance":"normal","giaiDoan":"Hàn Lập bố trận phòng thủ toàn đảo","text":"Hàn Lập bố trí mười mấy bộ khí cụ tự luyện chế khắp đảo, mở trận tạo sương mù nhân tạo bao phủ toàn đảo hòa nhập với sương Thôn Hải Ngư.","anchor":"hàng loạt luồng sương mù từ bên trong trận thoát ra, bao phủ hoàn toàn hòn đảo"}]},"nguon":["@c0515"]},{"id":"hoa-hinh-loi-kiep","name":"Hóa Hình Lôi Kiếp","cn":"化形雷劫","loai":"khac","loaiLabel":"Thiên kiếp","phamCap":"Không phân hạng (kiếp nạn tự nhiên)","hePhai":"","soHuu":[],"blurb":"Kiếp nạn thiên lôi xảy ra khi yêu thú cấp bảy tiến lên cấp tám, vượt qua mới có thể biến thành hình người. Tu vi càng thâm sâu thì hóa hình càng hoàn hảo.","detail":"Khi yêu thú có tu vi cấp bảy tiến vào cấp tám, phải trải qua một lần thiên lôi kiếp. Mây đen dày đặc trải ngàn dặm, lôi điện kinh hồn không ngừng đánh xuống. Vượt qua thì được hóa hình thành người; tu vi càng cao thì hóa hình càng hoàn hảo, yêu thú cấp mười hóa hình không phân biệt với nhân loại.","congNang":["Yêu thú cấp 7 lên cấp 8 phải chịu thiên lôi kiếp, qua được mới hóa hình thành người","Tu vi càng thâm sâu hóa hình càng hoàn hảo, cấp mười thì không phân biệt với nhân loại"],"tabs":{"tienTrinh":[{"chuong":"@c0518","loai":"xuat-hien","importance":"major","giaiDoan":"Lần đầu mô tả","text":"Cự Quy cấp bảy chịu Hóa Hình Lôi Kiếp trên biển gần đảo Hàn Lập, mây đen ngàn dặm, lôi điện kinh hồn liên tục đánh xuống.","anchor":"yêu thú có tu vi cấp bảy tiến vào cấp tám, phải trải qua một lần thiên lôi kiếp"}]},"nguon":["@c0518"]},{"id":"truu-hon-thuat","name":"Trừu Hồn thuật","cn":"抽魂术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Bí thuật rút hồn phách yêu thú ra khỏi thi thể, phối hợp với Tụ Hồn Bát để thu giữ.","detail":"Người dùng vận chú ngữ, từ đầu ngón tay phóng ra bạch tuyến mảnh như tơ cắm vào đầu yêu thú đã chết, rút hồn phách (lục quang) ra ngoài, kéo vào Tụ Hồn Bát. Hàn Lập lần đầu thi triển thực chiến tại mảng san hô đỏ, rút hồn phách cự hà cấp sáu.","thuocTinh":"Hồn phách","nguonGoc":"Không rõ","yeuCau":"Cần phối hợp Tụ Hồn Bát","uyLuc":"Rút thành công hồn phách yêu thú cấp sáu đã chết","dacDiem":"Phóng bạch tuyến mảnh như tơ từ ngón tay, cắm vào đầu mục tiêu","congNang":["Rút hồn phách yêu thú ra khỏi thi thể sau khi giết"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0521","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0521","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển thực chiến","text":"Hàn Lập vận chú ngữ phóng bạch tuyến từ ngón tay cắm vào đầu cự hà cấp sáu đã chết, rút hồn phách (lục quang) kéo vào Tụ Hồn Bát.","anchor":"đầu ngón tay bắn nhanh ra mấy đạo bạch tuyến mảnh như tơ, cắm vào đầu cự hà"}]},"nguon":["@c0521"]},{"id":"bon-phap-tran-vay-san-ho","name":"Bốn pháp trận vây san hô","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Bốn pháp trận Hàn Lập bày tại mảng san hô đỏ, vây kín khu vực mưa gió không lọt, bảo vệ Nghê Thường Thảo dụ yêu ở trung tâm.","detail":"Hàn Lập bày ra bốn pháp trận tại phụ cận khu san hô đỏ, vây kín mưa gió không lọt. Nghê Thường Thảo được trồng ở trung tâm để dụ yêu thú. Có tác dụng phòng thủ và vây bẫy yêu thú bị dẫn dụ đến.","congNang":["Phòng thủ vây kín khu vực","Vây bẫy yêu thú bị Nghê Thường Thảo dẫn dụ"],"tabs":{"tienTrinh":[{"chuong":"@c0521","loai":"thi triển","importance":"normal","giaiDoan":"Bày trận tại san hô đỏ","text":"Hàn Lập bày bốn pháp trận vây kín phụ cận mảng san hô đỏ, trồng Nghê Thường Thảo ở trung tâm dụ yêu.","anchor":"bày ra bốn pháp trận, đem phụ cận vây kín mưa gió không lọt"}]},"nguon":["@c0521"]},{"id":"tran-ban-xanh-biec","name":"Trận bàn xanh biếc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hàn Lập"],"blurb":"Trận pháp vây nhốt yêu thú, kích hoạt phun hơn mười cột sáng vàng tạo màn hào quang nhốt mục tiêu.","detail":"Hàn Lập kích hoạt trận bàn xanh biếc, hơn mười cột sáng màu vàng đồng thời từ biển phun lên tạo màn hào quang vàng vây nhốt yêu thú. Chịu được vài kích của gọng kềm cự hà cấp sáu nhưng có biểu hiện lung lay. Đủ dùng để nhốt tạm thời yêu thú cấp sáu trước khi dùng Ngũ Hành Hoàn trói chặt.","congNang":["Vây nhốt tạm thời yêu thú cấp sáu bằng màn hào quang vàng"],"uyLuc":"Lung lay sau vài đòn của yêu thú cấp sáu nhưng đủ nhốt tạm","tabs":{"tienTrinh":[{"chuong":"@c0521","loai":"thi triển","importance":"normal","giaiDoan":"Nhốt cự hà cấp sáu","text":"Hàn Lập kích hoạt trận bàn xanh biếc, hơn mười cột sáng vàng phun lên tạo màn hào quang nhốt cự hà cấp sáu.","anchor":"hơn mười đạo cột sáng màu vàng đồng thời trong biển phun ra"}]},"nguon":["@c0521"]},{"id":"kiem-thuat-bay-dao-thanh-quang","name":"Kiếm thuật bảy đạo thanh quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông kiếm","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thần thông kiếm do thanh niên áo lam (Hàn Lập) sử dụng — bảy đạo thanh quang hợp thành cự kiếm mười trượng, có chiêu ảo phân thân kiếm.","detail":"Bảy đạo thanh quang từ tay bắn ra hợp thành một thanh cự kiếm mười trượng. Khi đụng đối thủ, cự kiếm mờ ảo rồi từ trong thanh quang bay ra một thanh cự kiếm giống y hệt, xuất hiện trên đầu mục tiêu chém xuống. Uy lực cực lớn — giết Lưu Ly thú cấp sáu (nổi tiếng khó đối phó) chỉ trong nháy mắt.","thuocTinh":"Kim/Kiếm","uyLuc":"Giết Lưu Ly thú cấp sáu chỉ bằng một nhát","dacDiem":"Hợp kiếm + ảo ảnh phân thân kiếm","congNang":["Bảy thanh quang hợp thành cự kiếm mười trượng","Chiêu ảo phân thân — cự kiếm mờ ảo rồi phân thân ra cự kiếm thứ hai tấn công từ hướng khác"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0522","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0522","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Thanh niên áo lam (Hàn Lập) sử dụng bảy đạo thanh quang hợp cự kiếm mười trượng diệt Lưu Ly thú cấp sáu một nhát tại hải vực Ngoại Tinh Hải.","anchor":"từ trong thanh quang bay ra một thanh cự kiếm giống y như vậy, lóe lên biến mất"}]},"nguon":["@c0522"]},{"id":"khu-trung-thuat","name":"Khu Trùng Thuật","cn":"驱虫术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Thuật điều khiển trùng mà Hàn Lập sử dụng, khiến hắn nổi tiếng khắp Ngoại Tinh Hải với biệt danh Trùng Ma. Bích Vân Môn lợi dụng đặc điểm này để phái người giả mạo.","detail":"Hàn Lập nổi tiếng ngoài Ngoại Tinh Hải vì sử dụng Khu Trùng Thuật cùng Thanh Trúc Phong Vân Kiếm, bị mang ác danh Trùng Ma. Bích Vân Môn biết hắn dùng thuật này nên phái đệ tử giả mạo giết người đoạt bảo khắp nơi.","congNang":["Điều khiển linh trùng chiến đấu, Hàn Lập dùng kết hợp với Phệ Kim Trùng"],"tabs":{"tienTrinh":[{"chuong":"@c0525","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị kẻ thù lợi dụng tạo ác danh","text":"Bích Vân Môn biết Hàn Lập sử dụng Khu Trùng Thuật nên phái người giả mạo Trùng Ma dùng kim ngân phi trùng giết người đoạt bảo khắp Ngoại Tinh Hải.","anchor":"Hiển nhiên nghi ngờ lớn nhất, chính là do Bích Vân Môn tìm không ra hắn, mà vừa lại biết hắn sử dụng Khu Trùng Thuật cùng Thanh Trúc Phong Vân Kiếm"}]},"nguon":["@c0525"]},{"id":"ao-tran-tren-dao","name":"Ảo trận trên đảo","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Hàn Lập"],"blurb":"Ảo trận bao phủ khu rừng cây trên đảo nhỏ giữa biển, khi tiếp cận gần ba trượng thì kích hoạt, biến cảnh vật thành núi non xa lạ với linh khí nồng đậm. Có bạch sắc quang mang phân tầng bảo hộ bên trong.","detail":"Khi nhóm tu sĩ Thanh Linh Môn bay tới gần rừng cây ba trượng, ảo trận kích hoạt — cảnh vật đại biến thành núi non xa lạ, linh khí nồng đậm. Bên trong có tầng bạch sắc quang mang với khí tức cấm chế. Ưng Diên Thú cấp hai không bị ảo giác ảnh hưởng nhưng tạm mất phương hướng mục tiêu. Chủ nhân có thể điều khiển màn sáng tự hé ra lối đi rộng một trượng.","congNang":["Ảo giác che giấu nơi bế quan","Cấm chế bảo hộ bằng bạch sắc quang mang phân tầng","Chủ nhân điều khiển mở/đóng lối vào"],"tabs":{"tienTrinh":[{"chuong":"@c0528","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhóm Thanh Linh Môn vô tình lạc vào","text":"Nhóm tu sĩ Thanh Linh Môn bị Ưng Diên Thú đuổi, chạy về phía rừng cây, vô tình kích hoạt ảo trận — cảnh vật đại biến thành núi non xa lạ. Nữ tu sĩ nhận ra là ảo trận. Chủ nhân bên trong điều khiển Khôi Lỗi diệt yêu thú rồi hé lối đi cho nhóm người.","anchor":"bỗng quay cuồng... đột nhiên phát hiện cảnh vật trước mắt đã đại biến"}]},"nguon":["@c0528"]},{"id":"kim-chan-cong","name":"Kim Chân Công","cn":"金真功","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Đỉnh cấp","hePhai":"","soHuu":[],"blurb":"Đỉnh cấp công pháp của cả môn phái, ngọc giản chứa khẩu quyết đặt trên thạch bàn không có cấm chế bảo hộ.","detail":"Công pháp đỉnh cấp mà Công Tôn Hạnh phát hiện trong kho ngọc giản tại động phủ trên hoang đảo sương mù. Ngọc giản chứa khẩu quyết được đặt tùy tiện không có bất kỳ cấm chế bảo hộ nào. Công Tôn Hạnh xem nửa canh giờ, bị nội dung hấp dẫn rồi kinh ngạc đặt lại chỗ cũ.","nguon":["@c0531"],"tabs":{"tienTrinh":[{"chuong":"@c0531","loai":"xuất hiện","importance":"normal","giaiDoan":"Công Tôn Hạnh phát hiện trong kho ngọc giản","text":"Công Tôn Hạnh dùng thần thức xem ngọc giản, phát hiện Kim Chân Công là đỉnh cấp công pháp toàn phái, đặt tùy tiện không cấm chế.","anchor":"đúng là một đỉnh cấp công pháp của cả môn phái"}]}},{"id":"trien-ngoc-quyet","name":"Triền Ngọc Quyết","cn":"缠玉诀","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Đỉnh cấp","hePhai":"","soHuu":["Công Tôn Hạnh"],"blurb":"Đỉnh cấp công pháp đặc biệt thích hợp cho nữ tử tu luyện, uy lực vượt xa Thanh Linh Công trung cấp.","detail":"Công pháp đỉnh cấp mà Hàn Lập đoạt được từ một nam tử trước đây. Đặc biệt thích hợp cho nữ tử tu luyện, uy lực vượt xa Thanh Linh Công (công pháp chính của Thanh Linh Môn, chỉ ở mức trung cấp). Hàn Lập tặng lại cho Công Tôn Hạnh khi rời đảo — đây là bước ngoặt tu hành cho thiếu nữ.","nguon":["@c0531"],"thuocTinh":"Thích hợp nữ tử","nguonGoc":"Hàn Lập đoạt từ một nam tử","uyLuc":"Đỉnh cấp, vượt xa Thanh Linh Công trung cấp","congNang":["Thích hợp cho nữ tử tu luyện, uy lực vượt xa công pháp trung cấp"],"nguoiTu":[{"ten":"Công Tôn Hạnh","tuChuong":"@c0531","tangDatToi":"","trangThai":"dang-tu"}],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"","denChuong":"@c0531","cachCoDuoc":"Đoạt từ một nam tử","trangThai":"da-tang"},{"ten":"Công Tôn Hạnh","tuChuong":"@c0531","denChuong":"","cachCoDuoc":"Được Hàn Lập tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0531","loai":"đổi chủ","importance":"major","giaiDoan":"Hàn Lập tặng cho Công Tôn Hạnh","text":"Hàn Lập lưu lại Triền Ngọc Quyết cho Công Tôn Hạnh khi lặng lẽ rời đảo. Đây là đỉnh cấp công pháp thích hợp nữ tử, vượt xa Thanh Linh Công trung cấp của môn phái nàng.","anchor":"Triền Ngọc Quyết này đích xác thích hợp cho nữ tử tu luyện, mặc dù ta lấy được từ một trên người gã nam tử"}]}},{"id":"hoan-hinh-quyet","name":"Hoán Hình Quyết","cn":"幻形诀","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Huyền Âm Kinh","soHuu":["Hàn Lập"],"blurb":"Bí thuật thuộc Huyền Âm Kinh cho phép co giãn thân thể, thay đổi da thịt nhan sắc tức thì, khó bị thần thức tu sĩ nhìn thấu.","detail":"Có thể tùy ý kéo dài, rút ngắn các bộ phận của thân thể, đồng thời khống chế nới lỏng cơ thể, trong nháy mắt thay đổi da thịt nhan sắc. Hiệu quả biến hình khó bị thần thức tu sĩ nhìn thấu. Khuyết điểm: khi thi triển, pháp lực tối đa chỉ dùng được bảy thành; vượt quá thì hiệu quả biến mất, khôi phục hình dáng gốc.","thuocTinh":"","nguonGoc":"Bí thuật trong Huyền Âm Kinh","yeuCau":"","uyLuc":"Biến đổi dung mạo, thân hình tức thì, khó bị phát hiện bởi thần thức","dacDiem":"Giới hạn bảy thành pháp lực khi duy trì biến hình; vượt quá sẽ lộ nguyên hình","congNang":["Co giãn thân thể, thay đổi chiều cao","Thay đổi da thịt nhan sắc tức thì","Khó bị thần thức tu sĩ nhìn thấu"],"nguoiTu":[{"ten":"Hàn Lập","tuChuong":"@c0532","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0532","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Hàn Lập lần đầu thi triển Hoán Hình Quyết, rút ngắn thân hình một thốn, biến khuôn mặt thành mặt vàng lạ lẫm để giấu thân phận trước khi tiếp xúc Hoàng Minh Lễ.","anchor":"có thể tùy ý kéo dài, rút ngắn các bộ phận của thân thể, hơn nữa còn có thể khống chế nới lỏng cơ thể, trong nháy mắt thay đổi da thịt nhan sắc"}]},"capNhatToi":"@c0532","nguon":["@c0532"]},{"id":"bach-cot-am-hoa","name":"Bạch Cốt Âm Hỏa","cn":"白骨阴火","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Hỏa hệ / Âm hệ","soHuu":["Vân Thiên Khiếu"],"blurb":"Công pháp hộ thể của Vân Thiên Khiếu, bùng cháy ngọn lửa màu xám quỷ dị trên toàn thân, dùng để uy hiếp và phòng ngự.","detail":"Khi vận chuyển, trên người hiện lên vô số ngọn lửa màu xám quỷ dị. Có tác dụng hộ thể tự động khi bị tấn công. Tuy nhiên hoàn toàn không cản nổi mười hai thanh phi kiếm của Hàn Lập, bị xuyên phá dễ dàng.","congNang":["Hộ thể tự động, bùng lửa xám quỷ dị bao phủ toàn thân khi bị tấn công"],"nguoiTu":[{"ten":"Vân Thiên Khiếu","tuChuong":"@c0536","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c0536","loai":"thi triển","importance":"normal","giaiDoan":"Bị phá vỡ","text":"Vân Thiên Khiếu vận Bạch Cốt Âm Hỏa hộ thể khi bị Hàn Lập tấn công, lửa xám bao phủ toàn thân nhưng hoàn toàn không cản nổi mười hai thanh phi kiếm, bị xuyên phá dễ dàng.","anchor":"Trên hai tay của Vân Thiên Khiếu đột nhiên bùng cháy lên một ngọn hỏa diễm màu xám quỷ dị"}]},"nguon":["@c0536"]},{"id":"cong-phap-yeu-tu-tren-tam-dong","name":"Công pháp yêu tu trên tấm đồng","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Yêu tu","soHuu":[],"blurb":"Công pháp tu luyện của yêu thú ghi trên tấm đồng, gồm 36 tư thế kết hợp pháp quyết và vặn vẹo thân thể, có thể giúp biến hóa nhân hình.","detail":"Khi rót linh lực vào tấm đồng, nó phóng cột sáng hiện bức họa cổ xưa: một yêu thú toàn thân vảy bạc, trên đầu mọc sừng, biểu diễn 36 tư thế tu luyện. Văn tự trên tấm đồng cùng nguồn gốc với quyển sách da thú. Hàn Lập nhận định đây hoàn toàn là vật của yêu tu, không phải nhân loại, nên từ bỏ.","congNang":["Tu luyện yêu thú, giúp biến hóa nhân hình"],"dacDiem":"Ghi trên tấm đồng, 36 tư thế, cùng nguồn gốc văn tự với quyển sách da thú","tabs":{"tienTrinh":[{"chuong":"@c0539","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập phát hiện nội dung","text":"Hàn Lập rót linh lực vào tấm đồng, bức họa yêu thú vảy bạc hiện ra biểu diễn 36 tư thế tu luyện. Hắn nhận định là công pháp yêu tu, không phải vật nhân loại, từ bỏ nghiên cứu.","anchor":"từ công pháp tu luyện có thể biến hóa thành nhân hình thì có thể thấy công pháp này tuyệt đối không phải là loại thường"}]},"nguon":["@c0539"]},{"id":"phong-hoa-si","name":"Phong Hỏa Sí","cn":"风火翅","loai":"than-thong","loaiLabel":"Thần thông bản thể","phamCap":"Cấp cao","hePhai":"Liệt Phong tộc","soHuu":["Phong Hi"],"blurb":"Đôi cánh bản mệnh của Liệt Phong Thú, luyện đến cảnh giới cao nhất có thể dịch chuyển tức thời ngàn dặm.","detail":"Thần thông bản thể riêng của bộ tộc Liệt Phong Thú, thể hiện ở đôi cánh lửa. Luyện đến cảnh giới cao nhất có khả năng dịch chuyển tức thời ngàn dặm, thuộc phong thuộc tính. Phương pháp tu luyện Phong Hỏa Sí của Liệt Phong tộc là nền tảng để Phong Hi phát triển kế hoạch luyện chế Phong Lôi Sí.","thuocTinh":"Phong","nguonGoc":"Bản thể Liệt Phong Thú","dacDiem":"Dịch chuyển tức thời ngàn dặm khi đạt cảnh giới cao nhất","congNang":["Dịch chuyển tức thời ngàn dặm"],"tabs":{"tienTrinh":[{"chuong":"@c0543","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc đến như nền tảng luyện Phong Lôi Sí","text":"Phong Hi nhắc đến Phong Hỏa Sí là đôi cánh bản mệnh của Liệt Phong Thú, luyện đến cảnh giới cao nhất dịch chuyển tức thời ngàn dặm. Phương pháp tu luyện Phong Hỏa Sí của bộ tộc là nền tảng cho kế hoạch luyện chế Phong Lôi Sí.","anchor":"một đôi Phong Hỏa Sí luyện đến cảnh giới cao nhất, có thể dịch chuyển tức thời ngàn dặm"}]},"nguon":["@c0543"]},{"id":"cong-phap-thuy-thuoc-tinh-giao-long","name":"Công pháp thủy thuộc tính Giao Long","cn":"","loai":"cong-phap","loaiLabel":"Công pháp bản thể","phamCap":"","hePhai":"Giao Long Nhất tộc","soHuu":["Độc Giao"],"blurb":"Bản năng thiên phú của thân Giao Long, trời sinh thông hiểu mọi công pháp thủy thuộc tính, chỉ tu luyện sơ qua đã mạnh hơn các chủng tộc khác gấp trăm lần.","detail":"Thân thể Giao Long trời sinh thông hiểu hết các công pháp thủy thuộc tính. Chỉ cần tu luyện sơ qua đã mạnh mẽ hơn các chủng tộc khác gấp trăm lần. Đây là ưu thế bản thể của Giao Long Nhất tộc.","thuocTinh":"Thủy","nguonGoc":"Bản thể Giao Long","congNang":["Thông hiểu mọi công pháp thủy thuộc tính"],"tabs":{"tienTrinh":[{"chuong":"@c0543","loai":"nhắc tới","importance":"normal","giaiDoan":"Độc Giao tự hào năng lực bản thể","text":"Độc Giao tự hào thân Giao Long trời sinh thông hiểu mọi công pháp thủy thuộc tính, tu luyện sơ qua đã mạnh hơn các chủng tộc khác gấp trăm lần.","anchor":"thân thể Giao Long trời sinh thông hiểu hết các công pháp thủy thuộc tính, chỉ cần tu luyện sơ qua thì cũng đã mạnh mẽ hơn các chủng tộc khác gấp trăm lần"}]},"nguon":["@c0543"]}]};
